          # skip the strlen+sep scan and emit a direct allocator call.
          recv = @nd_receiver[nid]
          if recv >= 0 && @nd_type[recv] == "StringNode" && @nd_content[recv] == "" && @nd_type[a[0]] == "StringNode"
            return "sp_StrArray_new()"
          end
        end
      end
      return "sp_str_split(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "lines"
      @needs_str_array = 1
      return "sp_str_lines(" + rc + ")"
    end
    if mname == "scan"
      if @nd_block[nid] < 0
        args_id = @nd_arguments[nid]
        if args_id >= 0
          argl = get_args(args_id)
          if argl.length > 0
            rpat = regex_pat_c_expr(argl[0])
            if rpat != ""
              @needs_str_array = 1
              return "sp_re_scan(" + rpat + ", " + rc + ")"
            end
          end
        end
      end
    end
    if mname == "match?"
      re_args_id = @nd_arguments[nid]
      if re_args_id >= 0
        argl = get_args(re_args_id)
        if argl.length > 0
          rpat = regex_pat_c_expr(argl[0])
          if rpat != ""
            return "sp_re_match_p(" + rpat + ", " + rc + ")"
          end
        end
      end
      return "sp_str_include(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "gsub"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          rpat = regex_pat_c_expr(a[0])
          if rpat != ""
            return "sp_re_gsub(" + rpat + ", " + rc + ", " + compile_expr(a[1]) + ")"
          end
          return "sp_str_gsub(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return rc
    end
    if mname == "sub"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          rpat = regex_pat_c_expr(a[0])
          if rpat != ""
            return "sp_re_sub(" + rpat + ", " + rc + ", " + compile_expr(a[1]) + ")"
          end
          return "sp_str_sub(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return rc
    end
    if mname == "index"
      return "sp_str_index(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "rindex"
      return "sp_str_rindex(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "tr"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_tr(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return rc
    end
    if mname == "ljust"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_ljust2(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return "sp_str_ljust(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "rjust"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_rjust2(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return "sp_str_rjust(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "[]"
      args_id = @nd_arguments[nid]
      # Use length-aware variant if strlen of this receiver is hoisted
      use_len = (@hoisted_strlen_var != "" && @hoisted_strlen_recv == rc)
      fn = use_len ? "sp_str_sub_range_len" : "sp_str_sub_range"
      lprefix = use_len ? (rc + ", " + @hoisted_strlen_var) : rc
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 1
          if @nd_type[a[0]] == "RangeNode"
            # s[1..3] inclusive, s[1...3] exclusive
            left = compile_expr(@nd_left[a[0]])
            right = compile_expr(@nd_right[a[0]])
            adj = range_excl_end(a[0]) == 1 ? "" : " + 1"
            return fn + "(" + lprefix + ", " + left + ", " + right + " - " + left + adj + ")"
          end
          if a.length >= 2
            # s[0, 2]
            return fn + "(" + lprefix + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
          end
        end
      end
      return fn + "(" + lprefix + ", " + compile_arg0(nid) + ", 1)"
    end
    if mname == "reverse"
      return "sp_str_reverse(" + rc + ")"
    end
    if mname == "freeze"
      return rc
    end
    if mname == "frozen?"
      return "TRUE"
    end
    if mname == "to_sym" || mname == "intern"
      return "sp_sym_intern(" + rc + ")"
    end
    if mname == "ord"
      return "sp_str_ord(" + rc + ")"
    end
    if mname == "sub"
      args_id = @nd_arguments[nid]
      arg1 = "\"\""
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          arg1 = compile_expr(a[1])
        end
      end
      return "sp_str_sub(" + rc + ", " + compile_arg0(nid) + ", " + arg1 + ")"
    end
    if mname == "capitalize"
      return "sp_str_capitalize(" + rc + ")"
    end
    if mname == "count"
      return "sp_str_count(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "*"
      return "sp_str_repeat(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "empty?"
      return "(strlen(" + rc + ") == 0)"
    end
    if mname == "chars"
      @needs_str_array = 1
      @needs_gc = 1
      return "sp_str_split(" + rc + ", \"\")"
    end
    if mname == "bytes"
      @needs_int_array = 1
      @needs_gc = 1
      # `File.binread(path).bytes` — sp_str_bytes uses null-termination
      # so it stops at the first 0x00 byte, which is wrong for binary
      # data (e.g. .nes ROM files). Pattern-match the chained call
      # and emit a single binread-to-IntArray helper that reads with
      # the file's actual byte count.
      r = @nd_receiver[nid]
      if r >= 0 && @nd_type[r] == "CallNode"
        rmname = @nd_name[r]
        if rmname == "binread"
          rr = @nd_receiver[r]
          if rr >= 0 && @nd_type[rr] == "ConstantReadNode" && @nd_name[rr] == "File"
            rargs = @nd_arguments[r]
            if rargs >= 0
              ras = get_args(rargs)
              if ras.length >= 1
                @needs_file_io = 1
                return "sp_file_binread_bytes(" + compile_expr(ras[0]) + ")"
              end
            end
          end
        end
      end
      return "sp_str_bytes(" + rc + ")"
    end
    if mname == "hex"
      return "((mrb_int)strtoll(" + rc + ", NULL, 16))"
    end
    if mname == "oct"
      return "((mrb_int)strtoll(" + rc + ", NULL, 8))"
    end
    if mname == "tr"
      args_id = @nd_arguments[nid]
      arg1 = "\"\""
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          arg1 = compile_expr(a[1])
        end
      end
      return "sp_str_tr(" + rc + ", " + compile_arg0(nid) + ", " + arg1 + ")"
    end
    if mname == "delete"
      return "sp_str_delete(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "squeeze"
      return "sp_str_squeeze(" + rc + ")"
    end
    if mname == "size"
      if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
        return @hoisted_strlen_var
      end
      return "sp_str_length(" + rc + ")"
    end
    if mname == "slice"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_sub_range(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return "sp_str_sub_range(" + rc + ", " + compile_arg0(nid) + ", 1)"
    end
    if mname == "center"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_str_center2(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
      return "sp_str_center(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "lstrip"
      return "sp_str_lstrip(" + rc + ")"
    end
    if mname == "rstrip"
      return "sp_str_rstrip(" + rc + ")"
    end
    if mname == "dup"
      return "sp_str_dup(" + rc + ")"
    end
    if mname == "getbyte"
      return "((mrb_int)(unsigned char)(" + rc + ")[" + compile_arg0(nid) + "])"
    end
    if mname == "setbyte"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "(((char*)" + rc + ")[" + compile_expr(a[0]) + "] = (char)" + compile_expr(a[1]) + ", 0)"
        end
      end
      return "0"
    end
    if mname == "bytesize"
      return "(mrb_int)strlen(" + rc + ")"
    end
    if mname == "to_s"
      return rc
    end
