  end

  # Resolve the literal RangeNode behind a method receiver, peeking
  # through a single ParenthesesNode wrap. Returns -1 when the receiver
  # isn't a literal range — in which case the runtime sp_Range struct is
  # used and exclude_end isn't tracked.
  def resolve_literal_range_recv(nid)
    recv = @nd_receiver[nid]
    if recv < 0
      return -1
    end
    if @nd_type[recv] == "RangeNode"
      return recv
    end
    if @nd_type[recv] == "ParenthesesNode"
      pb = @nd_body[recv]
      if pb >= 0
        ps = get_stmts(pb)
        if ps.length > 0 && @nd_type[ps.first] == "RangeNode"
          return ps.first
        end
      end
    end
    -1
  end

  def compile_range_method_expr(nid, mname, rc)
    if mname == "first"
      return rc + ".first"
    end
    if mname == "last"
      return rc + ".last"
    end
    # include? / cover? on a numeric range reduce to first <= x <= last
    # (inclusive form). The two methods are identical for numeric ranges
    # so they share the same emission. Exclude_end isn't tracked in the
    # runtime sp_Range struct; non-literal receivers fall back to the
    # inclusive form (matches length/size).
    if mname == "include?" || mname == "cover?" || mname == "==="
      # Range#=== is the case-when membership operator and behaves like
      # cover? for numeric ranges (Ruby docs: "tests for membership").
      tmp = new_temp
      emit("  sp_Range " + tmp + " = " + rc + ";")
      arg = compile_arg0(nid)
      return "(" + arg + " >= " + tmp + ".first && " + arg + " <= " + tmp + ".last)"
    end
    if mname == "to_a"
      @needs_int_array = 1
      @needs_gc = 1
      # Honour `...` exclusive Range when the receiver is a literal
      # RangeNode (or wrapped in parens). For non-literal Range values
      # held in sp_Range structs, exclude_end is not tracked at runtime
      # and the inclusive form is used.
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0
        rright = compile_expr(@nd_right[range_nid])
        if range_excl_end(range_nid) == 1
          rright = "(" + rright + ") - 1"
        end
        return "sp_IntArray_from_range(" + compile_expr(@nd_left[range_nid]) + ", " + rright + ")"
      end
      return "sp_IntArray_from_range(" + rc + ".first, " + rc + ".last)"
    end
    if mname == "length"
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
    if mname == "size"
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
    if mname == "min"
      return rc + ".first"
    end
    if mname == "max"
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0 && range_excl_end(range_nid) == 1
        return "(" + rc + ".last - 1)"
      end
      return rc + ".last"
    end
    if mname == "count"
      # Inclusive: last - first + 1. Exclusive (literal): last - first.
      range_nid = resolve_literal_range_recv(nid)
      if range_nid >= 0 && range_excl_end(range_nid) == 1
        return "(" + rc + ".last - " + rc + ".first)"
      end
      return "(" + rc + ".last - " + rc + ".first + 1)"
    end
    # `(a..b).any?/all?/none?/one? { |i| ... }` — the array-shape
    # predicate emitter already iterates ranges via emit_iter_open;
    # just route to it. Without this, the call falls through to the
    # unresolved-call warning and emits literal 0.
    if (mname == "any?" || mname == "all?" || mname == "none?" || mname == "one?") && @nd_block[nid] >= 0
      return compile_array_predicate_block(nid, rc, "range", mname)
    end
    ""
  end

  # Symbol methods. rc is a sp_sym expression.
  def compile_symbol_method_expr(nid, mname, rc)
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Symbol" || arg_name == "Comparable" ||
             arg_name == "Object" || arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Symbol"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "to_s" || mname == "id2name" || mname == "name"
      return "sp_sym_to_s(" + rc + ")"
    end
    if mname == "to_sym" || mname == "intern"
      return rc
    end
    # Symbol#upcase / Symbol#downcase: lower-case via the str case helper
    # then re-intern. Naming convention `sp_str_<mname>` lets one branch
    # handle both — and slots in cleanly for capitalize/swapcase later.
    if mname == "upcase" || mname == "downcase"
      return "sp_sym_intern(sp_str_" + mname + "(sp_sym_to_s(" + rc + ")))"
    end
    if mname == "inspect"
      return "sp_str_concat(\":\", sp_sym_to_s(" + rc + "))"
    end
    if mname == "length" || mname == "size"
      return "((mrb_int)strlen(sp_sym_to_s(" + rc + ")))"
    end
    if mname == "empty?"
      return "(sp_sym_to_s(" + rc + ")[0] == 0)"
    end
    if mname == "hash"
      return "((mrb_int)" + rc + ")"
    end
    if mname == "<=>"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            other = compile_expr(aargs[0])
            # Lexical compare on symbol names (Ruby semantics)
            cmp = "strcmp(sp_sym_to_s(" + rc + "), sp_sym_to_s(" + other + "))"
            return "((" + cmp + ") < 0 ? (mrb_int)-1 : ((" + cmp + ") > 0 ? (mrb_int)1 : (mrb_int)0))"
          end
        end
      end
      return "0"
    end
    if mname == "==" || mname == "eql?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            return "(" + rc + " == " + compile_expr(aargs[0]) + ")"
          end
          # Symbol != anything-non-symbol in Ruby
          return "FALSE"
        end
      end
    end
    if mname == "!="
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 1
          at = infer_type(aargs[0])
          if at == "symbol"
            return "(" + rc + " != " + compile_expr(aargs[0]) + ")"
          end
          return "TRUE"
        end
      end
    end
    ""
  end

  def compile_int_method_expr(nid, mname, rc)
    # is_a? / kind_of? on a primitive int: resolve at compile time.  The
    # arg is a class constant (Integer / Numeric / Comparable / etc.);
    # answer based on Ruby's class hierarchy.  Anything not in the int
    # ancestor chain is FALSE.
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Integer" || arg_name == "Numeric" ||
             arg_name == "Comparable" || arg_name == "Object" ||
             arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    # instance_of? is is_a? without superclass / mixin matching.
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Integer"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "to_s"
      if @nd_arguments[nid] >= 0
        aargs = get_args(@nd_arguments[nid])
        if aargs.length > 0
          return "sp_int_to_s_base(" + rc + ", " + compile_expr(aargs[0]) + ")"
        end
      end
      return "sp_int_to_s(" + rc + ")"
    end
    if mname == "inspect"
      return "sp_int_to_s(" + rc + ")"
    end
    # `int <=> other` -- standard 3-way compare. Without this arm
    # the int-recv fallback at compile_call_expr's tail picks a
    # user-defined `<=>` (issue #399) and recurses. Comparable's
    # `<` / `>` / `<=` / `>=` already route to a numeric compare
    # in compile_call_expr; `<=>` itself was missing.
    if mname == "<=>"
      args_id_cmp = @nd_arguments[nid]
      if args_id_cmp >= 0
        a_cmp = get_args(args_id_cmp)
        if a_cmp.length >= 1
          rt_cmp = infer_type(a_cmp[0])
          if rt_cmp == "int" || rt_cmp == "float"
            arg_e = compile_expr(a_cmp[0])
            return "((" + rc + ") < (" + arg_e + ") ? (mrb_int)-1 : ((" + rc + ") > (" + arg_e + ") ? (mrb_int)1 : (mrb_int)0))"
          end
        end
      end
    end
    if mname == "digits"
      @needs_int_array = 1
      @needs_gc = 1
      base = "10"
      if @nd_arguments[nid] >= 0
        aargs = get_args(@nd_arguments[nid])
        if aargs.length > 0
          base = compile_expr(aargs[0])
        end
      end
      return "sp_int_digits(" + rc + ", " + base + ")"
    end
    if mname == "bit_length"
      # Number of bits needed to represent the integer (excluding sign)
      return "((" + rc + ") < 0 ? (64 - __builtin_clzll((uint64_t)~(" + rc + "))) : ((" + rc + ") == 0 ? 0 : (64 - __builtin_clzll((uint64_t)(" + rc + ")))))"
    end
    if mname == "fdiv"
      return "((mrb_float)(" + rc + ") / (mrb_float)" + compile_arg0(nid) + ")"
    end
    if mname == "divmod"
      tt = "tuple:int,int"
      register_tuple_type(tt)
      @needs_gc = 1
      name = tuple_c_name(tt)
      arg = compile_arg0(nid)
      tmp = new_temp
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp + "->_0 = sp_idiv(" + rc + ", " + arg + ");")
      emit("  " + tmp + "->_1 = sp_imod(" + rc + ", " + arg + ");")
      return tmp
    end
    if mname == "to_i"
      return rc
    end
    if mname == "to_f"
      return "(mrb_float)(" + rc + ")"
    end
    if mname == "abs"
      return "((" + rc + ") < 0 ? -(" + rc + ") : (" + rc + "))"
    end
    if mname == "even?"
      return "((" + rc + ") % 2 == 0)"
    end
    if mname == "odd?"
      return "((" + rc + ") % 2 != 0)"
    end
    if mname == "allbits?"
      mask = compile_arg0(nid)
      return "(((" + rc + ") & (" + mask + ")) == (" + mask + "))"
    end
    if mname == "anybits?"
      return "(((" + rc + ") & (" + compile_arg0(nid) + ")) != 0)"
    end
    if mname == "nobits?"
      return "(((" + rc + ") & (" + compile_arg0(nid) + ")) == 0)"
    end
    if mname == "zero?"
      return "((" + rc + ") == 0)"
    end
    if mname == "gcd"
      return "sp_gcd(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "lcm"
      return "sp_lcm(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "ceildiv"
      return "sp_ceildiv(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "div"
      return "sp_idiv(" + rc + ", " + compile_arg0(nid) + ")"
    end
    if mname == "clamp"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length >= 2
          return "sp_int_clamp(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
        end
      end
    end
    if mname == "frozen?"
      return "TRUE"
    end
    if mname == "chr"
      return "sp_int_chr(" + rc + ")"
    end
    if mname == "succ" || mname == "next"
      return "((" + rc + ") + 1)"
    end
    if mname == "pred"
      return "((" + rc + ") - 1)"
    end
    if mname == "itself"
      return rc
    end
    # Integer#[idx] — bit indexing. `n[k]` returns bit k of n.
    # Skip when the receiver is a constant reference (ENV, STDIN,
    # ::ARGV, ...) — those resolve their type to the int fallback at
    # infer_type's tail and would otherwise eat the constant's own
    # `[]` dispatch (e.g. ENV["HOME"] → getenv, ::ARGV[i] → argv).
    if mname == "[]"
      recv_id = @nd_receiver[nid]
      if recv_id >= 0 && (@nd_type[recv_id] == "ConstantReadNode" || @nd_type[recv_id] == "ConstantPathNode")
        return ""
      end
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length > 0
          # Skip bit-extract when the index is a non-int — `row[:id]`
          # / `row["id"]` is hash subscript, not bit indexing on an
          # integer. Without this gate, a poly/hash-receiver param
          # that defaulted to "int" (no upstream pinning) routed
          # `row[:id]` to `(row >> SPS_id) & 1`, shifting an int by
          # the symbol's interned id (>= 64) which is undefined
          # behavior under -Wshift-count-overflow. Surfaces in
          # Roundhouse's `def self.from_raw(row); row[:id] || 0;
          # end` where `row` is unpinned. Issue #314 (Roundhouse
          # warnings family).
          idx_t = infer_type(aargs[0])
          if idx_t != "int" && idx_t != "poly"
            return ""
          end
          idx = compile_expr(aargs[0])
          return "(((" + rc + ") >> (" + idx + ")) & 1)"
        end
      end
    end
    ""
  end

  def compile_float_method_expr(nid, mname, rc)
    if mname == "is_a?" || mname == "kind_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Float" || arg_name == "Numeric" ||
             arg_name == "Comparable" || arg_name == "Object" ||
             arg_name == "Kernel" || arg_name == "BasicObject"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          if arg_name == "Float"
            return "TRUE"
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end
    if mname == "itself"
      return rc
    end
    if mname == "to_s"
      return "sp_float_to_s(" + rc + ")"
    end
    if mname == "inspect"
      return "sp_float_inspect(" + rc + ")"
    end
    if mname == "to_i"
      return "(mrb_int)(" + rc + ")"
    end
    if mname == "to_f"
      return "(" + rc + ")"
    end
    # ceil/floor/round/truncate with precision arg use a GCC stmt-expr so
    # the argument expression is compiled-and-emitted once on the Ruby
    # side and pow(10, n) is evaluated once at runtime — the original
    # form double-evaluated both, which broke any side-effecting arg.
    if mname == "ceil"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); ceil((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)ceil(" + rc + ")"
    end
    if mname == "floor"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); floor((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)floor(" + rc + ")"
    end
    if mname == "round"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); round((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)round(" + rc + ")"
    end
    if mname == "abs"
      return "fabs(" + rc + ")"
    end
    if mname == "nan?"
      return "(isnan(" + rc + ") ? TRUE : FALSE)"
    end
    if mname == "finite?"
      return "(isfinite(" + rc + ") ? TRUE : FALSE)"
    end
    if mname == "infinite?"
      return "(isinf(" + rc + ") ? (" + rc + " < 0 ? -1 : 1) : 0)"
    end
    if mname == "truncate"
      if @nd_arguments[nid] >= 0
        arg = compile_arg0(nid)
        return "({ double _f = pow(10, " + arg + "); trunc((" + rc + ") * _f) / _f; })"
      end
      return "(mrb_int)trunc(" + rc + ")"
    end
    if mname == "fdiv"
      return "((" + rc + ") / (mrb_float)" + compile_arg0(nid) + ")"
    end
    if mname == "divmod"
      tt = "tuple:int,float"
      register_tuple_type(tt)
      @needs_gc = 1
      tname = tuple_c_name(tt)
      arg = compile_arg0(nid)
      tmp = new_temp
      emit("  " + tname + " *" + tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp + "->_0 = (mrb_int)floor(" + rc + " / " + arg + ");")
      emit("  " + tmp + "->_1 = " + rc + " - " + tmp + "->_0 * " + arg + ";")
      return tmp
    end
    ""
  end

  def compile_array_method_expr(nid, mname, rc, recv_type)
    # Skip non-array types. Without this guard a user class with a
    # method whose name happens to overlap an Array method (e.g.
    # `def sample`, `def first`) would be dispatched as that Array
    # method, with `array_c_prefix` falling back to `IntArray` and
    # the receiver pointer used as if it were an `sp_IntArray *`.
    if is_array_type(recv_type) == 0
      return ""
    end
    # Array#dig with a single index reduces to []. Multi-arg dig that
    # walks into nested arrays/hashes isn't supported here yet — fall
    # through to the unsupported-call warning.
    if mname == "dig"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length == 1
          return compile_array_method_expr(nid, "[]", rc, recv_type)
        end
      end
    end
    # arr.slice!(from, n) — returns a fresh array of `n` elements
    # starting at `from` and removes them from the receiver. Each
    # array type lowers to its own runtime helper that mutates the
    # backing buffer in place. sym_array shares the IntArray helper
    # since symbols are stored as interned int IDs.
    if mname == "slice!"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        aargs = get_args(args_id)
        if aargs.length >= 2
          from_e = compile_expr(aargs[0])
          n_e = compile_expr(aargs[1])
          if recv_type == "int_array" || recv_type == "sym_array"
            @needs_int_array = 1
            return "sp_IntArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "float_array"
            @needs_float_array = 1
            return "sp_FloatArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "str_array"
            @needs_str_array = 1
            return "sp_StrArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if is_ptr_array_type(recv_type) == 1
            @needs_ptr_array = 1
            return "sp_PtrArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
          if recv_type == "poly_array"
            @needs_poly_array = 1
            return "sp_PolyArray_slice_bang(" + rc + ", " + from_e + ", " + n_e + ")"
          end
        end
      end
    end
    # Array#inspect and Array#to_s (CRuby aliases them for arrays, so
    # the two share one definition via compile_inspect_for). Guard on
    # recv_type being an actual array type so scalar receivers with
    # the same method name (e.g. (poly).to_s, (int).to_s) fall through
    # to their own scalar dispatchers.
    if mname == "inspect" || mname == "to_s"
      if is_array_type(recv_type) == 1
        r = compile_inspect_for(recv_type, rc)
        if r != ""
          return r
        end
      end
    end
    # zip without block: return array of pairs/tuples
    if mname == "zip" && @nd_block[nid] < 0
      @needs_gc = 1
      pfx_recv = array_c_prefix(recv_type)
      args_id = @nd_arguments[nid]
      aargs = get_args(args_id)
      # Check if heterogeneous or multi-arg
      heterogeneous = 0
      k = 0
      while k < aargs.length
        at = infer_type(aargs[k])
        if at != recv_type
          heterogeneous = 1
        end
        k = k + 1
      end
      if aargs.length > 1
        heterogeneous = 1
      end
      # Compile all zip arguments
      arg_rcs = "".split(",")
      arg_types = "".split(",")
      k = 0
      while k < aargs.length
        arg_rcs.push(compile_expr(aargs[k]))
        arg_types.push(infer_type(aargs[k]))
        k = k + 1
      end
      tmp = new_temp
      itmp = new_temp
      pair_tmp = new_temp
      emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_" + pfx_recv + "_length(" + rc + "); " + itmp + "++) {")
      if heterogeneous == 1
        # Build tuple type
        parts = "".split(",")
        parts.push(elem_type_of_array(recv_type))
        k = 0
        while k < arg_types.length
          parts.push(elem_type_of_array(arg_types[k]))
          k = k + 1
        end
        tt = "tuple:" + parts.join(",")
        register_tuple_type(tt)
        tname = tuple_c_name(tt)
        emit("    " + tname + " *" + pair_tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    " + pair_tmp + "->_0 = sp_" + pfx_recv + "_get(" + rc + ", " + itmp + ");")
        k = 0
        while k < arg_rcs.length
          apfx = array_c_prefix(arg_types[k])
          emit("    " + pair_tmp + "->_" + (k + 1).to_s + " = sp_" + apfx + "_get(" + arg_rcs[k] + ", " + itmp + ");")
          k = k + 1
        end
      else
        emit("    " + c_type(recv_type) + " " + pair_tmp + " = sp_" + pfx_recv + "_new();")
        emit("    sp_" + pfx_recv + "_push(" + pair_tmp + ", sp_" + pfx_recv + "_get(" + rc + ", " + itmp + "));")
        k = 0
        while k < arg_rcs.length
          emit("    sp_" + pfx_recv + "_push(" + pair_tmp + ", sp_" + pfx_recv + "_get(" + arg_rcs[k] + ", " + itmp + "));")
          k = k + 1
        end
      end
      emit("    sp_PtrArray_push(" + tmp + ", " + pair_tmp + ");")
      emit("  }")
      return tmp
    end
    # first(n) / last(n) with argument: return new array
    if mname == "first" && @nd_arguments[nid] >= 0
      aargs = get_args(@nd_arguments[nid])
      if aargs.length > 0
        pfx = array_c_prefix(recv_type)
        n = compile_expr(aargs[0])
        tmp = new_temp
        itmp = new_temp
        emit("  " + c_type(recv_type) + " " + tmp + " = sp_" + pfx + "_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + n + " && " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
        emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
        return tmp
      end
    end
    if mname == "last" && @nd_arguments[nid] >= 0
      aargs = get_args(@nd_arguments[nid])
      if aargs.length > 0
        pfx = array_c_prefix(recv_type)
        n = compile_expr(aargs[0])
        tmp = new_temp
        itmp = new_temp
        len_tmp = new_temp
        emit("  mrb_int " + len_tmp + " = sp_" + pfx + "_length(" + rc + ");")
        emit("  " + c_type(recv_type) + " " + tmp + " = sp_" + pfx + "_new();")
        emit("  for (mrb_int " + itmp + " = (" + len_tmp + " - " + n + " < 0 ? 0 : " + len_tmp + " - " + n + "); " + itmp + " < " + len_tmp + "; " + itmp + "++)")
        emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
        return tmp
      end
    end
    # Common array methods (all array types)
    if mname == "take"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0(nid)
      tmp = new_temp
      itmp = new_temp
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + n + " && " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
      return tmp
    end
    if mname == "drop"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0(nid)
      tmp = new_temp
      itmp = new_temp
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = " + n + "; " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", " + itmp + "));")
      return tmp
    end
    if mname == "fill"
      pfx = array_c_prefix(recv_type)
      args_id_fill = @nd_arguments[nid]
      val = compile_arg0(nid)
      start_expr = "0"
      # Default end: current array length (matches CRuby's no-args
      # form which fills the entire existing array).
      end_expr = "sp_" + pfx + "_length(" + rc + ")"
      if args_id_fill >= 0
        aargs_fill = get_args(args_id_fill)
        if aargs_fill.length >= 3
          # arr.fill(value, start, length): negative start counts from
          # the end; if still negative after that, clamp to 0
          # (matches CRuby: `[1,2,3].fill(9, -5, 2) #=> [9, 9, 3]`).
          # end_expr = start + length lets the array grow past its
          # current length when start+length > length; sp_*_set
          # auto-grows and zero-fills gaps (matches CRuby:
          # `[1,2,3].fill(9, 5, 2) #=> [1, 2, 3, 0, 0, 9, 9]`).
          start_tmp = new_temp
          len_tmp = new_temp
          emit("  mrb_int " + start_tmp + " = " + compile_expr(aargs_fill[1]) + ";")
          emit("  mrb_int " + len_tmp + " = " + compile_expr(aargs_fill[2]) + ";")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " += sp_" + pfx + "_length(" + rc + ");")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " = 0;")
          start_expr = start_tmp
          end_expr = "(" + start_tmp + " + " + len_tmp + ")"
        elsif aargs_fill.length == 2
          # arr.fill(value, start): fills from start to end of EXISTING
          # array. If start >= length, fills nothing (does NOT grow,
          # matching CRuby: `[1,2,3].fill(9, 5) #=> [1, 2, 3]`).
          start_tmp = new_temp
          emit("  mrb_int " + start_tmp + " = " + compile_expr(aargs_fill[1]) + ";")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " += sp_" + pfx + "_length(" + rc + ");")
          emit("  if (" + start_tmp + " < 0) " + start_tmp + " = 0;")
          start_expr = start_tmp
        end
      end
      itmp = new_temp
      emit("  for (mrb_int " + itmp + " = " + start_expr + "; " + itmp + " < " + end_expr + "; " + itmp + "++)")
      if recv_type == "poly_array"
        v_id = -1
        if args_id_fill >= 0
          v_id = get_args(args_id_fill)[0]
        end
        vt = v_id >= 0 ? infer_type(v_id) : "int"
        vbox = vt == "poly" ? val : box_value_to_poly(vt, val)
        emit("    sp_PolyArray_set(" + rc + ", " + itmp + ", " + vbox + ");")
      else
        emit("    sp_" + pfx + "_set(" + rc + ", " + itmp + ", " + val + ");")
      end
      return rc
    end
    if mname == "rotate"
      pfx = array_c_prefix(recv_type)
      n = compile_arg0(nid)
      if n == "0"
        n = "1"
      end
      tmp = new_temp
      itmp = new_temp
      len_tmp = new_temp
      emit("  mrb_int " + len_tmp + " = sp_" + pfx + "_length(" + rc + ");")
      emit("  " + c_type(recv_type) + tmp + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + len_tmp + "; " + itmp + "++)")
      emit("    sp_" + pfx + "_push(" + tmp + ", sp_" + pfx + "_get(" + rc + ", ((" + itmp + " + " + n + ") % " + len_tmp + " + " + len_tmp + ") % " + len_tmp + "));")
      return tmp
    end
    if mname == "sample"
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
      return "sp_" + pfx + "_get(" + rc + ", rand() % sp_" + pfx + "_length(" + rc + "))"
    end
    if mname == "shuffle" && is_array_type(recv_type) == 1
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
      return "sp_" + pfx + "_shuffle(" + rc + ")"
    end
    if mname == "shuffle!" && is_array_type(recv_type) == 1
      @needs_rand = 1
      pfx = array_c_prefix(recv_type)
      emit("  sp_" + pfx + "_shuffle_bang(" + rc + ");")
      return rc
    end
    if mname == "any?" && @nd_block[nid] < 0
      pfx = array_c_prefix(recv_type)
      return "(sp_" + pfx + "_length(" + rc + ") > 0)"
    end
    if mname == "none?" && @nd_block[nid] < 0
      pfx = array_c_prefix(recv_type)
      return "(sp_" + pfx + "_length(" + rc + ") == 0)"
    end
    if mname == "count" && @nd_arguments[nid] >= 0 && @nd_block[nid] < 0
      # count(val) — count occurrences of a specific value
      pfx = array_c_prefix(recv_type)
      val = compile_arg0(nid)
      tmp_c = new_temp
      tmp_i = new_temp
      if recv_type == "str_array"
        emit("  mrb_int " + tmp_c + " = 0;")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++)")
        emit("    if (strcmp(sp_" + pfx + "_get(" + rc + ", " + tmp_i + "), " + val + ") == 0) " + tmp_c + "++;")
      else
        emit("  mrb_int " + tmp_c + " = 0;")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++)")
        emit("    if (sp_" + pfx + "_get(" + rc + ", " + tmp_i + ") == " + val + ") " + tmp_c + "++;")
      end
      return tmp_c
    end
    if (mname == "any?" || mname == "all?" || mname == "none?" || mname == "one?") && @nd_block[nid] >= 0
      return compile_array_predicate_block(nid, rc, recv_type, mname)
    end
    if (mname == "find" || mname == "detect") && @nd_block[nid] >= 0
      return compile_array_find_block(nid, rc, recv_type)
    end
    if mname == "filter_map" && @nd_block[nid] >= 0
      return compile_array_filter_map(nid, rc, recv_type)
    end
    if (mname == "sum") && @nd_block[nid] >= 0
      return compile_array_sum_block(nid, rc, recv_type)
    end
    if (mname == "count") && @nd_block[nid] >= 0
      return compile_array_count_block(nid, rc, recv_type)
    end
    if mname == "partition" && @nd_block[nid] >= 0
      pfx = array_c_prefix(recv_type)
      tt = "tuple:" + recv_type + "," + recv_type
      register_tuple_type(tt)
      @needs_gc = 1
      name = tuple_c_name(tt)
      bp1 = get_block_param(nid, 0)
      if bp1 == ""
        bp1 = "_x"
      end
      et = elem_type_of_array(recv_type)
      tmp_t = new_temp
      tmp_f = new_temp
      tmp_res = new_temp
      itmp = new_temp
      emit("  " + c_type(recv_type) + " " + tmp_t + " = sp_" + pfx + "_new();")
      emit("  " + c_type(recv_type) + " " + tmp_f + " = sp_" + pfx + "_new();")
      emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++) {")
      emit("    " + c_type(et) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + itmp + ");")
      push_scope
      declare_var(bp1, et)
      blk = @nd_block[nid]
      bexpr = "0"
      if @nd_body[blk] >= 0
        bs = get_stmts(@nd_body[blk])
        if bs.length > 0
          k = 0
          while k < bs.length - 1
            compile_stmt(bs[k])
            k = k + 1
          end
          bexpr = compile_expr(bs.last)
        end
      end
      emit("    if (" + bexpr + ") sp_" + pfx + "_push(" + tmp_t + ", lv_" + bp1 + "); else sp_" + pfx + "_push(" + tmp_f + ", lv_" + bp1 + ");")
      pop_scope
      emit("  }")
      emit("  " + name + " *" + tmp_res + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp_res + "->_0 = " + tmp_t + ";")
      emit("  " + tmp_res + "->_1 = " + tmp_f + ";")
      return tmp_res
    end
    if mname == "minmax"
      pfx = array_c_prefix(recv_type)
      et = elem_type_of_array(recv_type)
      tt = "tuple:" + et + "," + et
      register_tuple_type(tt)
      @needs_gc = 1
      name = tuple_c_name(tt)
      tmp = new_temp
      tmp_min = new_temp
      tmp_max = new_temp
      itmp = new_temp
      emit("  " + c_type(et) + " " + tmp_min + " = sp_" + pfx + "_get(" + rc + ", 0);")
      emit("  " + c_type(et) + " " + tmp_max + " = " + tmp_min + ";")
      emit("  for (mrb_int " + itmp + " = 1; " + itmp + " < sp_" + pfx + "_length(" + rc + "); " + itmp + "++) {")
      emit("    " + c_type(et) + " _v = sp_" + pfx + "_get(" + rc + ", " + itmp + ");")
      if et == "string"
        emit("    if (strcmp(_v, " + tmp_min + ") < 0) " + tmp_min + " = _v;")
        emit("    if (strcmp(_v, " + tmp_max + ") > 0) " + tmp_max + " = _v;")
      else
        emit("    if (_v < " + tmp_min + ") " + tmp_min + " = _v;")
        emit("    if (_v > " + tmp_max + ") " + tmp_max + " = _v;")
      end
      emit("  }")
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(tt) + ");")
      emit("  " + tmp + "->_0 = " + tmp_min + ";")
      emit("  " + tmp + "->_1 = " + tmp_max + ";")
      return tmp
    end
    if (mname == "min" || mname == "max") && @nd_block[nid] >= 0
      return compile_array_min_max_block(nid, rc, recv_type, mname)
    end
    # Array methods
    if recv_type == "int_array" || recv_type == "sym_array"
      if mname == "length" || mname == "size"
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_IntArray_length(" + rc + ")"
      end
      if mname == "[]"
        # a[range] and a[start, len] return slices; bare a[i] stays a get.
        # Mirrors compile_string_method_expr's slicing dispatch.
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length >= 1 && @nd_type[a[0]] == "RangeNode"
            left = compile_expr(@nd_left[a[0]])
            right = compile_expr(@nd_right[a[0]])
            adj = range_excl_end(a[0]) == 1 ? "" : " + 1"
            return "sp_IntArray_slice(" + rc + ", " + left + ", " + right + " - " + left + adj + ")"
          end
          if a.length >= 2
            return "sp_IntArray_slice(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
          end
        end
        return "sp_IntArray_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "push"
        return "(sp_IntArray_push(" + rc + ", " + compile_arg0_as_int(nid) + "), 0)"
      end
      if mname == "pop"
        return "sp_IntArray_pop(" + rc + ")"
      end
      if mname == "shift"
        return "sp_IntArray_shift(" + rc + ")"
      end
      if mname == "empty?"
        return "sp_IntArray_empty(" + rc + ")"
      end
      if mname == "include?"
        return "sp_IntArray_include(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "index" || mname == "find_index"
        if @nd_arguments[nid] >= 0
          return "sp_IntArray_index(" + rc + ", " + compile_arg0(nid) + ")"
        end
      end
      if mname == "rindex"
        if @nd_arguments[nid] >= 0
          return "sp_IntArray_rindex(" + rc + ", " + compile_arg0(nid) + ")"
        end
      end
      if mname == "delete_at"
        return "sp_IntArray_delete_at(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "insert"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 2
            return "(sp_IntArray_insert(" + rc + ", " + compile_expr(aargs[0]) + ", " + compile_expr(aargs[1]) + "), " + rc + ")"
          end
        end
      end
      if mname == "sort"
        if recv_type == "sym_array"
          tmp = new_temp
          emit("  sp_IntArray *" + tmp + " = sp_IntArray_dup(" + rc + "); sp_sym_array_sort(" + tmp + ");")
          return tmp
        end
        return "sp_IntArray_sort(" + rc + ")"
      end
      # `pack("C*")` — the only format Spinel implements: each
      # int element is written as a byte into a freshly allocated
      # NUL-terminated string. Sufficient for the optcarrot save-
      # RAM `@wrk.pack("C*")` shape and the symmetric inverse of
      # `String#bytes` we already support. Other format strings
      # fall through to the unresolved-call warning.
      if mname == "pack" && recv_type == "int_array"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a_pk = get_args(args_id)
          if a_pk.length == 1 && @nd_type[a_pk[0]] == "StringNode" && @nd_content[a_pk[0]] == "C*"
            tmp = new_temp
            ntmp = new_temp
            itmp = new_temp
            emit("  mrb_int " + ntmp + " = sp_IntArray_length(" + rc + ");")
            emit("  char *" + tmp + " = sp_str_alloc(" + ntmp + ");")
            emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + ntmp + "; " + itmp + "++) " + tmp + "[" + itmp + "] = (char)sp_IntArray_get(" + rc + ", " + itmp + ");")
            emit("  " + tmp + "[" + ntmp + "] = 0;")
            return tmp
          end
        end
      end
      # `replace(other)` in expression position: the stmt-form
      # arm in compile_*_stmt only fires when the call's value is
      # discarded; in expression position (e.g. last stmt of a
      # method body, or rvalue of an assignment) we still need to
      # emit the side effect *and* yield the receiver as the
      # value. Use the comma operator so the result is `rc`.
      if mname == "replace" && recv_type == "int_array"
        return "(sp_IntArray_replace(" + rc + ", " + compile_arg0(nid) + "), " + rc + ")"
      end
      # `a[i] = v` in expression position. The stmt-form is
      # handled by `compile_bracket_assign`; in rvalue chains like
      # `@io_latch = @sp_ram[i] = mask(data)` (optcarrot PPU), the
      # call lands here. Lift idx/val into temps so each side is
      # evaluated exactly once, then return the rhs (Ruby `[]=`
      # semantics).
      if mname == "[]=" && recv_type == "int_array"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a_set = get_args(args_id)
          if a_set.length >= 2
            idx_tmp = new_temp
            val_tmp = new_temp
            emit("  mrb_int " + idx_tmp + " = " + compile_expr(a_set[0]) + ";")
            emit("  mrb_int " + val_tmp + " = " + compile_expr(a_set[1]) + ";")
            emit("  sp_IntArray_set(" + rc + ", " + idx_tmp + ", " + val_tmp + ");")
            return val_tmp
          end
        end
      end
      # take_while / drop_while: block-driven prefix scan. take_while
      # collects elements from the front while the block stays truthy;
      # drop_while skips them and returns the rest. Mirrors the
      # existing take/drop arms but with per-element block evaluation.
      # `bp`'s C type and the metadata `declare_var` records both come
      # from `elem_type_of_array(recv_type)` so sym_array gets `sp_sym`
      # rather than a hardcoded `mrb_int`. Multi-stmt blocks compile
      # preceding statements before extracting the predicate expr from
      # the last — same shape as the partition arm.
      if (mname == "take_while" || mname == "drop_while") && @nd_block[nid] >= 0
        blk = @nd_block[nid]
        bp = get_block_param(nid, 0)
        if bp == ""
          bp = "_x"
        end
        elem_t = elem_type_of_array(recv_type)
        tmp = new_temp
        itmp = new_temp
        ktmp = new_temp
        emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
        emit("  { mrb_int " + ktmp + " = sp_IntArray_length(" + rc + ");")
        emit("    mrb_int " + itmp + " = 0;")
        emit("    while (" + itmp + " < " + ktmp + ") {")
        emit("      " + c_type(elem_t) + " lv_" + bp + " = sp_IntArray_get(" + rc + ", " + itmp + ");")
        push_scope
        declare_var(bp, elem_t)
        bbody = @nd_body[blk]
        bexpr = "0"
        if bbody >= 0
          bs = get_stmts(bbody)
          if bs.length > 0
            k = 0
            while k < bs.length - 1
              compile_stmt(bs[k])
              k = k + 1
            end
            bexpr = compile_expr(bs.last)
          end
        end
        emit("      if (!(" + bexpr + ")) break;")
        if mname == "take_while"
          emit("      sp_IntArray_push(" + tmp + ", lv_" + bp + ");")
        end
        emit("      " + itmp + "++;")
        emit("    }")
        if mname == "drop_while"
          emit("    while (" + itmp + " < " + ktmp + ") { sp_IntArray_push(" + tmp + ", sp_IntArray_get(" + rc + ", " + itmp + ")); " + itmp + "++; }")
        end
        emit("  }")
        pop_scope
        return tmp
      end
      # tally: sym_array only — int_array would need an int_int_hash
      # variant which doesn't exist yet. Result is sym_int_hash.
      if mname == "tally" && recv_type == "sym_array"
        @needs_sym_int_hash = 1
        return "sp_SymArray_tally(" + rc + ")"
      end
      if mname == "first"
        return "sp_IntArray_get(" + rc + ", 0)"
      end
      if mname == "last"
        return "sp_IntArray_get(" + rc + ", sp_IntArray_length(" + rc + ") - 1)"
      end
      if mname == "min"
        return "sp_IntArray_min(" + rc + ")"
      end
      if mname == "max"
        return "sp_IntArray_max(" + rc + ")"
      end
      if mname == "sum"
        return "sp_IntArray_sum(" + rc + ")"
      end
      if mname == "to_a"
        return "sp_IntArray_dup(" + rc + ")"
      end
      if mname == "uniq"
        return "sp_IntArray_uniq(" + rc + ")"
      end
      if mname == "join"
        jarg = compile_arg0(nid)
        if jarg == "0"
          jarg = "\"\""
        end
        return "sp_IntArray_join(" + rc + ", " + jarg + ")"
      end
      if mname == "reverse"
        return "({ sp_IntArray *_r = sp_IntArray_dup(" + rc + "); sp_IntArray_reverse_bang(_r); _r; })"
      end
      if mname == "compact"
        return "sp_IntArray_dup(" + rc + ")"
      end
      if mname == "flatten"
        return "sp_IntArray_dup(" + rc + ")"
      end
      if mname == "unshift"
        return "(sp_IntArray_unshift(" + rc + ", " + compile_arg0(nid) + "), 0)"
      end
      if mname == "dup"
        return "sp_IntArray_dup(" + rc + ")"
      end
      if mname == "count"
        return "sp_IntArray_length(" + rc + ")"
      end
      if mname == "intersection"
        return "sp_IntArray_intersect(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "union"
        return "sp_IntArray_union(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "difference"
        return "sp_IntArray_difference(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "min_by"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          itmp = new_temp
          emit("  mrb_int " + tmp + " = sp_IntArray_get(" + rc + ", 0);")
          emit("  { mrb_int _best = INT64_MAX;")
          emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_IntArray_length(" + rc + "); " + itmp + "++) {")
          emit("    mrb_int lv_" + bp + " = sp_IntArray_get(" + rc + ", " + itmp + ");")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    mrb_int _v = " + bexpr + ";")
          emit("    if (_v < _best) { _best = _v; " + tmp + " = lv_" + bp + "; }")
          emit("  } }")
          return tmp
        end
      end
      if mname == "max_by"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          itmp = new_temp
          emit("  mrb_int " + tmp + " = sp_IntArray_get(" + rc + ", 0);")
          emit("  { mrb_int _best = INT64_MIN;")
          emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < sp_IntArray_length(" + rc + "); " + itmp + "++) {")
          emit("    mrb_int lv_" + bp + " = sp_IntArray_get(" + rc + ", " + itmp + ");")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    mrb_int _v = " + bexpr + ";")
          emit("    if (_v > _best) { _best = _v; " + tmp + " = lv_" + bp + "; }")
          emit("  } }")
          return tmp
        end
      end
      if mname == "sort_by"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_IntArray *" + tmp + " = sp_IntArray_dup(" + rc + ");")
          # Use bubble sort with block as key function
          emit("  { mrb_int _n = " + tmp + "->len;")
          emit("  for (mrb_int _i = 0; _i < _n - 1; _i++)")
          emit("    for (mrb_int _j = 0; _j < _n - 1 - _i; _j++) {")
          emit("      mrb_int lv_" + bp + " = " + tmp + "->data[" + tmp + "->start + _j];")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("      mrb_int _ka = " + bexpr + ";")
          emit("      lv_" + bp + " = " + tmp + "->data[" + tmp + "->start + _j + 1];")
          emit("      mrb_int _kb = " + bexpr + ";")
          emit("      if (_ka > _kb) { mrb_int _t = " + tmp + "->data[" + tmp + "->start + _j]; " + tmp + "->data[" + tmp + "->start + _j] = " + tmp + "->data[" + tmp + "->start + _j + 1]; " + tmp + "->data[" + tmp + "->start + _j + 1] = _t; }")
          emit("    }")
          emit("  }")
          return tmp
        end
      end
    end
    # Float array methods
    if recv_type == "float_array"
      if mname == "length"
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_FloatArray_length(" + rc + ")"
      end
      if mname == "[]"
        # a[range] / a[start, len] return slices; bare a[i] stays a get.
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length >= 1 && @nd_type[a[0]] == "RangeNode"
            left = compile_expr(@nd_left[a[0]])
            right = compile_expr(@nd_right[a[0]])
            adj = range_excl_end(a[0]) == 1 ? "" : " + 1"
            return "sp_FloatArray_slice(" + rc + ", " + left + ", " + right + " - " + left + adj + ")"
          end
          if a.length >= 2
            return "sp_FloatArray_slice(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
          end
        end
        return "sp_FloatArray_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "push"
        return "(sp_FloatArray_push(" + rc + ", " + compile_arg0(nid) + "), 0)"
      end
      if mname == "pop"
        return "sp_FloatArray_pop(" + rc + ")"
      end
      if mname == "shift"
        return "sp_FloatArray_shift(" + rc + ")"
      end
      if mname == "empty?"
        return "sp_FloatArray_empty(" + rc + ")"
      end
      if mname == "size"
        return "sp_FloatArray_length(" + rc + ")"
      end
      if mname == "min"
        return "sp_FloatArray_min(" + rc + ")"
      end
      if mname == "max"
        return "sp_FloatArray_max(" + rc + ")"
      end
      if mname == "sum"
        return "sp_FloatArray_sum(" + rc + ")"
      end
      if mname == "first"
        return "sp_FloatArray_get(" + rc + ", 0)"
      end
      if mname == "last"
        return "sp_FloatArray_get(" + rc + ", -1)"
      end
      if mname == "intersection"
        return "sp_FloatArray_intersect(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "union"
        return "sp_FloatArray_union(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "difference"
        return "sp_FloatArray_difference(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "sort"
        # Non-bang: yield a fresh sorted copy. Mirror the
        # `sp_FloatArray_shuffle` pattern (new + replace) so the
        # source array is left untouched.
        tmp = new_temp
        emit("  sp_FloatArray *" + tmp + " = sp_FloatArray_new(); sp_FloatArray_replace(" + tmp + ", " + rc + "); sp_FloatArray_sort_bang(" + tmp + ");")
        return tmp
      end
    end
    if is_ptr_array_type(recv_type) == 1
      elem_type = ptr_array_elem_type(recv_type)
      ct = c_type(elem_type)
      if mname == "length" || mname == "size"
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_PtrArray_length(" + rc + ")"
      end
      if mname == "[]"
        return "((" + ct + ")sp_PtrArray_get(" + rc + ", " + compile_arg0_as_int(nid) + "))"
      end
      if mname == "first"
        return "((" + ct + ")sp_PtrArray_get(" + rc + ", 0))"
      end
      if mname == "last"
        return "((" + ct + ")sp_PtrArray_get(" + rc + ", sp_PtrArray_length(" + rc + ") - 1))"
      end
      if mname == "push"
        return "(sp_PtrArray_push(" + rc + ", " + compile_arg0(nid) + "), 0)"
      end
      if mname == "empty?"
        return "sp_PtrArray_empty(" + rc + ")"
      end
      # transpose for [[Int]] (int_array_ptr_array). Other
      # nested-array element shapes are not yet supported and fall
      # through to the unresolved-call warning.
      if mname == "transpose" && elem_type == "int_array"
        @needs_int_array = 1
        tmp = new_temp
        col = new_temp
        itmp = new_temp
        jtmp = new_temp
        cols = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        # GC-root the result PtrArray and the per-column IntArray. Both
        # outlive the inner allocation calls (`sp_IntArray_new`,
        # `sp_PtrArray_push`'s realloc) that may trigger collection. Without
        # the root, an inner sp_IntArray_new could free `tmp` mid-loop and
        # the next push dereferences a freed pointer.
        emit("  SP_GC_ROOT(" + tmp + ");")
        emit("  if (sp_PtrArray_length(" + rc + ") > 0) {")
        emit("    mrb_int " + cols + " = sp_IntArray_length((sp_IntArray *)sp_PtrArray_get(" + rc + ", 0));")
        emit("    for (mrb_int " + jtmp + " = 0; " + jtmp + " < " + cols + "; " + jtmp + "++) {")
        emit("      sp_IntArray *" + col + " = sp_IntArray_new();")
        emit("      SP_GC_ROOT(" + col + ");")
        emit("      for (mrb_int " + itmp + " = 0; " + itmp + " < sp_PtrArray_length(" + rc + "); " + itmp + "++) {")
        emit("        sp_IntArray_push(" + col + ", sp_IntArray_get((sp_IntArray *)sp_PtrArray_get(" + rc + ", " + itmp + "), " + jtmp + "));")
        emit("      }")
        emit("      sp_PtrArray_push(" + tmp + ", " + col + ");")
        emit("    }")
        emit("  }")
        return tmp
      end
    end
    if recv_type == "str_array"
      if mname == "length"
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_StrArray_length(" + rc + ")"
      end
      if mname == "size"
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_StrArray_length(" + rc + ")"
      end
      if mname == "[]"
        # a[range] / a[start, len] return slices; bare a[i] stays a get.
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length >= 1 && @nd_type[a[0]] == "RangeNode"
            left = compile_expr(@nd_left[a[0]])
            right = compile_expr(@nd_right[a[0]])
            adj = range_excl_end(a[0]) == 1 ? "" : " + 1"
            return "sp_StrArray_slice(" + rc + ", " + left + ", " + right + " - " + left + adj + ")"
          end
          if a.length >= 2
            return "sp_StrArray_slice(" + rc + ", " + compile_expr(a[0]) + ", " + compile_expr(a[1]) + ")"
          end
        end
        return "sp_StrArray_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "first"
        return "sp_StrArray_get(" + rc + ", 0)"
      end
      if mname == "last"
        return "sp_StrArray_get(" + rc + ", sp_StrArray_length(" + rc + ") - 1)"
      end
      if mname == "join"
        jarg = compile_arg0(nid)
        if jarg == "0"
          jarg = "\"\""
        end
        return "sp_StrArray_join(" + rc + ", " + jarg + ")"
      end
      if mname == "push"
        return "(sp_StrArray_push(" + rc + ", " + compile_arg0(nid) + "), 0)"
      end
      if mname == "pop"
        return "sp_StrArray_pop(" + rc + ")"
      end
      if mname == "empty?"
        return "sp_StrArray_empty(" + rc + ")"
      end
      if mname == "include?"
        return "sp_StrArray_include(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "index" || mname == "find_index"
        if @nd_arguments[nid] >= 0
          return "sp_StrArray_index(" + rc + ", " + compile_arg0(nid) + ")"
        end
      end
      if mname == "rindex"
        if @nd_arguments[nid] >= 0
          return "sp_StrArray_rindex(" + rc + ", " + compile_arg0(nid) + ")"
        end
      end
      if mname == "delete_at"
        return "sp_StrArray_delete_at(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "tally"
        @needs_str_int_hash = 1
        return "sp_StrArray_tally(" + rc + ")"
      end
      if mname == "compact"
        return "sp_StrArray_compact(" + rc + ")"
      end
      if mname == "insert"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 2
            return "(sp_StrArray_insert(" + rc + ", " + compile_expr(aargs[0]) + ", " + compile_expr(aargs[1]) + "), " + rc + ")"
          end
        end
      end
      if mname == "count"
        return "sp_StrArray_length(" + rc + ")"
      end
      if mname == "intersection"
        return "sp_StrArray_intersect(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "union"
        return "sp_StrArray_union(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "difference"
        return "sp_StrArray_difference(" + rc + ", " + compile_arg0(nid) + ")"
      end
    end

    # PolyArray methods
    if recv_type == "poly_array"
      if mname == "length"
        return "sp_PolyArray_length(" + rc + ")"
      end
      if mname == "[]"
        return "sp_PolyArray_get(" + rc + ", " + compile_arg0_as_int(nid) + ")"
      end
      if mname == "push"
        arg_id = -1
        aargs = get_args(@nd_arguments[nid])
        if aargs.length > 0
          arg_id = aargs[0]
        end
        return "(sp_PolyArray_push(" + rc + ", " + box_expr_to_poly(arg_id) + "), 0)"
      end
      # `clear` in expression position (e.g. `@x ||= @arr.clear`).
      # Mirrors the stmt-form arm in compile_*_stmt: zero the
      # length, leave capacity/buffer alone, return the (now-empty)
      # array so the caller can chain.
      if mname == "clear"
        return "(" + rc + "->len = 0, " + rc + ")"
      end
    end
    ""
  end

  def compile_hash_method_expr(nid, mname, rc, recv_type)
    # Hash methods
    if mname == "dig"
      return compile_hash_dig(nid, rc, recv_type)
    end
    if recv_type == "sym_int_hash"
      if mname == "[]"
        args_id0 = @nd_arguments[nid]
        if args_id0 >= 0
          aa0 = get_args(args_id0)
          if aa0.length > 0 && infer_type(aa0[0]) != "symbol"
            return "((mrb_int)0)"
          end
        end
        return "sp_SymIntHash_get((sp_SymIntHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        args_id1 = @nd_arguments[nid]
        if args_id1 >= 0
          aa1 = get_args(args_id1)
          if aa1.length > 0 && infer_type(aa1[0]) != "symbol"
            return "FALSE"
          end
        end
        return "sp_SymIntHash_has_key((sp_SymIntHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_SymIntHash_length((sp_SymIntHash *)(" + rc + "))"
      end
      if mname == "empty?"
        return "(sp_SymIntHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_SymIntHash_length(" + rc + ") > 0)"
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_SymIntHash_has_key(" + rc + ", " + key + ") ? sp_SymIntHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_SymIntHash_get((sp_SymIntHash *)(" + rc + "), " + key + ")"
        end
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_SymIntHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_int_array = 1
        return "sp_SymIntHash_values(" + rc + ")"
      end
      # transform_values { |v| ... } — same key set, block-transformed
      # int values.  Keeps the result a sym_int_hash; the block's last
      # expression is set as the new value (truncated to mrb_int by
      # sp_SymIntHash_set's signature when the block returns int).
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_SymIntHash *" + tmp + " = sp_SymIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    mrb_int lv_" + bp + " = sp_SymIntHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "int")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_SymIntHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "sym_str_hash"
      if mname == "[]"
        args_id0s = @nd_arguments[nid]
        if args_id0s >= 0
          aa0s = get_args(args_id0s)
          if aa0s.length > 0 && infer_type(aa0s[0]) != "symbol"
            return "(&(\"\\xff\")[1])"
          end
        end
        return "sp_SymStrHash_get((sp_SymStrHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        args_id1s = @nd_arguments[nid]
        if args_id1s >= 0
          aa1s = get_args(args_id1s)
          if aa1s.length > 0 && infer_type(aa1s[0]) != "symbol"
            return "FALSE"
          end
        end
        return "sp_SymStrHash_has_key((sp_SymStrHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_SymStrHash_length((sp_SymStrHash *)(" + rc + "))"
      end
      if mname == "empty?"
        return "(sp_SymStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_SymStrHash_length(" + rc + ") > 0)"
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_SymStrHash_has_key(" + rc + ", " + key + ") ? sp_SymStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_SymStrHash_get((sp_SymStrHash *)(" + rc + "), " + key + ")"
        end
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_SymStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_str_array = 1
        return "sp_SymStrHash_values(" + rc + ")"
      end
    end
    if recv_type == "sym_poly_hash"
      if mname == "[]"
        return "sp_SymPolyHash_get((sp_SymPolyHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_SymPolyHash_has_key((sp_SymPolyHash *)(" + rc + "), " + compile_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_SymPolyHash_length((sp_SymPolyHash *)(" + rc + "))"
      end
      if mname == "empty?"
        return "(sp_SymPolyHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_SymPolyHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_SymPolyHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_poly_array = 1
        @needs_rb_value = 1
        return "sp_SymPolyHash_values(" + rc + ")"
      end
      if mname == "merge"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length == 1
            arg_t = infer_type(aargs[0])
            if arg_t == "sym_poly_hash"
              tmp = new_temp
              emit("  sp_SymPolyHash *" + tmp + " = sp_SymPolyHash_merge(" + rc + ", " + compile_arg0(nid) + ");")
              return tmp
            elsif arg_t == "poly"
              # Poly-typed local whose runtime value is a sym_poly_hash
              # (typical when an `is_a?` branch widened the static
              # type). Guard the unbox with a cls_id check; if the
              # arg is something else at runtime, fall back to a
              # receiver-only copy (the override is silently dropped,
              # which matches the pre-existing behaviour for
              # unsupported argument types).
              tmp_arg = new_temp
              tmp = new_temp
              emit("  sp_RbVal " + tmp_arg + " = " + compile_arg0(nid) + ";")
              emit("  sp_SymPolyHash *" + tmp + " = (" + tmp_arg + ".tag == SP_TAG_OBJ && " + tmp_arg + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) ? sp_SymPolyHash_merge(" + rc + ", (sp_SymPolyHash *)" + tmp_arg + ".v.p) : sp_SymPolyHash_merge(" + rc + ", sp_SymPolyHash_new());")
              return tmp
            end
          end
        end
      end
    end
    if recv_type == "str_poly_hash"
      if mname == "[]"
        return "sp_StrPolyHash_get(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_StrPolyHash_has_key(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_StrPolyHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_StrPolyHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_StrPolyHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        return "sp_StrPolyHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_poly_array = 1
        @needs_rb_value = 1
        return "sp_StrPolyHash_values(" + rc + ")"
      end
    end
    if recv_type == "poly_poly_hash"
      args_id_ph = @nd_arguments[nid]
      if mname == "[]" && args_id_ph >= 0
        a0 = get_args(args_id_ph)[0]
        return "sp_PolyPolyHash_get(" + rc + ", " + box_expr_to_poly(a0) + ")"
      end
      if (mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?") && args_id_ph >= 0
        a0 = get_args(args_id_ph)[0]
        return "sp_PolyPolyHash_has_key(" + rc + ", " + box_expr_to_poly(a0) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_PolyPolyHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_PolyPolyHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_PolyPolyHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        @needs_poly_array = 1
        @needs_rb_value = 1
        return "sp_PolyPolyHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_poly_array = 1
        @needs_rb_value = 1
        return "sp_PolyPolyHash_values(" + rc + ")"
      end
    end
    if recv_type == "str_int_hash"
      if mname == "[]"
        return "sp_StrIntHash_get(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_StrIntHash_has_key(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_StrIntHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_StrIntHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_StrIntHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        return "sp_StrIntHash_keys(" + rc + ")"
      end
      if mname == "values"
        return "sp_StrIntHash_values(" + rc + ")"
      end
      if (mname == "select" || mname == "reject") && @nd_block[nid] >= 0
        return compile_hash_select_reject(nid, "str_int_hash", rc, mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?" || mname == "find" || mname == "detect") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "str_int_hash", rc, mname)
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr_as_string(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_StrIntHash_has_key(" + rc + ", " + key + ") ? sp_StrIntHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_StrIntHash_get(" + rc + ", " + key + ")"
        end
      end
      if mname == "merge"
        tmp = new_temp
        arg = compile_arg0(nid)
        emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_merge(" + rc + ", " + arg + ");")
        return tmp
      end
      if mname == "to_a"
        tt = "tuple:string,int"
        register_tuple_type(tt)
        @needs_gc = 1
        tname = tuple_c_name(tt)
        tmp = new_temp
        itmp = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrIntHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    mrb_int lv_" + bp + " = sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "int")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
      # transform_keys: apply the block to each key, keep the matching
      # value, build a new hash. Result type matches the input hash
      # type when the block returns the same key C-type — the common
      # case for `transform_keys { |k| k.upcase }` etc.
      if mname == "transform_keys"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = " + rc + "->order[_i];")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "lv_" + bp
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_StrIntHash_set(" + tmp + ", " + bexpr + ", sp_StrIntHash_get(" + rc + ", " + rc + "->order[_i]));")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "int_str_hash"
      @needs_int_str_hash = 1
      if mname == "[]"
        return "sp_IntStrHash_get(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_IntStrHash_has_key(" + rc + ", " + compile_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        return "sp_IntStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_IntStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_IntStrHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        @needs_int_array = 1
        return "sp_IntStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        @needs_str_array = 1
        return "sp_IntStrHash_values(" + rc + ")"
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_IntStrHash_has_key(" + rc + ", " + key + ") ? sp_IntStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_IntStrHash_get(" + rc + ", " + key + ")"
        end
      end
      # transform_values block form. Mirrors str_int_hash's arm: walk
      # self, run the block on each value, build a new hash with the
      # same keys and the block's returns. Result type matches the
      # input hash type.
      if mname == "transform_values"
        if @nd_block[nid] >= 0
          blk = @nd_block[nid]
          bp = get_block_param(nid, 0)
          tmp = new_temp
          emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
          emit("  for (mrb_int _i = 0; _i < " + rc + "->len; _i++) {")
          emit("    const char *lv_" + bp + " = sp_IntStrHash_get(" + rc + ", " + rc + "->order[_i]);")
          push_scope
          declare_var(bp, "string")
          bbody = @nd_body[blk]
          bexpr = "0"
          if bbody >= 0
            bs = get_stmts(bbody)
            if bs.length > 0
              bexpr = compile_expr(bs.last)
            end
          end
          emit("    sp_IntStrHash_set(" + tmp + ", " + rc + "->order[_i], " + bexpr + ");")
          pop_scope
          emit("  }")
          return tmp
        end
      end
    end
    if recv_type == "str_str_hash"
      if mname == "[]"
        return "sp_StrStrHash_get(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "has_key?" || mname == "key?" || mname == "include?" || mname == "member?"
        return "sp_StrStrHash_has_key(" + rc + ", " + compile_str_arg0(nid) + ")"
      end
      if mname == "length" || mname == "size" || (mname == "count" && @nd_block[nid] < 0 && @nd_arguments[nid] < 0)
        if @hoisted_strlen_var != "" && @hoisted_strlen_recv == rc
          return @hoisted_strlen_var
        end
        return "sp_StrStrHash_length(" + rc + ")"
      end
      if mname == "empty?"
        return "(sp_StrStrHash_length(" + rc + ") == 0)"
      end
      if mname == "any?" && @nd_block[nid] < 0
        return "(sp_StrStrHash_length(" + rc + ") > 0)"
      end
      if mname == "keys"
        return "sp_StrStrHash_keys(" + rc + ")"
      end
      if mname == "values"
        return "sp_StrStrHash_values(" + rc + ")"
      end
      if mname == "invert"
        return "sp_StrStrHash_invert(" + rc + ")"
      end
      if mname == "to_a"
        tt = "tuple:string,string"
        register_tuple_type(tt)
        @needs_gc = 1
        tname = tuple_c_name(tt)
        tmp = new_temp
        itmp = new_temp
        emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
        emit("  for (mrb_int " + itmp + " = 0; " + itmp + " < " + rc + "->len; " + itmp + "++) {")
        emit("    " + tname + " *_tp = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        emit("    _tp->_0 = " + rc + "->order[" + itmp + "];")
        emit("    _tp->_1 = sp_StrStrHash_get(" + rc + ", " + rc + "->order[" + itmp + "]);")
        emit("    sp_PtrArray_push(" + tmp + ", _tp);")
        emit("  }")
        return tmp
      end
      if (mname == "select" || mname == "reject") && @nd_block[nid] >= 0
        return compile_hash_select_reject(nid, "str_str_hash", rc, mname)
      end
      if (mname == "count" || mname == "any?" || mname == "all?" || mname == "find" || mname == "detect") && @nd_block[nid] >= 0
        return compile_hash_block_predicate(nid, "str_str_hash", rc, mname)
      end
      if mname == "fetch"
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          key = compile_expr_as_string(aargs[0])
          if aargs.length >= 2
            defval = compile_expr(aargs[1])
            return "(sp_StrStrHash_has_key(" + rc + ", " + key + ") ? sp_StrStrHash_get(" + rc + ", " + key + ") : " + defval + ")"
          end
          return "sp_StrStrHash_get(" + rc + ", " + key + ")"
        end
      end
    end
    ""
  end

  # Multi-key Hash#dig walks across poly slots: each step dispatches
  # on acc.cls_id to pick a concrete-hash variant (cls_ids stamped in
  # box_value_to_poly via cls_id_for_hash_type). A cls_id that matches
  # no known variant collapses the walk to nil, covering both "key
  # missing mid-walk" and "value at this depth isn't a hash".
  def compile_hash_dig(nid, rc, recv_type)
    args_id = @nd_arguments[nid]
    aargs = []
    if args_id >= 0
      aargs = get_args(args_id)
    end
    if aargs.length == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

    # `"".split(",")` builds an empty str_array — bare `[]` would be
    # inferred as int_array under spinel's self-host rules and can't
    # hold the string temps below.
    key_tmps = "".split(",")
    key_types = "".split(",")
    ki = 0
    while ki < aargs.length
      kt = infer_type(aargs[ki])
      tmp = new_temp
      if kt == "symbol"
        emit("  sp_sym " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      elsif kt == "string"
        emit("  const char *" + tmp + " = " + compile_expr_as_string(aargs[ki]) + ";")
      elsif kt == "int"
        emit("  mrb_int " + tmp + " = " + compile_expr(aargs[ki]) + ";")
      else
        emit("  mrb_int " + tmp + " = 0; (void)" + tmp + ";")
      end
      key_tmps.push(tmp)
      key_types.push(kt)
      ki = ki + 1
    end

    # First-key static mismatch: short-circuit before the typed `_get`
    # so we don't fabricate a sentinel 0/"" leaf that would round-trip
    # through boxing as a real boxed 0/"".
    if hash_key_matches_recv(recv_type, key_types[0]) == 0
      @needs_rb_value = 1
      return "sp_box_nil()"
    end

    if aargs.length == 1
      return hash_get_expr(recv_type, rc, key_tmps[0])
    end

    @needs_rb_value = 1
    acc = new_temp
    emit("  sp_RbVal " + acc + ";")
    first_get = hash_get_expr(recv_type, rc, key_tmps[0])
    emit("  " + acc + " = " + box_non_nullable_value_to_poly(hash_leaf_type(recv_type), first_get) + ";")

    si = 1
    while si < aargs.length
      emit_dig_step(acc, key_tmps[si], key_types[si])
      si = si + 1
    end
    acc
  end

  # Caller must pass `key_expr` typed for recv_type's key family —
  # compile_hash_dig validates this with hash_key_matches_recv first.
  def hash_get_expr(recv_type, rc, key_expr)
    if recv_type == "sym_int_hash"
      return "sp_SymIntHash_get((sp_SymIntHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_str_hash"
      return "sp_SymStrHash_get((sp_SymStrHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "sym_poly_hash"
      @needs_rb_value = 1
      return "sp_SymPolyHash_get((sp_SymPolyHash *)(" + rc + "), " + key_expr + ")"
    end
    if recv_type == "str_poly_hash"
      @needs_rb_value = 1
      return "sp_StrPolyHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_int_hash"
      return "sp_StrIntHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "str_str_hash"
      return "sp_StrStrHash_get(" + rc + ", " + key_expr + ")"
    end
    if recv_type == "int_str_hash"
      return "sp_IntStrHash_get(" + rc + ", " + key_expr + ")"
    end
    "0"
  end

  # Non-poly inner hashes need a has_key guard: their typed `_get`
  # returns 0/"" on miss, which sp_box_int/sp_box_str would otherwise
  # round-trip as a genuine 0/"" leaf indistinguishable from a real
  # value. Poly inner hashes don't need the guard — their `_get`
  # already returns sp_box_nil() on miss.
  def emit_dig_step(acc, key_expr, key_type)
    emit("  if (" + acc + ".tag != SP_TAG_OBJ) { " + acc + " = sp_box_nil(); } else {")
    if key_type == "symbol"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_SYM_POLY_HASH", "sp_SymPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_INT_HASH", "sp_SymIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_SYM_STR_HASH", "sp_SymStrHash", "sp_box_str")
    elsif key_type == "string"
      emit_dig_arm_poly(acc, key_expr, "SP_BUILTIN_STR_POLY_HASH", "sp_StrPolyHash")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_INT_HASH", "sp_StrIntHash", "sp_box_int")
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_STR_STR_HASH", "sp_StrStrHash", "sp_box_str")
    elsif key_type == "int"
      emit_dig_arm_typed(acc, key_expr, "SP_BUILTIN_INT_STR_HASH", "sp_IntStrHash", "sp_box_str")
    end
    emit("    " + acc + " = sp_box_nil();")
    emit("  }")
  end

  def emit_dig_arm_poly(acc, key_expr, cls_id, cstruct)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + acc + " = " + cstruct + "_get((" + cstruct + " *)" + acc + ".v.p, " + key_expr + "); } else")
  end

  def emit_dig_arm_typed(acc, key_expr, cls_id, cstruct, box_fn)
    emit("    if (" + acc + ".cls_id == " + cls_id + ") { " + cstruct + " *_dh = (" + cstruct + " *)" + acc + ".v.p; " + acc + " = " + cstruct + "_has_key(_dh, " + key_expr + ") ? " + box_fn + "(" + cstruct + "_get(_dh, " + key_expr + ")) : sp_box_nil(); } else")
  end

  def compile_enumerable_expr(nid, mname)
    # map as expression
    if mname == "map"
      if @nd_block[nid] >= 0
        return compile_map_expr(nid)
      end
    end

    # flat_map as expression
    if mname == "flat_map"
      if @nd_block[nid] >= 0
        return compile_flat_map_expr(nid)
      end
    end

    # each_with_object as expression: run the loop as side effect, return obj
    if mname == "each_with_object"
      if @nd_block[nid] >= 0
        return compile_each_with_object_block(nid)
      end
    end

    # tap: run block with receiver, return receiver
    if mname == "tap"
      if @nd_block[nid] >= 0
        return compile_tap_expr(nid)
      end
    end

    # then / yield_self: pass receiver to block, return block result
    if mname == "then" || mname == "yield_self"
      if @nd_block[nid] >= 0
        return compile_then_expr(nid)
      end
    end

    # select as expression
    if mname == "select" || mname == "filter"
      if @nd_block[nid] >= 0
        return compile_select_expr(nid)
      end
    end

    # reject as expression
    if mname == "reject"
      if @nd_block[nid] >= 0
        return compile_reject_expr(nid)
      end
    end

    # reduce/inject as expression
    if mname == "reduce"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    if mname == "inject"
      if @nd_block[nid] >= 0
        return compile_reduce_expr(nid)
      end
    end
    ""
  end

  def compile_constant_recv_expr(nid, mname, recv, rc)
    rcname = constructor_class_name(recv)
    if rcname != ""
      # Foo.method_defined?(:sym[, inherit=true]) — compile-time decide.
      # Default arm walks the parent chain via class_has_method (covers
      # instance methods, attr readers/writers, ancestors).  When the
      # second arg is the literal `false`, restrict the lookup to the
      # receiver's own methods (no parent walk) via class_has_method_local.
      if mname == "method_defined?"
        ci_md = find_class_idx(rcname)
        if ci_md >= 0
          args_id_md = @nd_arguments[nid]
          if args_id_md >= 0
            a_md = get_args(args_id_md)
            if a_md.length > 0
              if @nd_type[a_md[0]] == "SymbolNode" || @nd_type[a_md[0]] == "StringNode"
                lit_name = @nd_content[a_md[0]]
                inherit_md = 1
                if a_md.length >= 2 && @nd_type[a_md[1]] == "FalseNode"
                  inherit_md = 0
                end
                hit = inherit_md == 1 ? class_has_method(ci_md, lit_name) : class_has_method_local(ci_md, lit_name)
                return hit == 1 ? "TRUE" : "FALSE"
              end
            end
          end
        end
      end
      # ARGV methods
      if rcname == "ARGV"
        if mname == "length"
          return "sp_argv.len"
        end
        if mname == "[]"
          idx_expr = compile_arg0(nid)
          return "((" + idx_expr + " < sp_argv.len) ? sp_argv.data[(int)" + idx_expr + "] : NULL)"
        end
      end
      # Math
      if rcname == "Math"
        if mname == "sqrt"
          return "sqrt(" + compile_arg0(nid) + ")"
        end
        if mname == "cos"
          return "cos(" + compile_arg0(nid) + ")"
        end
        if mname == "sin"
          return "sin(" + compile_arg0(nid) + ")"
        end
        if mname == "tan"
          return "tan(" + compile_arg0(nid) + ")"
        end
        if mname == "acos"
          return "acos(" + compile_arg0(nid) + ")"
        end
        if mname == "asin"
          return "asin(" + compile_arg0(nid) + ")"
        end
        if mname == "atan"
          return "atan(" + compile_arg0(nid) + ")"
        end
        if mname == "sinh"
          return "sinh(" + compile_arg0(nid) + ")"
        end
        if mname == "cosh"
          return "cosh(" + compile_arg0(nid) + ")"
        end
        if mname == "tanh"
          return "tanh(" + compile_arg0(nid) + ")"
        end
        if mname == "asinh"
          return "asinh(" + compile_arg0(nid) + ")"
        end
        if mname == "acosh"
          return "acosh(" + compile_arg0(nid) + ")"
        end
        if mname == "atanh"
          return "atanh(" + compile_arg0(nid) + ")"
        end
        if mname == "log"
          return "log(" + compile_arg0(nid) + ")"
        end
        if mname == "log2"
          return "log2(" + compile_arg0(nid) + ")"
        end
        if mname == "log10"
          return "log10(" + compile_arg0(nid) + ")"
        end
        if mname == "exp"
          return "exp(" + compile_arg0(nid) + ")"
        end
        if mname == "atan2"
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return "atan2(" + compile_expr(arg_ids[0]) + ", " + compile_expr(arg_ids[1]) + ")"
            end
          end
        end
        if mname == "hypot"
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return "hypot(" + compile_expr(arg_ids[0]) + ", " + compile_expr(arg_ids[1]) + ")"
            end
          end
        end
      end
      # Integer class methods (Ruby 2.5+)
      if rcname == "Integer"
        if mname == "sqrt"
          # Integer.sqrt(n) is the integer square root, distinct from
          # Math.sqrt's float result. Use sp_int_sqrt (Newton's method,
          # exact for the full mrb_int range) instead of casting through
          # double — double has only 53 bits of mantissa so values above
          # ~2^53 round and produce off-by-one results.
          return "sp_int_sqrt(" + compile_arg0(nid) + ")"
        end
      end
      # File operations
      if rcname == "File"
        if mname == "read" || mname == "binread"
          return "sp_file_read(" + compile_arg0(nid) + ")"
        end
        if mname == "exist?"
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "readable?"
          # Reuse the exist check: on every platform Spinel
          # targets, a fopen-able file is also readable from
          # the same process. Distinguishing the two would
          # need access(2), which isn't worth a runtime fn for
          # the dead-code optcarrot battery-save path that
          # surfaced this.
          return "sp_file_exist(" + compile_arg0(nid) + ")"
        end
        if mname == "delete"
          return "(sp_file_delete(" + compile_arg0(nid) + "), 0)"
        end
        if mname == "binwrite"
          # NOTE: `sp_file_write` uses fputs, so an embedded NUL
          # in the payload truncates the write — fine for the
          # optcarrot save-RAM dead-code path that surfaced
          # this, not safe for general binary use.
          args_id_bw = @nd_arguments[nid]
          if args_id_bw >= 0
            a_bw = get_args(args_id_bw)
            if a_bw.length >= 2
              return "(sp_file_write(" + compile_expr(a_bw[0]) + ", " + compile_expr(a_bw[1]) + "), 0)"
            end
          end
          return "0"
        end
        if mname == "join"
          args_id = @nd_arguments[nid]
          if args_id >= 0
            arg_ids = get_args(args_id)
            if arg_ids.length >= 2
              return "sp_str_concat(sp_str_concat(" + compile_expr(arg_ids[0]) + ", \"/\"), " + compile_expr(arg_ids[1]) + ")"
            end
          end
          return "\"\""
        end
        if mname == "basename"
          return "sp_file_basename(" + compile_arg0(nid) + ")"
        end
      end
      if rcname == "Time"
        if mname == "now"
          return "sp_time_now()"
        end
        if mname == "at"
          arg_id = compile_arg0(nid)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0 && infer_type(aargs[0]) == "float"
              return "sp_time_at_float(" + arg_id + ")"
            end
          end
          return "sp_time_at_int(" + arg_id + ")"
        end
      end
      # Complex.polar(magnitude, angle) — value-type Cartesian
      # Complex (sp_Complex). Used in optcarrot's nestopia palette
      # generator; see lib/sp_runtime.h for the runtime helpers.
      # Args may arrive boxed (poly) when the surrounding code
      # destructured them out of a poly_array; unbox via
      # sp_poly_to_f rather than a plain `(mrb_float)` cast (the
      # cast would mis-reinterpret the sp_RbVal struct).
      if rcname == "Complex"
        if mname == "polar"
          args_id_cp = @nd_arguments[nid]
          if args_id_cp >= 0
            aargs_cp = get_args(args_id_cp)
            if aargs_cp.length >= 2
              a0_e = compile_expr(aargs_cp[0])
              a1_e = compile_expr(aargs_cp[1])
              if infer_type(aargs_cp[0]) == "poly"
                a0_e = "sp_poly_to_f(" + a0_e + ")"
              else
                a0_e = "(mrb_float)(" + a0_e + ")"
              end
              if infer_type(aargs_cp[1]) == "poly"
                a1_e = "sp_poly_to_f(" + a1_e + ")"
              else
                a1_e = "(mrb_float)(" + a1_e + ")"
              end
              return "sp_complex_polar(" + a0_e + ", " + a1_e + ")"
            end
          end
        end
      end
      # Process.clock_gettime — assume CLOCK_MONOTONIC; the clock_id
      # arg is not modeled. Returns seconds as a float.
      if rcname == "Process"
        if mname == "clock_gettime"
          return "({ struct timespec _ts; clock_gettime(CLOCK_MONOTONIC, &_ts); (mrb_float)_ts.tv_sec + (mrb_float)_ts.tv_nsec / 1e9; })"
        end
      end
      # ENV
      if rcname == "ENV"
        if mname == "[]"
          return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
        end
        if mname == "fetch"
          # Two-arg form: ENV.fetch(key, default). If the env var is
          # set, return its value; otherwise return the supplied
          # default. The single-arg form (`ENV.fetch("X")`) raises
          # KeyError in CRuby; spinel doesn't model that, so it
          # behaves like ENV[] -- callers wanting strict behaviour
          # should pass an explicit default.
          args_id = @nd_arguments[nid]
          if args_id >= 0
            argz = get_args(args_id)
            if argz.length >= 2
              key = compile_expr(argz[0])
              dfl = compile_expr_as_string(argz[1])
              tmp = new_temp
              return "({ const char *" + tmp + " = getenv(" + key + "); " +
                     tmp + " ? sp_str_dup_external(" + tmp + ") : (" + dfl + "); })"
            end
            if argz.length == 1
              return "sp_str_dup_external(getenv(" + compile_arg0(nid) + "))"
            end
          end
          return "(&(\"\\xff\")[1])"
        end
      end
      # Dir
      if rcname == "Dir"
        if mname == "home"
          return "sp_str_dup_external(getenv(\"HOME\"))"
        end
      end
      # Module class method dispatch
      mi2 = 0
      while mi2 < @module_names.length
        if @module_names[mi2] == rcname
          # Look for module class method
          mfn = rcname + "_cls_" + mname
          mfi = find_method_idx(mfn)
          if mfi >= 0
            # Route through compile_call_args_with_defaults so a
            # `def self.greet(name, msg = nil); end` inside a
            # module accepts shorter call sites — caller-omitted
            # trailing args get filled in from the method's
            # recorded default expressions, the same as top-level
            # method calls.
            ca = compile_call_args_with_defaults(nid, mfi)
            if ca != ""
              return "sp_" + sanitize_name(mfn) + "(" + ca + ")"
            else
              return "sp_" + sanitize_name(mfn) + "()"
            end
          end
        end
        mi2 = mi2 + 1
      end
      # `Klass.method(:cls_meth)` — bind to a class method. Mirrors
      # the instance-recv `obj.method(:bar)` form (line ~20940), but
      # the underlying class method has no `self *` param. Emit a
      # static adapter trampoline that ignores the dispatch ABI's
      # `void *self` slot and forwards the rest, then bind the
      # Method's iv_fn_ptr to the adapter. iv_self_obj is unused but
      # set to a stable stand-in (a NULL pointer cast through
      # sp_Method *); the Method dispatch in compile_poly_method_call
      # passes it as the void * arg, which the adapter discards.
      if mname == "method"
        ci_cm = find_class_idx(rcname)
        if ci_cm >= 0
          args_id_cm = @nd_arguments[nid]
          if args_id_cm >= 0
            arg_ids_cm = get_args(args_id_cm)
            if arg_ids_cm.length >= 1
              cm_ref = @nd_content[arg_ids_cm[0]]
              if cm_ref == ""
                cm_ref = @nd_name[arg_ids_cm[0]]
              end
              owner_cm = cls_cmethod_owner(ci_cm, cm_ref)
              if owner_cm >= 0
                owner_cm_name = @cls_names[owner_cm]
                emit_cls_method_adapter(owner_cm, cm_ref)
                adapter_name = "sp_" + owner_cm_name + "_" + sanitize_name(cm_ref) + "_cls_method_adapter"
                return "sp_Method_new((sp_Method *)0, (mrb_int)(uintptr_t)&" + adapter_name + ")"
              end
            end
          end
        end
      end
      # Class method dispatch (def self.xxx). Issue #208: walk the
      # parent chain so `Leaf.all` resolves to `Base.all`'s emitter
      # (`sp_Base_cls_all`, not `sp_Leaf_cls_all` which is never
      # generated when Leaf doesn't override).
      ci3 = find_class_idx(rcname)
      if ci3 >= 0
        owner_ci = cls_cmethod_owner(ci3, mname)
        if owner_ci >= 0
          owner_name = @cls_names[owner_ci]
          ca = compile_call_args(nid)
          # Fill in defaults for trailing params the caller
          # omitted. `def self.greet(name, msg = nil)` with call
          # site `C.greet("a")` would otherwise emit
          # `sp_C_cls_greet("a")` against the 2-arg signature and
          # the C compiler rejects with `too few arguments`. Look
          # up the cls method's recorded defaults (parallel to
          # @cls_meth_defaults for instance methods) and append
          # the missing trailing exprs.
          owner_cmnames = @cls_cmeth_names[owner_ci].split(";")
          owner_cmptypes = @cls_cmeth_ptypes[owner_ci].split("|")
          owner_cmdefaults = @cls_cmeth_defaults[owner_ci].split("|")
          cmidx239 = 0
          while cmidx239 < owner_cmnames.length
            if owner_cmnames[cmidx239] == mname
              break
            end
            cmidx239 = cmidx239 + 1
          end
          if cmidx239 < owner_cmnames.length && cmidx239 < owner_cmptypes.length
            owner_pt = owner_cmptypes[cmidx239].split(",")
            owner_df = "".split(",")
            if cmidx239 < owner_cmdefaults.length
              owner_df = owner_cmdefaults[cmidx239].split(",")
            end
            args_id239 = @nd_arguments[nid]
            arg_count239 = 0
            if args_id239 >= 0
              arg_count239 = get_args(args_id239).length
            end
            kk239 = arg_count239
            while kk239 < owner_pt.length
              if kk239 < owner_df.length
                def_id239 = owner_df[kk239].to_i
                if def_id239 >= 0
                  if ca == ""
                    ca = compile_expr(def_id239)
                  else
                    ca = ca + ", " + compile_expr(def_id239)
                  end
                end
              end
              kk239 = kk239 + 1
            end
          end
          if ca != ""
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "(" + ca + ")"
          else
            return "sp_" + owner_name + "_cls_" + sanitize_name(mname) + "()"
          end
        end
      end
    end
    ""
  end

  def compile_to_a_range_expr(nid, recv)
    range_nid = -1
    if @nd_type[recv] == "RangeNode"
      range_nid = recv
    end
    if @nd_type[recv] == "ParenthesesNode"
      pb = @nd_body[recv]
      if pb >= 0
        pstmts = get_stmts(pb)
        if pstmts.length > 0
          if @nd_type[pstmts.first] == "RangeNode"
            range_nid = pstmts.first
          end
        end
      end
    end
    if range_nid >= 0
      @needs_int_array = 1
      @needs_gc = 1
      right_expr = compile_expr(@nd_right[range_nid])
      # sp_IntArray_from_range is inclusive; for `1...3` shave the upper end.
      if range_excl_end(range_nid) == 1
        right_expr = "(" + right_expr + ") - 1"
      end
      return "sp_IntArray_from_range(" + compile_expr(@nd_left[range_nid]) + ", " + right_expr + ")"
    end
    ""
  end

  def compile_open_class_dispatch_expr(nid, mname, rc, recv_type)
    # Open class method dispatch on built-in types
    oc_prefix = ""
    if recv_type == "int"
      oc_prefix = "__oc_Integer_"
    end
    if recv_type == "string"
      oc_prefix = "__oc_String_"
    end
    if recv_type == "float"
      oc_prefix = "__oc_Float_"
    end
    if oc_prefix != ""
      oc_name = oc_prefix + mname
      oc_mi = find_method_idx(oc_name)
      if oc_mi >= 0
        ca = compile_call_args(nid)
        if ca != ""
          return "sp_" + sanitize_name(oc_name) + "(" + rc + ", " + ca + ")"
        else
          return "sp_" + sanitize_name(oc_name) + "(" + rc + ")"
        end
      end
    end
    ""
  end

  def compile_introspection_expr(nid, mname, rc, recv_type)
    # is_a? - check class hierarchy
    if mname == "is_a?"
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        arg0 = ""
        args_id = @nd_arguments[nid]
        if args_id >= 0
          a = get_args(args_id)
          if a.length > 0
            arg0 = @nd_name[a[0]]
          end
        end
        # Check if cname is or inherits from arg0
        if is_class_or_ancestor(cname, arg0) == 1
          return "TRUE"
        else
          return "FALSE"
        end
      end
      return "FALSE"
    end

    # respond_to? - check if method exists
    if mname == "respond_to?"
      if is_obj_type(recv_type) == 1
        cname = recv_type[4, recv_type.length - 4]
        ci = find_class_idx(cname)
        if ci >= 0
          arg0 = ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            a = get_args(args_id)
            if a.length > 0
              arg0 = @nd_content[a[0]]
            end
          end
          if cls_find_method(ci, arg0) >= 0
            return "TRUE"
          end
          # Check attr_readers
          readers = @cls_attr_readers[ci].split(";")
          rk = 0
          while rk < readers.length
            if readers[rk] == arg0
              return "TRUE"
            end
            rk = rk + 1
          end
          return "FALSE"
        end
      end
      return "FALSE"
    end

    # nil?
    if mname == "nil?"
      if recv_type == "nil"
        return "TRUE"
      end
      if recv_type == "poly"
        return "sp_poly_nil_p(" + rc + ")"
      end
      if is_nullable_type(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      if type_is_pointer(recv_type) == 1
        return "(" + rc + " == NULL)"
      end
      return "FALSE"
    end

    # frozen? on any type
    if mname == "frozen?"
      return "TRUE"
    end

    # `freeze` on any object — returns the receiver. The string /
    # mutable-str dispatchers earlier in compile_call_expr handle their
    # own variants; this catches everything else (obj_*, sp_Object *,
    # array types, etc.) so `expr.freeze` in a const initializer (issue
    # #63) doesn't fall through to the "0" fallback.
    if mname == "freeze"
      return rc
    end

    # positive? / negative?
    if mname == "positive?"
      return "(" + rc + " > 0)"
    end
    if mname == "negative?"
      return "(" + rc + " < 0)"
    end
    ""
  end

  def compile_object_method_expr(nid, mname, rc, recv_type)
    # Object method calls
    if is_obj_type(recv_type) == 1
      bt = base_type(recv_type)
      cname = bt[4, bt.length - 4]
      ci = find_class_idx(cname)
      if ci >= 0
        arrow = "->"
        if @cls_is_value_type[ci] == 1
          arrow = "."
        end
        # attr_reader
        readers = @cls_attr_readers[ci].split(";")
        j = 0
        while j < readers.length
          if readers[j] == mname
            return rc + arrow + sanitize_ivar(mname)
          end
          j = j + 1
        end
        # attr_writer
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname = mname[0, mname.length - 1]
            writers = @cls_attr_writers[ci].split(";")
            j = 0
            while j < writers.length
              if writers[j] == bname
                # Box the rhs when the slot is poly so the assignment
                # type-matches at C level. Spill the rhs to a typed
                # temp first via a statement-expression so its side
                # effects run exactly once: the chain's value must be
                # the *original* rhs (Ruby's `obj.attr = v` returns
                # `v`), so without the temp the comma form would
                # textually substitute `arg0_w` twice and re-execute
                # any function call inside it.
                slot_t = cls_ivar_type(ci, "@" + bname)
                arg0_w = compile_arg0(nid)
                if slot_t == "poly"
                  arg_t = "int"
                  args_id_w = @nd_arguments[nid]
                  if args_id_w >= 0
                    arg_ids_w = get_args(args_id_w)
                    if arg_ids_w.length > 0
                      arg_t = infer_type(arg_ids_w[0])
                    end
                  end
                  tmp_w = new_temp
                  boxed = box_value_to_poly(arg_t, tmp_w)
                  return "({" + c_type(arg_t) + " " + tmp_w + " = " + arg0_w + "; " + rc + arrow + sanitize_ivar(bname) + " = " + boxed + "; " + tmp_w + ";})"
                end
                return "(" + rc + arrow + sanitize_ivar(bname) + " = " + arg0_w + ")"
              end
              j = j + 1
            end
          end
        end
        # Method call
        owner = find_method_owner(ci, mname)
        if owner != ""
          oci2 = find_class_idx(owner)
          midx2 = -1
          if oci2 >= 0
            midx2 = cls_find_method_direct(oci2, mname)
          end
          # Omit the trailing &block slot from default-padding when the
          # callee declares one — we'll fill it explicitly from the
          # call site's literal block below.
          has_proc = cls_method_has_block_param(oci2, midx2)
          ca = ""
          if midx2 >= 0
            ca = compile_typed_call_args(nid, oci2, midx2, has_proc)
          else
            ca = compile_call_args(nid)
          end
          bp = ""
          if has_proc == 1
            bp = block_forward_expr(nid)
            if bp == ""
              # The callee declares &block but the call site provides
              # none — fill the slot with NULL so the C call has the
              # right arity.
              bp = "0"
            end
          end
          tail = build_call_tail(ca, bp)
          if owner == cname
            return "sp_" + owner + "_" + sanitize_name(mname) + "(" + rc + tail + ")"
          else
            return "sp_" + owner + "_" + sanitize_name(mname) + "((sp_" + owner + " *)" + rc + tail + ")"
          end
        end
      end
    end
    ""
  end

  def compile_int_class_fallback_expr(nid, mname, rc, recv_type)
    # Fallback: if receiver is int (e.g. from IntArray get) but method belongs to a class,
    # cast the int to the appropriate class pointer and dispatch.
    #
    # ...but NOT when `mname` is a method also defined on a
    # primitive type (String, Array, Hash, Integer, etc.). The
    # int-to-class cast here would silently pick the first user
    # class defining the same method name — e.g. routing
    # `s.index("[")` (a String method on a still-int-typed param)
    # to `ArticlesController#index`. A param typed `mrb_int`
    # because it wasn't pinned upstream is not the IntArray-of-
    # pointers shape this fallback was written for; refuse to
    # pick a user class and let the unresolved-call diagnostic
    # fire instead.
    if recv_type == "int" && primitive_method_shared_with_user_class(mname) == 1
      return ""
    end
    if recv_type == "int"
      ci2 = 0
      while ci2 < @cls_names.length
        cname2 = @cls_names[ci2]
        readers2 = @cls_attr_readers[ci2].split(";")
        found_reader = 0
        j2 = 0
        while j2 < readers2.length
          if readers2[j2] == mname
            found_reader = 1
          end
          j2 = j2 + 1
        end
        if found_reader == 1
          return "((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(mname)
        end
        # Check writers
        if mname.length > 1
          if mname[mname.length - 1] == "="
            bname2 = mname[0, mname.length - 1]
            writers2 = @cls_attr_writers[ci2].split(";")
            j2 = 0
            while j2 < writers2.length
              if writers2[j2] == bname2
                return "(((sp_" + cname2 + " *)" + rc + ")->" + sanitize_ivar(bname2) + " = " + compile_arg0(nid) + ")"
              end
              j2 = j2 + 1
            end
          end
        end
        # Check methods
        owner2 = find_method_owner(ci2, mname)
        if owner2 != ""
          oci3 = find_class_idx(owner2)
          midx3 = -1
          if oci3 >= 0
            midx3 = cls_find_method_direct(oci3, mname)
          end
          ca2 = ""
          if midx3 >= 0
            ca2 = compile_typed_call_args(nid, oci3, midx3, 0)
          else
            ca2 = compile_call_args(nid)
          end
          if ca2 != ""
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ", " + ca2 + ")"
          else
            return "sp_" + owner2 + "_" + sanitize_name(mname) + "((sp_" + owner2 + " *)" + rc + ")"
          end
        end
        ci2 = ci2 + 1
      end
    end
    ""
  end


  # Inferred return type for `recv.mname(...)` when `recv` is poly.
  # If every user class that defines mname agrees on the return type,
  # that concrete type is used. If any two disagree, the call is
  # genuinely polymorphic and the caller must treat the result as
  # an sp_RbVal.
  # Returns 1 if class `ci` declares `mname` as an attr_reader (in
  # which case `obj.<mname>` reads `obj->iv_<mname>`).
  def cls_has_attr_reader(ci, mname)
    readers = @cls_attr_readers[ci].split(";")
    j = 0
    while j < readers.length
      if readers[j] == mname
        return 1
      end
      j = j + 1
    end
    0
  end

  # Decide whether a `<poly>[k]` call site (the outer `[]` in
  # `arr[i][k]` chains) can return int instead of poly. The poly
  # value came from `arr[i]` where `arr` is a poly_array; if every
  # element kind observed for `arr`'s slot has an int-returning
  # `[]` (IntArray + Method, the optcarrot `__fetch__` shape), the
  # outer dispatch is guaranteed to land on a poly carrying an int
  # tag, and we can read it as `mrb_int` directly. Returns 0
  # whenever the chain doesn't fit the pattern, so the default
  # poly-typed temp is preserved for everything else.
  def poly_index_narrow_int(nid)
    recv_id = @nd_receiver[nid]
    if recv_id < 0
      return 0
    end
    # The receiver must itself be a `[]` call (`arr[i]`).
    if @nd_type[recv_id] != "CallNode" || @nd_name[recv_id] != "[]"
      return 0
    end
    inner_recv = @nd_receiver[recv_id]
    if inner_recv < 0
      return 0
    end
    # Resolve the inner receiver to an ivar (directly, or via a
    # one-step LV alias from `lv = @ivar`).
    iname = ""
    if @nd_type[inner_recv] == "InstanceVariableReadNode"
      iname = @nd_name[inner_recv]
    elsif @nd_type[inner_recv] == "LocalVariableReadNode"
      lv_name = @nd_name[inner_recv]
      # Codegen-time scope alias takes priority (set by the LV-write
      # handler when `lv = @ivar` is emitted in this scope).
      iname = find_var_ivar_alias(lv_name)
      # Fallback for inference-time (`infer_type` before codegen,
      # when the scope stack hasn't been populated yet): walk the
      # enclosing method bodies for a single, unambiguous
      # `lv_name = @ivar` write. If the LV is reassigned from a
      # non-ivar elsewhere, leave iname empty and let the caller
      # bail out — the alias is no longer load-bearing.
      if iname == ""
        iname = find_lv_ivar_alias_in_ast(lv_name)
      end
    end
    if iname == "" || @current_class_idx < 0
      return 0
    end
    # The slot must currently be a poly_array — the only shape that
    # produces a poly via `[i]`.
    slot_t = cls_ivar_type(@current_class_idx, iname)
    if slot_t != "poly_array"
      return 0
    end
    # Derive the heterogeneous element kinds from
    # `cls_ivar_observed_types`. Each entry there is a slot type
    # the ivar held at some scan iteration: `int_array` means int
    # elements were stored, `obj_Method_ptr_array` means Method
    # elements, etc. The final `poly_array` entry just records the
    # widened state and adds no info. A bare `poly` observation
    # (whole-ivar `@x = something_poly`) is unknown — bail out.
    obs = cls_ivar_observed_types_for(@current_class_idx, iname)
    if obs == ""
      return 0
    end
    distinct = obs.split(",")
    saw_any = 0
    di = 0
    while di < distinct.length
      t = distinct[di]
      if t == "" || t == "poly_array"
        # ignore — uninformative
      elsif t == "int_array" || t == "obj_Method_ptr_array"
        # int-returning element kind
        saw_any = 1
      else
        # any other observed slot type (str_array, float_array,
        # other ptr_array variants, "poly" whole-ivar writes…) is
        # not safely narrowable.
        return 0
      end
      di = di + 1
    end
    saw_any
  end

  # Inference-time fallback for resolving `lv_name -> @ivar` when the
  # codegen scope alias isn't available yet. Walks every method body
  # in the current class for `lv_name = @ivar` writes. Returns the
  # ivar name only if the LV is unambiguously aliased (one ivar
  # source, no non-ivar reassignment); empty string otherwise. Cached
  # in `@lv_alias_cache_<class>:<lv>` to keep the per-narrow cost
  # down — this is called during type inference, which runs many
  # iterations.
  def find_lv_ivar_alias_in_ast(lv_name)
    if @current_class_idx < 0
      return ""
    end
    cache_key = @current_class_idx.to_s + ":" + lv_name
    if @lv_alias_cache.key?(cache_key)
      return @lv_alias_cache[cache_key]
    end
    found = ""
    bodies = @cls_meth_bodies[@current_class_idx].split(";")
    bi = 0
    while bi < bodies.length
      bid = bodies[bi].to_i
      if bid >= 0
        r = scan_lv_alias_for(bid, lv_name)
        if r == "?"
          # Ambiguous: at least one non-ivar write to this LV. The
          # alias is unstable and unsafe to use for narrowing.
          found = ""
          break
        end
        if r != ""
          if found != "" && found != r
            found = ""
            break
          end
          found = r
        end
      end
      bi = bi + 1
    end
    @lv_alias_cache[cache_key] = found
    found
  end

  # Recursive AST walk under `nid`. Returns:
  #   ""  — no `lv_name = ...` write seen
  #   "?" — `lv_name = <non-ivar>` write seen (alias is unstable)
  #   "@x" — exactly one ivar source `lv_name = @x` seen
  def scan_lv_alias_for(nid, lv_name)
    if nid < 0
      return ""
    end
    found = ""
    if @nd_type[nid] == "LocalVariableWriteNode" && @nd_name[nid] == lv_name
      ex_id = @nd_expression[nid]
      if ex_id >= 0 && @nd_type[ex_id] == "InstanceVariableReadNode"
        found = @nd_name[ex_id]
      else
        return "?"
      end
    end
    cs = []
    push_child_ids(nid, cs)
    k = 0
    while k < cs.length
      r = scan_lv_alias_for(cs[k], lv_name)
      if r == "?"
        return "?"
      end
      if r != ""
        if found != "" && found != r
          return "?"
        end
        found = r
      end
      k = k + 1
    end
    found
  end

  # Read the comma-separated whole-ivar observation list for a given
  # ivar by name. Used by `poly_index_narrow_int`.
  def cls_ivar_observed_types_for(ci, iname)
    if ci < 0 || ci >= @cls_ivar_observed_types.length
      return ""
    end
    names = @cls_ivar_names[ci].split(";")
    parts = @cls_ivar_observed_types[ci].split(";", -1)
    k = 0
    while k < names.length
      if names[k] == iname && k < parts.length
        return parts[k]
      end
      k = k + 1
    end
    ""
  end

  def poly_dispatch_return_type(mname)
    if mname == "[]"
      @needs_rb_value = 1
      return "poly"
    end
    # Setters: mname ends with "=" and at least one class has an
    # attr_writer for the bare name. Return type is the ivar type
    # (Ruby returns the rhs from `x = v`); without this, the result
    # tmp's C type defaults to `mrb_int` and `tmp = rhs` mismatches
    # for non-int slots.
    setter_bname = ""
    if mname.length > 1 && mname[mname.length - 1] == "="
      setter_bname = mname[0, mname.length - 1]
    end
    common = ""
    ci = 0
    while ci < @cls_names.length
      rt = ""
      if cls_find_method_direct(ci, mname) >= 0
        rt = cls_method_return(ci, mname)
      elsif cls_has_attr_reader(ci, mname) == 1
        # An attr_reader returns the ivar type. Issue #119.
        rt = cls_ivar_type(ci, "@" + mname)
      elsif setter_bname != "" && cls_has_attr_writer(ci, setter_bname) == 1
        # An attr_writer setter returns the ivar's type.
        rt = cls_ivar_type(ci, "@" + setter_bname)
      end
      if rt != ""
        if common == ""
          common = rt
        elsif common != rt
          return "poly"
        end
      end
      ci = ci + 1
    end
    common == "" ? "int" : common
  end

  # Runtime tag-check for `<poly>.is_a?(<klass>)` / `kind_of?` /
  # `instance_of?`. Returns a C boolean expression for the named
  # built-in class (Integer, String, Float, etc.), including
  # mixin-style names that match every value (Object, Kernel,
  # BasicObject, Comparable). Returns "" when the name has no
  # SP_TAG_* mapping (caller falls back to user-class dispatch).
  def poly_is_a_tag_check(klass, recv_tmp, is_instance_of)
    if klass == "Integer"
      return "(" + recv_tmp + ".tag == SP_TAG_INT)"
    end
    if klass == "String"
      return "(" + recv_tmp + ".tag == SP_TAG_STR)"
    end
    if klass == "Float"
      return "(" + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Symbol"
      return "(" + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "NilClass"
      return "(" + recv_tmp + ".tag == SP_TAG_NIL)"
    end
    if klass == "TrueClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && " + recv_tmp + ".v.b)"
    end
    if klass == "FalseClass"
      return "(" + recv_tmp + ".tag == SP_TAG_BOOL && !" + recv_tmp + ".v.b)"
    end
    if klass == "Numeric"
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT)"
    end
    if klass == "Comparable"
      if is_instance_of == 1
        return "0"
      end
      return "(" + recv_tmp + ".tag == SP_TAG_INT || " + recv_tmp + ".tag == SP_TAG_FLT || " + recv_tmp + ".tag == SP_TAG_STR || " + recv_tmp + ".tag == SP_TAG_SYM)"
    end
    if klass == "Object" || klass == "Kernel" || klass == "BasicObject"
      # Every value is_a? Object in Ruby. instance_of?(Object) is FALSE
      # for primitives (their class is Integer/String/etc., not Object).
      if is_instance_of == 1
        return "0"
      end
      return "1"
    end
    if klass == "Array"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY || " + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY))"
    end
    if klass == "Hash"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_INT_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_STR_POLY_HASH || " + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH))"
    end
    if klass == "Range"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_RANGE)"
    end
    if klass == "Proc"
      return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == SP_BUILTIN_PROC)"
    end
    ""
  end

  def compile_poly_method_call(nid, rc, mname)
    @needs_rb_value = 1
    if mname == "nil?"
      return "sp_poly_nil_p(" + rc + ")"
    end
    if mname == "to_s"
      return "sp_poly_to_s(" + rc + ")"
    end
    if mname == "to_i"
      # Unbox the poly value's int payload. For SP_TAG_INT it's the
      # raw `v.i`. For SP_TAG_OBJ branches the runtime values are
      # always pointers — `.to_i` on a class that doesn't define
      # `to_i` is the obj-id in Ruby; we approximate as 0 since
      # spinel doesn't expose a stable obj-id and the only practical
      # use is unboxing a poly-with-int payload (e.g. the result of
      # `arr[i][j]` over a heterogeneous IntArray + Method array,
      # whose dispatch arms all box back to SP_TAG_INT).
      tmp = new_temp
      recv_tmp = new_temp
      emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
      emit("  mrb_int " + tmp + " = (" + recv_tmp + ".tag == SP_TAG_INT) ? " + recv_tmp + ".v.i : 0;")
      return tmp
    end
    # `<poly>.is_a?(<Class>)` / `kind_of?` / `instance_of?` — decide
    # at runtime by inspecting the SP_TAG_* tag (and cls_id for
    # SP_TAG_OBJ). Without this branch the call falls through to the
    # SP_TAG_OBJ dispatch below, which has no `is_a?` method on any
    # user class — every primitive arm returns the default and
    # `is_a?(Integer)` on a poly slot is always falsy. Common in
    # dispatch helpers like `(addr.is_a?(Integer) ? [addr] : addr).each`.
    if mname == "is_a?" || mname == "kind_of?" || mname == "instance_of?"
      args_id = @nd_arguments[nid]
      if args_id >= 0
        a = get_args(args_id)
        if a.length > 0
          arg_name = @nd_name[a[0]]
          recv_tmp = new_temp
          emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
          io = mname == "instance_of?" ? 1 : 0
          tag_check = poly_is_a_tag_check(arg_name, recv_tmp, io)
          if tag_check != ""
            return tag_check
          end
          # User-defined class: match by cls_id. instance_of? requires
          # exact class; is_a?/kind_of? include subclasses, so
          # enumerate user classes whose ancestor chain reaches
          # arg_name (cls_is_descendant) and OR them in.
          ci = find_class_idx(arg_name)
          if ci >= 0
            if mname == "instance_of?"
              return "(" + recv_tmp + ".tag == SP_TAG_OBJ && " + recv_tmp + ".cls_id == " + ci.to_s + ")"
            end
            check = "(" + recv_tmp + ".tag == SP_TAG_OBJ && (" + recv_tmp + ".cls_id == " + ci.to_s
            cn = 0
            while cn < @cls_names.length
              if cn != ci && cls_is_descendant(cn, ci) == 1
                check = check + " || " + recv_tmp + ".cls_id == " + cn.to_s
              end
              cn = cn + 1
            end
            check = check + "))"
            return check
          end
          return "0"
        end
      end
      return "0"
    end
    # For object method calls, dispatch based on cls_id. Two namespaces
    # of cls_id share SP_TAG_OBJ:
    #   - non-negative: index into @cls_names (user-defined classes)
    #   - negative SP_BUILTIN_*: built-in pointer types (IntArray, ...)
    # The result temp is typed by the method's return type. If user
    # classes disagree on that type, the result is sp_RbVal and each
    # branch boxes its concrete return value.
    ret_type = poly_dispatch_return_type(mname)
    # Approach 2 narrowing: `<poly>[k]` defaults to poly because the
    # static `[]` dispatch can't pin the return; check whether the
    # poly receiver here came from `<poly_array>[i]` whose every
    # observed element kind has an int-returning `[]` (IntArray,
    # Method-with-int-return). If so, narrow to int so the slot
    # @_pc / @_addr / etc. on the caller side stays mrb_int instead
    # of widening to sp_RbVal and breaking downstream `iv += 1`,
    # `~poly`, and friends.
    narrowed_int_idx = 0
    if ret_type == "poly" && mname == "[]"
      narrowed_int_idx = poly_index_narrow_int(nid)
      if narrowed_int_idx == 1
        ret_type = "int"
      end
    end
    is_poly_ret = ret_type == "poly" ? 1 : 0
    ret_ct = c_type(ret_type)
    ret_def = c_default_val(ret_type)
    # Stash the receiver in a temp so we don't re-evaluate the
    # expression for every if-branch below.
    recv_tmp = new_temp
    emit("  sp_RbVal " + recv_tmp + " = " + rc + ";")
    # Compile the call's argument list once. Track the inferred
    # source type alongside the compiled expression so the int-bit
    # branch below can unbox a poly arg without re-walking the AST.
    arg_compiled = "".split(",")
    arg_types = "".split(",")
    arg_strs = ""
    args_id = @nd_arguments[nid]
    if args_id >= 0
      aargs = get_args(args_id)
      k = 0
      while k < aargs.length
        ce = compile_expr(aargs[k])
        arg_compiled.push(ce)
        arg_types.push(infer_type(aargs[k]))
        arg_strs = arg_strs + ", " + ce
        k = k + 1
      end
    end
    tmp = new_temp
    emit("  " + ret_ct + " " + tmp + " = " + ret_def + ";")
    # `int[i]` (bit-extraction) on a poly receiver. When a CPU
    # register / scratch ivar is widened to sp_RbVal but still
    # carries an int value, `pc[8]` (the page-bit test in branch
    # instructions etc.) must compile to `(pc >> 8) & 1`, not to
    # the array dispatch in the SP_TAG_OBJ block below — which
    # would silently leave the result at nil and miscount cycles.
    # Only emit the int-bit-extract fallback when the index
    # argument is itself an int (or a poly we can unbox to int).
    # For non-int keys (string, sym, ...) the SP_TAG_INT branch
    # is unreachable at runtime and `(recv.v.i >> key)` is
    # invalid C — `>> const char *` won't compile.
    if mname == "[]" && arg_compiled.length >= 1 && (arg_types[0] == "int" || arg_types[0] == "poly")
      a0_int = arg_compiled[0]
      if arg_types[0] == "poly"
        a0_int = "(" + a0_int + ").v.i"
      end
      bit = "((" + recv_tmp + ".v.i >> (" + a0_int + ")) & 1)"
      brhs = is_poly_ret == 1 ? "sp_box_int(" + bit + ")" : bit
      emit("  if (" + recv_tmp + ".tag == SP_TAG_INT) " + tmp + " = " + brhs + ";")
    end
    emit("  if (" + recv_tmp + ".tag == SP_TAG_OBJ) {")
    # User-class dispatch
    i = 0
    while i < @cls_names.length
      cname = @cls_names[i]
      midx = cls_find_method_direct(i, mname)
      if midx >= 0
        # Match each arm to the target method's *fixed* C arity:
        # pad missing trailing slots with default-typed zeros, and
        # truncate extras (when the call site supplies more args than
        # this candidate accepts — happens when several classes share
        # the method name but disagree on parameter count).
        arm_arg_strs = ""
        arm_ptypes = cls_meth_ptypes_get(i, midx)
        pk = 0
        while pk < arm_ptypes.length
          if pk < arg_compiled.length
            # When this arm's param widened to `poly` (cross-
            # call-site union) but the call site supplied a
            # concrete value (string / mrb_int / symbol / ...),
            # box it via the appropriate sp_box_* helper so the
            # arg type matches the slot — otherwise gcc errors
            # `incompatible type for argument` on `const char *` /
            # `mrb_int` into a `sp_RbVal`. The inverse direction
            # (poly arg into a concrete-typed param) is handled
            # downstream; this only does the boxing direction.
            arg_v = arg_compiled[pk]
            arm_pt_base = base_type(arm_ptypes[pk])
            if arm_pt_base == "poly" && pk < arg_types.length && arg_types[pk] != "poly" && arg_types[pk] != ""
              arg_v = box_value_to_poly(arg_types[pk], arg_v)
            end
            arm_arg_strs = arm_arg_strs + ", " + arg_v
          else
            pad = "0"
            pt_base = base_type(arm_ptypes[pk])
            if pt_base == "poly"
              pad = "sp_box_nil()"
            end
            arm_arg_strs = arm_arg_strs + ", " + pad
          end
          pk = pk + 1
        end
        call_expr = "sp_" + cname + "_" + sanitize_name(mname) + "((sp_" + cname + " *)" + recv_tmp + ".v.p" + arm_arg_strs + ")"
        rhs = call_expr
        if is_poly_ret == 1
          this_rt = cls_method_return(i, mname)
          rhs = box_val_to_poly(call_expr, this_rt)
        end
        # Narrowed `[]` arms (Approach 2): suppress user-class arms
        # whose `[]` doesn't return int — the dead-code emit would
        # otherwise assign e.g. a string to the now-mrb_int result
        # temp and fail the C compile. The runtime can't reach these
        # arms anyway because the observation set narrowed past them.
        if narrowed_int_idx == 1 && cls_method_return(i, mname) != "int"
          # skip
        else
          emit("    if (" + recv_tmp + ".cls_id == " + i.to_s + ") " + tmp + " = " + rhs + ";")
        end
      elsif cls_has_attr_reader(i, mname) == 1
        # An auto-registered attr_reader doesn't appear in
        # @cls_meth_names, so the explicit-method walk above misses it.
        # Read the ivar directly. Issue #119.
        ivar_expr = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + mname)
        rhs = ivar_expr
        if is_poly_ret == 1
          this_rt = cls_ivar_type(i, "@" + mname)
          rhs = box_val_to_poly(ivar_expr, this_rt)
        end
        if narrowed_int_idx == 1 && cls_ivar_type(i, "@" + mname) != "int"
          # skip non-int attr_reader arms on a narrowed `[]`
        else
          emit("    if (" + recv_tmp + ".cls_id == " + i.to_s + ") " + tmp + " = " + rhs + ";")
        end
      elsif mname.length > 1 && mname[mname.length - 1] == "=" && cls_has_attr_writer(i, mname[0, mname.length - 1]) == 1
        # An auto-registered attr_writer setter (`obj.x = v`) on a
        # poly-typed receiver. Without this arm the cls_id dispatch
        # finds neither a real method nor an attr_reader, falls
        # through silently, and the assignment never executes —
        # `obj.x = v` becomes a no-op.
        bname = mname[0, mname.length - 1]
        raw_val = arg_compiled.length > 0 ? arg_compiled[0] : "0"
        raw_t   = arg_types.length > 0 ? arg_types[0] : ""
        slot_t  = cls_ivar_type(i, "@" + bname)
        # Match the rhs to the slot's concrete C type for *this arm*.
        # Three cases:
        #   slot poly + arg concrete  -> box the arg.
        #   slot concrete + arg poly  -> unbox the arg.
        #   else                      -> direct assign.
        # Different arms in the dispatch may take different branches
        # (e.g. one slot is `int`, another is `string`).
        store_val = raw_val
        if slot_t == "poly" && raw_t != "poly" && raw_t != ""
          store_val = box_value_to_poly(raw_t, raw_val)
        elsif slot_t != "poly" && raw_t == "poly"
          store_val = unbox_poly_to(slot_t, raw_val)
        end
        ivar_lhs = "((sp_" + cname + " *)" + recv_tmp + ".v.p)->" + sanitize_ivar("@" + bname)
        # `x = v` returns v in Ruby. The result tmp's type is set by
        # poly_dispatch_return_type (poly when slot types diverge,
        # otherwise the common slot type). Box / coerce the stored
        # value into the tmp's expected shape.
        rhs_for_tmp = store_val
        if is_poly_ret == 1
          rhs_for_tmp = box_val_to_poly(store_val, slot_t)
        end
        emit("    if (" + recv_tmp + ".cls_id == " + i.to_s + ") { " + ivar_lhs + " = " + store_val + "; " + tmp + " = " + rhs_for_tmp + "; }")
      end
      i = i + 1
    end
    # Built-in type dispatch (cls_id < 0).
    emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, tmp, is_poly_ret, narrowed_int_idx)
    emit("  }")
    tmp
  end

  # Emit branches for the built-in (negative cls_id) entries. Each
  # entry maps a (SP_BUILTIN_*, method) pair to a C expression.
  # Adding a new built-in type means one more `if` branch here.
  def emit_poly_builtin_dispatch(recv_tmp, mname, arg_compiled, arg_types, result_tmp, is_poly_ret, narrowed_int = 0)
    a0 = ""
    if arg_compiled.length > 0
      a0 = arg_compiled[0]
      # Unbox if poly — every built-in `[]` arm here passes a0 to a
      # function expecting `mrb_int` (sp_IntArray_get etc., or the
      # Method fn_ptr's int parameter). When the caller's arg is
      # poly (e.g. `def fetch(addr); @fetch[addr][addr]; end` with
      # addr widened), we must unbox before the C call.
      if arg_types.length > 0 && arg_types[0] == "poly"
        a0 = "(" + a0 + ").v.i"
      end
    end
    # `[]` — element types differ per built-in. When the result temp
    # is sp_RbVal (poly return), every branch can box into it. When
    # the temp is concretely typed, only built-ins whose element type
    # fits the temp can contribute — otherwise the assignment is a
    # C type mismatch. The unmatched runtime types simply leave the
    # temp at its default (`0`/empty) for that input, which is
    # acceptable since the caller's static type analysis already
    # picked a compatible result type.
    #
    # Every built-in [] arm here passes the key to a function
    # expecting `mrb_int`. Only emit the arms when the key type
    # is int or poly (poly is unboxed via `.v.i` above). For
    # non-int keys (string, sym), these arms are unreachable at
    # runtime (a poly recv carrying a String key would be a hash,
    # not an array) and emitting them produces Wint-conversion
    # warnings — or hard errors under -Werror.
    a0_is_int = arg_compiled.length >= 1 && (arg_types.length == 0 || arg_types[0] == "int" || arg_types[0] == "poly")
    if mname == "[]" && arg_compiled.length >= 1 && a0_is_int
      ic = "sp_IntArray_get((sp_IntArray *)" + recv_tmp + ".v.p, " + a0 + ")"
      irhs = is_poly_ret == 1 ? "sp_box_int(" + ic + ")" : ic
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + irhs + ";")
      if is_poly_ret == 1
        fc = "sp_FloatArray_get((sp_FloatArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = sp_box_float(" + fc + ");")
        sc = "sp_StrArray_get((sp_StrArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = sp_box_str(" + sc + ");")
        # sym_array shares IntArray storage; tag back as symbol when
        # the caller wants a poly result.
        yc = "(sp_sym)sp_IntArray_get((sp_IntArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = sp_box_sym(" + yc + ");")
      end
      # PtrArray dispatch — sp_PtrArray_get returns void*, which is
      # implicitly convertible to any pointer for the non-poly path
      # (result_tmp may be `sp_Foo *`) and accepted directly by
      # sp_box_obj for the poly path. Casting through mrb_int would
      # fail to compile when result_tmp is a pointer type — and the
      # narrowed-`[]` path (Approach 2) types result_tmp as mrb_int,
      # so PtrArray cls_ids are unobserved by construction. Skip the
      # arm in that case.
      if narrowed_int == 0
        pc = "sp_PtrArray_get((sp_PtrArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        prhs = is_poly_ret == 1 ? "sp_box_obj(" + pc + ", 0)" : pc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + prhs + ";")
      end
      # PolyArray dispatch — sp_PolyArray_get returns sp_RbVal directly.
      # When the result temp is poly, just assign; otherwise unbox via .v.i
      # (the typed temp's static type drives caller-side conversion).
      # Narrowed-`[]` likewise excludes PolyArray from the observed
      # set: the arm is unreachable, and emitting `.v.i` against a
      # cls_id that won't match at runtime is harmless but noisy.
      if narrowed_int == 0
        polyc = "sp_PolyArray_get((sp_PolyArray *)" + recv_tmp + ".v.p, " + a0 + ")"
        polyrhs = is_poly_ret == 1 ? polyc : "(" + polyc + ").v.i"
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyrhs + ";")
      end
      # Method dispatch — `bm[arg]` / `bm[a1, a2]` on a Method instance
      # is `bm.call(...)`. When bm came through a heterogeneous
      # poly_array (e.g. optcarrots `@fetch[i] = method(:peek_X)` mixed
      # with `@fetch[i] = @ram` where @fetch is widened to poly_array),
      # the static type at the call site is poly, so the typed
      # obj_Method path at line 20367 doesnt fire. Generate the
      # function-pointer cast + indirect call inline, guarded by a
      # null fn_ptr check (Rubys NoMethodError analogue). Handles up
      # to N args by reusing the same arg_compiled list and unboxing
      # any that came in as poly.
      method_idx = find_class_idx("Method")
      if method_idx >= 0
        mp = "((sp_Method *)" + recv_tmp + ".v.p)"
        sig_args = "void *"
        call_args = "(void *)" + mp + "->iv_self_obj"
        mi = 0
        while mi < arg_compiled.length
          sig_args = sig_args + ", mrb_int"
          ai_val = arg_compiled[mi]
          if mi < arg_types.length && arg_types[mi] == "poly"
            ai_val = "(" + ai_val + ").v.i"
          end
          call_args = call_args + ", " + ai_val
          mi = mi + 1
        end
        mc = "(" + mp + " && " + mp + "->iv_fn_ptr ? ((mrb_int (*)(" + sig_args + "))(uintptr_t)" + mp + "->iv_fn_ptr)(" + call_args + ") : 0)"
        mrhs = is_poly_ret == 1 ? "sp_box_int(" + mc + ")" : mc
        emit("    if (" + recv_tmp + ".cls_id == " + method_idx.to_s + ") " + result_tmp + " = " + mrhs + ";")
      end
    end
    # `[]` with a symbol key — sym_poly_hash dispatch. Mirrors the
    # int-key block above for the case where a poly receiver carries
    # a SymPolyHash at runtime (e.g. a constant hash boxed back into
    # a slot whose static type is poly because of an earlier
    # is_a?(String) branch).
    a0_is_sym = arg_compiled.length >= 1 && arg_types.length >= 1 && arg_types[0] == "symbol"
    if mname == "[]" && a0_is_sym
      shc = "sp_SymPolyHash_get((sp_SymPolyHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
      shrhs = is_poly_ret == 1 ? shc : "(" + shc + ").v.i"
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_POLY_HASH) " + result_tmp + " = " + shrhs + ";")
      # SymIntHash arm: heterogeneous-element array of `{n: 3}`-style
      # hashes (issue #402) boxes each as SymIntHash. Returns mrb_int,
      # box to poly when the call site expects poly. Only emit when
      # the program already uses SymIntHash so we don't pull the
      # runtime helpers in for unrelated programs.
      if @needs_sym_int_hash == 1
        sihc = "sp_SymIntHash_get((sp_SymIntHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sihrhs = is_poly_ret == 1 ? "sp_box_int(" + sihc + ")" : sihc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_INT_HASH) " + result_tmp + " = " + sihrhs + ";")
      end
      if @needs_sym_str_hash == 1
        sshc = "sp_SymStrHash_get((sp_SymStrHash *)" + recv_tmp + ".v.p, " + arg_compiled[0] + ")"
        sshrhs = is_poly_ret == 1 ? "sp_box_str(" + sshc + ")" : sshc
        emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_STR_HASH) " + result_tmp + " = " + sshrhs + ";")
      end
    end
    # `length` / `size` — every built-in array exposes its own
    # `_length` helper (sym_array shares IntArray's). PtrArray is
    # safe here because length doesn't need an element type.
    if mname == "length" || mname == "size"
      ic = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      irhs = is_poly_ret == 1 ? "sp_box_int(" + ic + ")" : ic
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_INT_ARRAY) " + result_tmp + " = " + irhs + ";")
      fc = "sp_FloatArray_length((sp_FloatArray *)" + recv_tmp + ".v.p)"
      frhs = is_poly_ret == 1 ? "sp_box_int(" + fc + ")" : fc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_FLT_ARRAY) " + result_tmp + " = " + frhs + ";")
      sc = "sp_StrArray_length((sp_StrArray *)" + recv_tmp + ".v.p)"
      srhs = is_poly_ret == 1 ? "sp_box_int(" + sc + ")" : sc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_STR_ARRAY) " + result_tmp + " = " + srhs + ";")
      # sym_array shares the IntArray representation (same `_length`).
      yc = "sp_IntArray_length((sp_IntArray *)" + recv_tmp + ".v.p)"
      yrhs = is_poly_ret == 1 ? "sp_box_int(" + yc + ")" : yc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_SYM_ARRAY) " + result_tmp + " = " + yrhs + ";")
      pc = "sp_PtrArray_length((sp_PtrArray *)" + recv_tmp + ".v.p)"
      prhs = is_poly_ret == 1 ? "sp_box_int(" + pc + ")" : pc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_PTR_ARRAY) " + result_tmp + " = " + prhs + ";")
      polyc = "sp_PolyArray_length((sp_PolyArray *)" + recv_tmp + ".v.p)"
      polyrhs = is_poly_ret == 1 ? "sp_box_int(" + polyc + ")" : polyc
      emit("    if (" + recv_tmp + ".cls_id == SP_BUILTIN_POLY_ARRAY) " + result_tmp + " = " + polyrhs + ";")
    end
  end

  # Try to compile str[i] <op> "c" as direct char comparison
  # Returns "" if not applicable
  def try_char_cmp(nid, c_op)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    a = get_args(args_id)
    if a.length == 0
      return ""
    end
    arg_id = a[0]
    if @nd_type[arg_id] != "StringNode"
      return ""
    end
    lit = @nd_content[arg_id]
    if lit == ""
      lit = @nd_unescaped[arg_id]
    end
    if lit.length != 1
      return ""
    end
    if @nd_type[recv] != "CallNode" || @nd_name[recv] != "[]"
      return ""
    end
    sr = @nd_receiver[recv]
    if sr < 0 || infer_type(sr) != "string"
      return ""
    end
    str_c = compile_expr(sr)
    idx_c = compile_arg0(recv)
    ch = lit
    if lit == "\n"
      ch = "\\n"
    elsif lit == "\t"
      ch = "\\t"
    elsif lit == "\r"
      ch = "\\r"
    elsif lit.ord == 92 || lit.ord == 39
      # backslash or single quote — skip char optimization
      return ""
    end
    "(" + str_c + "[(mrb_int)" + idx_c + "] " + c_op + " '" + ch + "')"
  end

  def compile_eq(nid, op)
    recv = @nd_receiver[nid]
    lt = infer_type(recv)
    args_id = @nd_arguments[nid]
    arg_id = -1
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        arg_id = a[0]
      end
    end
    at = "int"
    if arg_id >= 0
      at = infer_type(arg_id)
    end
    lc = compile_expr(recv)
    rc = "0"
    if arg_id >= 0
      rc = compile_expr(arg_id)
    end
    if lt == "poly" || at == "poly"
      @needs_rb_value = 1
      left = lc
      right = rc
      if lt != "poly"
        left = box_value_to_poly(lt, lc)
      end
      if at != "poly"
        right = box_value_to_poly(at, rc)
      end
      if op == "=="
        return "sp_poly_eq(" + left + ", " + right + ")"
      else
        return "(!sp_poly_eq(" + left + ", " + right + "))"
      end
    end
    # Symbol equality: distinct from all non-symbol types in Ruby.
    if lt == "symbol"
      if at == "symbol"
        if op == "=="
          return "(" + lc + " == " + rc + ")"
        else
          return "(" + lc + " != " + rc + ")"
        end
      end
      # sym vs non-sym: always unequal in Ruby
      return op == "==" ? "FALSE" : "TRUE"
    end
    if at == "symbol"
      # non-sym lhs vs sym rhs: also always unequal
      return op == "==" ? "FALSE" : "TRUE"
    end
    if lt == "string"
      if at == "nil"
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
      # Optimize: str[i] == "c" → direct char comparison (no malloc)
      cc = try_char_cmp(nid, op)
      if cc != ""
        return cc
      end
      # NULL-safe equality via sp_str_eq. Plain strcmp(NULL, ...)
      # is UB and segfaults on real inputs (ENV[] returns NULL for
      # unset vars). The helper does a NULL check then strcmp;
      # identical answer for non-NULL operands, so existing
      # equality call sites are unaffected.
      if op == "=="
        return "sp_str_eq(" + lc + ", " + rc + ")"
      else
        return "(!sp_str_eq(" + lc + ", " + rc + "))"
      end
    end
    if at == "nil"
      if type_is_pointer(lt) == 1
        if op == "=="
          return "(" + lc + " == NULL)"
        else
          return "(" + lc + " != NULL)"
        end
      end
    end
    if lt == "int_array"
      if at == "int_array"
        if op == "=="
          return "sp_IntArray_eq(" + lc + ", " + rc + ")"
        else
          return "(!sp_IntArray_eq(" + lc + ", " + rc + "))"
        end
      end
    end
    "(" + lc + " " + op + " " + rc + ")"
  end

  # Box an already-compiled value of static type `at` into an sp_RbVal.
  # Mirrors box_expr_to_poly but operates on a raw (type, value) pair so
  # callers that already have temps don't have to re-emit the expr.
  # Unbox an sp_RbVal expression `val` into the C representation
  # of `at`. Used at sites where the destructure / cls_id-aware
  # dispatch produced an sp_RbVal but the consumer slot is a
  # concrete C type (mrb_int, sp_IntArray *, const char *, ...).
  # No runtime cls_id check — caller has already narrowed via
  # static type / wrapping cls_id dispatch.
  def unbox_poly_to(at, val)
    base = is_nullable_type(at) == 1 ? base_type(at) : at
    if base == "int" || base == "bool" || base == "nil"
      return "(" + val + ").v.i"
    end
    if base == "float"
      return "(" + val + ").v.f"
    end
    if base == "string"
      return "(const char *)(" + val + ").v.p"
    end
    if base == "symbol"
      return "(sp_sym)(" + val + ").v.i"
    end
    if base == "int_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "float_array"
      return "(sp_FloatArray *)(" + val + ").v.p"
    end
    if base == "str_array"
      return "(sp_StrArray *)(" + val + ").v.p"
    end
    if base == "sym_array"
      return "(sp_IntArray *)(" + val + ").v.p"
    end
    if base == "poly_array"
      return "(sp_PolyArray *)(" + val + ").v.p"
    end
    if is_ptr_array_type(base) == 1
      return "(sp_PtrArray *)(" + val + ").v.p"
    end
    if is_obj_type(base) == 1
      cname = base[4, base.length - 4]
      return "(sp_" + cname + " *)(" + val + ").v.p"
    end
    # Fallback: cast generic pointer.
    "(void *)(" + val + ").v.p"
  end

  def box_value_to_poly(at, val)
    nullable = is_nullable_type(at)
    raw_at = at
    at = base_type(at)
    if nullable == 1 && is_nullable_pointer_type(raw_at) == 1
      if at == "string"
        return "sp_box_nullable_str(" + val + ")"
      end
      if at == "int_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_INT_ARRAY)"
      end
      if at == "float_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_FLT_ARRAY)"
      end
      if at == "str_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_STR_ARRAY)"
      end
      if at == "sym_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_SYM_ARRAY)"
      end
      if is_ptr_array_type(at) == 1
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PTR_ARRAY)"
      end
      if at == "poly_array"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_POLY_ARRAY)"
      end
      if at == "proc" || at == "lambda"
        return "sp_box_nullable_obj(" + val + ", SP_BUILTIN_PROC)"
      end
      if is_obj_type(at) == 1
        cname = at[4, at.length - 4]
        ci = find_class_idx(cname)
        return "sp_box_nullable_obj(" + val + ", " + ci.to_s + ")"
      end
      # Stamp hash cls_id so Hash#dig can recover the concrete type;
      # falling through to cls_id=0 would make dig collapse to nil.
      hcid = cls_id_for_hash_type(at)
      if hcid != ""
        return "sp_box_nullable_obj((void *)(" + val + "), " + hcid + ")"
      end
      if type_is_pointer(at) == 1
        return "sp_box_nullable_obj((void *)(" + val + "), 0)"
      end
    end
    box_non_nullable_value_to_poly(at, val)
  end

  def box_non_nullable_value_to_poly(at, val)
    if at == "poly"
      return val
    end
    if at == "int"
      return "sp_box_int(" + val + ")"
    end
    if at == "string"
      return "sp_box_str(" + val + ")"
    end
    if at == "float"
      return "sp_box_float(" + val + ")"
    end
    if at == "bool"
      return "sp_box_bool(" + val + ")"
    end
    if at == "nil"
      # `val` may be a side-effecting call (e.g. an arm in a
      # cls_id-dispatched table where the user-defined override
      # returns nil because its body is a `puts` / similar). Drop
      # the value but keep the side effect via the comma operator;
      # otherwise the generated dispatch silently elides the call
      # for any subclass whose method's static return type is nil.
      return "((void)(" + val + "), sp_box_nil())"
    end
    if at == "symbol"
      return "sp_box_sym(" + val + ")"
    end
    if at == "int_array"
      return "sp_box_int_array(" + val + ")"
    end
    if at == "float_array"
      return "sp_box_float_array(" + val + ")"
    end
    if at == "str_array"
      return "sp_box_str_array(" + val + ")"
    end
    if at == "sym_array"
      return "sp_box_sym_array(" + val + ")"
    end
    if is_ptr_array_type(at) == 1
      return "sp_box_ptr_array(" + val + ")"
    end
    if at == "poly_array"
      return "sp_box_poly_array(" + val + ")"
    end
    if at == "proc" || at == "lambda"
      return "sp_box_proc(" + val + ")"
    end
    if at == "range"
      # sp_Range is a 16-byte value type; sp_RbVal's union is 8.
      # sp_box_range copies the stack range onto the GC heap and
      # boxes the pointer via SP_BUILTIN_RANGE.
      return "sp_box_range(" + val + ")"
    end
    if at == "time"
      # Same shape as range: sp_Time is wider than sp_RbVal's union,
      # heap-copy via sp_box_time and box through SP_BUILTIN_TIME.
      return "sp_box_time(" + val + ")"
    end
    if is_obj_type(at) == 1
      cname = at[4, at.length - 4]
      ci = find_class_idx(cname)
      return "sp_box_obj(" + val + ", " + ci.to_s + ")"
    end
    hcid = cls_id_for_hash_type(at)
    if hcid != ""
      return "sp_box_obj((void *)(" + val + "), " + hcid + ")"
    end
    # Other pointer types (mutable strings, etc.) — box with a
    # neutral cls_id of 0 rather than truncating the pointer to int.
    if type_is_pointer(at) == 1
      return "sp_box_obj((void *)(" + val + "), 0)"
    end
    "sp_box_int(" + val + ")"
  end

  def box_expr_to_poly(nid)
    # Ternary / if-as-expression whose branches may have different
    # concrete types: per-branch box unconditionally. Same-type
    # branches yield a redundant box that still produces correct
    # sp_RbVal; mixed-type branches need the per-branch box to
    # avoid C's pointer/integer ternary-type-mismatch (which would
    # otherwise land as an unsafe cast in the poly slot and
    # segfault). Gating on infer_type's "poly" answer would miss
    # mixed-type cases — unify_return_type treats int as
    # default/unresolved (`int + T → T`), so a genuinely
    # int-string ternary infers as "string" and a poly gate would
    # fall through to the same UB-prone wholesale `sp_box_str`.
    if nid >= 0 && @nd_type[nid] == "IfNode"
      # When the predicate is a statically-decidable is_a? /
      # kind_of? on an already-typed expression, emit only the
      # live arm. The dead arm may contain a recursion call whose
      # argument types don't match the function's signature (e.g.
      # `v.is_a?(Hash) ? recurse(v) : v` where v is statically a
      # string) — generating it would land as a C type error even
      # though the branch is unreachable at runtime.
      sv = static_is_a_value(@nd_predicate[nid])
      if sv == "TRUE"
        body = @nd_body[nid]
        if body >= 0
          ts = get_stmts(body)
          if ts.length > 0
            return box_expr_to_poly(ts.last)
          end
        end
        return "sp_box_nil()"
      end
      if sv == "FALSE"
        sub = @nd_subsequent[nid]
        if sub >= 0
          if @nd_type[sub] == "ElseNode"
            eb = @nd_body[sub]
            if eb >= 0
              es = get_stmts(eb)
              if es.length > 0
                return box_expr_to_poly(es.last)
              end
            end
          else
            return box_expr_to_poly(sub)
          end
        end
        return "sp_box_nil()"
      end
      cond = compile_cond_expr(@nd_predicate[nid])
      then_v = "sp_box_nil()"
      body = @nd_body[nid]
      if body >= 0
        ts = get_stmts(body)
        if ts.length > 0
          then_v = box_expr_to_poly(ts.last)
        end
      end
      else_v = "sp_box_nil()"
      sub = @nd_subsequent[nid]
      if sub >= 0
        if @nd_type[sub] == "ElseNode"
          eb = @nd_body[sub]
          if eb >= 0
            es = get_stmts(eb)
            if es.length > 0
              else_v = box_expr_to_poly(es.last)
            end
          end
        else
          else_v = box_expr_to_poly(sub)
        end
      end
      return "(" + cond + " ? " + then_v + " : " + else_v + ")"
    end
    # Pass the nullable type through; box_value_to_poly's nullable
    # wrapper picks the right `sp_box_nullable_*` variant before
    # falling back to base-type dispatch.
    at = infer_type(nid)
    val = compile_expr(nid)
    box_value_to_poly(at, val)
  end

  def box_val_to_poly(val, at)
    box_value_to_poly(at, val)
  end

  # Emit a chained `@a = @b = ... = expr` write as one rhs evaluation
  # plus N per-slot stores. Caller has verified that `nid` is an
  # InstanceVariableWriteNode whose expression is itself an
  # InstanceVariableWriteNode. Each slot is typed independently (some
  # widened to poly by scan_writer_calls, others kept native), so the
  # store boxes through sp_RbVal only for the poly slots.
  def compile_chained_ivar_writes(nid)
    # Collect the chain of ivar names (head -> tail) and the bottom
    # rhs node id.
    ivars = []
    cur = nid
    while @nd_type[cur] == "InstanceVariableWriteNode"
      ivars.push(@nd_name[cur])
      cur = @nd_expression[cur]
    end
    rhs_id = cur
    rhs_type = infer_type(rhs_id)
    # NilNode rhs has no side effect and `compile_expr(NilNode)` is the
    # null-pointer-constant `0`, which assigns cleanly to any slot
    # type. Routing it through a typed temp would force a `mrb_int 0`
    # variable into pointer slots, which C won't implicitly null. Emit
    # one store per slot through the unchained IVW path; each slot
    # picks its own boxing rule (poly slots box to sp_box_nil()).
    if @nd_type[rhs_id] == "NilNode"
      ki = 0
      while ki < ivars.length
        cur_iv = nid
        kj = 0
        while kj < ki
          cur_iv = @nd_expression[cur_iv]
          kj = kj + 1
        end
        saved_expr = @nd_expression[cur_iv]
        @nd_expression[cur_iv] = rhs_id
        compile_stmt(cur_iv)
        @nd_expression[cur_iv] = saved_expr
        ki = ki + 1
      end
      return
    end
    # Empty `{}` / `[]` literal RHS — `compile_expr` returns the
    # default `sp_StrIntHash_new()` / `sp_IntArray_new()`, but
    # slots may have been promoted to a typed container by their
    # subsequent writes (e.g. `@h["k"] = "v"` lifts the slot to
    # str_str_hash). If every chain participant agrees on the
    # same promoted concrete container type, emit the slot-typed
    # constructor as the temp so each store is type-correct AND
    # the Ruby semantic of one shared object is preserved across
    # the chain. Disagreeing-type chains fall through to the
    # general case below; the resulting C will still warn about
    # pointer
    # type mismatch but at least one slot will be correct.
    if is_empty_hash_literal(rhs_id) == 1 || is_empty_array_literal(rhs_id) == 1
      consensus_t = ""
      consensus_ok = 1
      pi = 0
      while pi < ivars.length
        pt = ""
        if @current_class_idx >= 0
          pt = cls_ivar_type(@current_class_idx, ivars[pi])
        end
        if pi == 0
          consensus_t = pt
        elsif pt != consensus_t
          consensus_ok = 0
        end
        pi = pi + 1
      end
      if consensus_ok == 1 && consensus_t != "" && consensus_t != "str_int_hash" && consensus_t != "int_array" && consensus_t != "poly"
        ctor236 = ""
        if is_empty_hash_literal(rhs_id) == 1
          if consensus_t == "str_str_hash"
            @needs_str_str_hash = 1
            ctor236 = "sp_StrStrHash_new()"
          elsif consensus_t == "int_str_hash"
            @needs_int_str_hash = 1
            ctor236 = "sp_IntStrHash_new()"
          elsif consensus_t == "sym_int_hash"
            @needs_sym_int_hash = 1
            ctor236 = "sp_SymIntHash_new()"
          elsif consensus_t == "sym_str_hash"
            @needs_sym_str_hash = 1
            ctor236 = "sp_SymStrHash_new()"
          elsif consensus_t == "str_poly_hash"
            ctor236 = "sp_StrPolyHash_new()"
          elsif consensus_t == "sym_poly_hash"
            ctor236 = "sp_SymPolyHash_new()"
          elsif consensus_t == "poly_poly_hash"
            @needs_poly_poly_hash = 1
            @needs_rb_value = 1
            ctor236 = "sp_PolyPolyHash_new()"
          end
        else
          ctor236 = empty_array_new_for_type(consensus_t)
        end
        if ctor236 != ""
          @needs_gc = 1
          tmp236 = new_temp
          emit("  " + c_type(consensus_t) + " " + tmp236 + " = " + ctor236 + ";")
          ki236 = 0
          while ki236 < ivars.length
            emit("  " + self_arrow + sanitize_ivar(ivars[ki236]) + " = " + tmp236 + ";")
            ki236 = ki236 + 1
          end
          return
        end
      end
    end
    # General case: evaluate the rhs once into a typed temp, then
    # store into each slot. Side-effecting rhs (CallNode etc.) must
    # not be replicated.
    rhs_expr = compile_expr(rhs_id)
    tmp = new_temp
    emit("  " + c_type(rhs_type) + " " + tmp + " = " + rhs_expr + ";")
    ki = 0
    while ki < ivars.length
      iname_i = ivars[ki]
      ivt_i = ""
      if @current_class_idx >= 0
        ivt_i = cls_ivar_type(@current_class_idx, iname_i)
      end
      val_i = tmp
      if ivt_i == "poly" && rhs_type != "poly"
        val_i = box_value_to_poly(rhs_type, tmp)
      end
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname_i[1, iname_i.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + val_i + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        emit("  " + self_arrow + sanitize_ivar(iname_i) + " = " + val_i + ";")
      end
      ki = ki + 1
    end
  end

  # Emit a runtime loop that pushes every element of the array `src_expr`
  # (a node id whose value is some typed array) onto the destination
  # int_array variable `dst`. Used when expanding `*args` into a rest
  # parameter that will be received as sp_IntArray *.
  def emit_splat_into_int_array(dst, src_expr)
    src_t = infer_type(src_expr)
    src_v = compile_expr(src_expr)
    @needs_int_array = 1
    @needs_gc = 1
    if src_t == "int_array" || src_t == "sym_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_IntArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_IntArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "str_array"
      @needs_str_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_StrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_StrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "float_array"
      @needs_float_array = 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_FloatArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)sp_FloatArray_get(" + src_v + ", " + i + "));")
      return
    end
    if is_ptr_array_type(src_t) == 1
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PtrArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", (mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + i + "));")
      return
    end
    if src_t == "poly_array"
      i = new_temp
      emit("  for (mrb_int " + i + " = 0; " + i + " < sp_PolyArray_length(" + src_v + "); " + i + "++) sp_IntArray_push(" + dst + ", sp_PolyArray_get(" + src_v + ", " + i + ").v.i);")
      return
    end
    # Fallback: treat the single value as one element.
    emit("  sp_IntArray_push(" + dst + ", (mrb_int)" + src_v + ");")
  end

  # Read an element of a typed array as an mrb_int (so it fits int param
  # slots and the int_array rest bundle uniformly).
  def array_get_as_int_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "(mrb_int)sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "(mrb_int)sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "(mrb_int)(intptr_t)sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "poly_array"
      # Pull the int channel out of the tagged union. Lossy for non-int
      # tags — Spinel's *rest can only hold mrb_int today, so any non-int
      # element splatted into a rest param prints as raw bits.
      return "sp_PolyArray_get(" + src_v + ", " + idx_expr + ").v.i"
    end
    "0"
  end

  # Same as array_get_as_int_expr but returns the element in its native
  # C type (used when the param slot is typed, e.g. const char *).
  def array_get_native_expr(src_t, src_v, idx_expr)
    if src_t == "int_array" || src_t == "sym_array"
      return "sp_IntArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "str_array"
      return "sp_StrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if src_t == "float_array"
      return "sp_FloatArray_get(" + src_v + ", " + idx_expr + ")"
    end
    if is_ptr_array_type(src_t) == 1
      return "sp_PtrArray_get(" + src_v + ", " + idx_expr + ")"
    end
    "0"
  end

  # Splat-aware companion to compile_call_args_with_defaults. Handles a
  # single SplatNode in positional args. The conceptual positional list
  # is (prefix... ++ splat_array ++ suffix...); fixed params eat from the
  # left; the rest param (if any) gets the remainder.
  def compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    splat_node = positional_ids[splat_idx]
    splat_src_id = @nd_expression[splat_node]
    prefix_count = splat_idx
    suffix_count = positional_ids.length - splat_idx - 1

    # Pre-evaluate the splat source so we can index it twice (length and
    # element access) without re-evaluating side effects.
    src_t = "int_array"
    src_v = "0"
    if splat_src_id >= 0
      src_t = infer_type(splat_src_id)
      @needs_gc = 1
      src_tmp = new_temp
      emit("  " + c_type(src_t) + " " + src_tmp + " = " + compile_expr(splat_src_id) + ";")
      if type_is_pointer(src_t) == 1
        emit("  SP_GC_ROOT(" + src_tmp + ");")
      end
      src_v = src_tmp
    end
    src_len_expr = length_c_expr(src_t, src_v)
    if src_len_expr == ""
      src_len_expr = "0"
    end

    # Identify if the last emitted param is the explicit rest slot.
    method_has_rest = 0
    if rest_param_idx >= 0 && rest_param_idx == pnames.length - 1
      method_has_rest = 1
    end
    n_fixed = pnames.length
    if method_has_rest == 1
      n_fixed = pnames.length - 1
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end

      # Keyword args take priority (matches non-splat path).
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
          if k < ptypes.length && ptypes[k] == "poly"
            # Pick the box helper from the arg's actual source
            # type via box_expr_to_poly. A hardcoded sp_box_str
            # would mistype any non-string source (e.g. an
            # `obj_<C>` instance) as SP_TAG_STR — invalid C and a
            # value that disagrees with sp_RbVal's tag/cls_id
            # contract at runtime.
            result = result + box_expr_to_poly(kw_arg_ids[ki])
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 1
        k = k + 1
        next
      end

      # Rest param: bundle leftover splat elements + suffix positionals.
      if k == pnames.length - 1 && method_has_rest == 1
        @needs_int_array = 1
        @needs_gc = 1
        rest_tmp = new_temp
        emit("  sp_IntArray *" + rest_tmp + " = sp_IntArray_new();")
        # Prefix positionals beyond n_fixed overflow into the rest before
        # any splat content (e.g. take(1, 2, *xs) where take has only a
        # *rest param: the literals 1 and 2 must lead the bundle).
        po_start = n_fixed
        if po_start < 0
          po_start = 0
        end
        if po_start < prefix_count
          poi = po_start
          while poi < prefix_count
            emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(positional_ids[poi]) + ");")
            poi = poi + 1
          end
        end
        consumed = n_fixed - prefix_count
        if consumed < 0
          consumed = 0
        end
        i_loop = new_temp
        emit("  for (mrb_int " + i_loop + " = " + consumed.to_s + "; " + i_loop + " < " + src_len_expr + "; " + i_loop + "++) sp_IntArray_push(" + rest_tmp + ", " + array_get_as_int_expr(src_t, src_v, i_loop) + ");")
        si = 0
        while si < suffix_count
          pid = positional_ids[splat_idx + 1 + si]
          emit("  sp_IntArray_push(" + rest_tmp + ", (mrb_int)" + compile_expr(pid) + ");")
          si = si + 1
        end
        result = result + rest_tmp
        k = k + 1
        next
      end

      # Fixed param. Determine which conceptual positional it consumes.
      pt = "int"
      if k < ptypes.length
        pt = ptypes[k]
      end
      if k < prefix_count
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[k])
        else
          result = result + compile_expr(positional_ids[k])
        end
        k = k + 1
        next
      end
      # Index into the splat source.
      idx_in_splat = k - prefix_count
      # Unconsumed splat elements available for fixed params:
      #   src_len - (positional slots after the splat that need to come
      #              from the splat to feed remaining fixed params)
      # We don't know src_len statically, so we trust the caller has
      # provided enough — a runtime over-read returns 0/NULL via the
      # array's bounds clamp.
      slots_left_for_splat = n_fixed - prefix_count
      if idx_in_splat < slots_left_for_splat
        ge = array_get_native_expr(src_t, src_v, idx_in_splat.to_s)
        if pt == "poly"
          # The splat element itself isn't a node id, so wrap manually.
          result = result + ge
        else
          result = result + ge
        end
        k = k + 1
        next
      end
      # Comes from a suffix positional (after the splat).
      suffix_offset = idx_in_splat - slots_left_for_splat
      pid_idx = splat_idx + 1 + suffix_offset
      if pid_idx < positional_ids.length
        if pt == "poly"
          result = result + box_expr_to_poly(positional_ids[pid_idx])
        else
          result = result + compile_expr(positional_ids[pid_idx])
        end
      else
        # Fall back to default if defined.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            if k < ptypes.length
              result = result + compile_expr_for_expected_type(def_id, ptypes[k])
            else
              result = result + compile_expr(def_id)
            end
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_call_args_with_defaults(nid, mi, omit_trailing = 0)
    # `omit_trailing` is the number of trailing param slots to leave out
    # entirely — block-forwarding call sites pass 1 so the &block slot
    # isn't default-padded with "0" (the actual proc is appended by the
    # caller after this returns).
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    pnames = @meth_param_names[mi].split(",")
    ptypes = @meth_param_types[mi].split(",")
    defaults = @meth_has_defaults[mi].split(",")
    rest_param_idx = method_rest_index(mi)
    if omit_trailing > 0
      kept = "".split(",")
      pk = 0
      limit = pnames.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(pnames[pk])
        pk = pk + 1
      end
      pnames = kept
    end
    if rest_param_idx >= pnames.length
      rest_param_idx = -1
    end

    # Check if args contain a KeywordHashNode - extract kw pairs.
    # Track kw_arg_ids parallel to kw_vals so the poly-boxing branch
    # below (Issue #314) can pick the right box helper from the arg's
    # actual source type via box_expr_to_poly, rather than hardcoding
    # sp_box_str.
    kw_names = "".split(",")
    kw_vals = "".split(",")
    kw_arg_ids = []
    positional_ids = []
    splat_idx = -1
    splat_count_local = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_vals.push(compile_expr(@nd_expression[elems[ek]]))
              kw_arg_ids.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      else
        if @nd_type[arg_ids[ak]] == "SplatNode"
          if splat_idx < 0
            splat_idx = positional_ids.length
          end
          splat_count_local = splat_count_local + 1
        end
        positional_ids.push(arg_ids[ak])
      end
      ak = ak + 1
    end

    if splat_count_local == 1
      return compile_call_args_splat(nid, mi, pnames, ptypes, defaults, kw_names, kw_vals, kw_arg_ids, positional_ids, splat_idx, rest_param_idx)
    end

    result = ""
    k = 0
    while k < pnames.length
      if k > 0
        result = result + ", "
      end
      # Check keyword args first
      kw_found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[k]
          kw_found = 1
          # Check if param is poly
          if k < ptypes.length
            if ptypes[k] == "poly"
              # Pick the box helper from the arg's actual source
              # type via box_expr_to_poly. A hardcoded sp_box_str
              # would mistype any non-string source — and a
              # kwargs call site with a poly-widened param
              # (e.g. `model:` after call-site widening folds
              # Article + Comment into poly) is exactly the path
              # that flows non-string objs through here.
              result = result + box_expr_to_poly(kw_arg_ids[ki])
            else
              result = result + kw_vals[ki]
            end
          else
            result = result + kw_vals[ki]
          end
        end
        ki = ki + 1
      end
      if kw_found == 0
        if k < ptypes.length
          if ptypes[k] == "int_array" && k == rest_param_idx
            # Rest parameter (splat). Trigger when caller passes more
            # positional args than the method has params, OR when any
            # positional arg is itself a SplatNode that we have to expand.
            has_splat_arg = 0
            si = k
            while si < positional_ids.length
              if @nd_type[positional_ids[si]] == "SplatNode"
                has_splat_arg = 1
              end
              si = si + 1
            end
            # Treat the last param as a rest target when it's the trailing
            # int_array slot. This covers three cases:
            #   - extra positional args spilling in (the original heuristic)
            #   - a SplatNode somewhere in the args
            #   - no args supplied at all (rest-only method called bare)
            is_last_param = 0
            if k == pnames.length - 1
              is_last_param = 1
            end
            treat_as_rest = 0
            if positional_ids.length > pnames.length || has_splat_arg == 1
              treat_as_rest = 1
            end
            if is_last_param == 1 && positional_ids.length <= k
              treat_as_rest = 1
            end
            if treat_as_rest == 1
              # Fast path: the only positional is a splat whose source is
              # already an int_array. Pass it directly without copying.
              if has_splat_arg == 1 && positional_ids.length == k + 1 && @nd_type[positional_ids[k]] == "SplatNode"
                src_expr = @nd_expression[positional_ids[k]]
                if src_expr >= 0
                  src_t = infer_type(src_expr)
                  if src_t == "int_array" || src_t == "sym_array"
                    result = result + compile_expr(src_expr)
                    k = k + 1
                    next
                  end
                end
              end
              @needs_int_array = 1
              @needs_gc = 1
              tmp = new_temp
              emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
              pi = k
              while pi < positional_ids.length
                if @nd_type[positional_ids[pi]] == "SplatNode"
                  src_expr2 = @nd_expression[positional_ids[pi]]
                  if src_expr2 >= 0
                    emit_splat_into_int_array(tmp, src_expr2)
                  end
                else
                  emit("  sp_IntArray_push(" + tmp + ", (mrb_int)" + compile_expr(positional_ids[pi]) + ");")
                end
                pi = pi + 1
              end
              result = result + tmp
              k = k + 1
              next
            end
          end
        end
        if k < positional_ids.length
          if k < ptypes.length
            if ptypes[k] == "poly"
              result = result + box_expr_to_poly(positional_ids[k])
              k = k + 1
              next
            end
            # An empty `[]` literal at the call site needs to
            # construct the right typed-array container. The
            # literal's own infer_type returns int_array
            # (compile_array_literal emits sp_IntArray_new()), but
            # when the param is a concrete typed-array, emit the
            # matching constructor instead.
            if is_empty_array_literal(positional_ids[k]) == 1
              if ptypes[k] == "str_array"
                @needs_str_array = 1
                @needs_gc = 1
                result = result + "sp_StrArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "float_array"
                @needs_float_array = 1
                @needs_gc = 1
                result = result + "sp_FloatArray_new()"
                k = k + 1
                next
              end
              if ptypes[k] == "sym_array"
                @needs_int_array = 1
                @needs_gc = 1
                result = result + "sp_IntArray_new()"
                k = k + 1
                next
              end
            end
            # When the param expects `sp_<C> *` but the arg's static
            # type is `int` (typically a local catching a method
            # whose return widened to mrb_int because the union
            # collapsed somewhere upstream — e.g.
            # `parent = article` after a `nil.return` narrows
            # parent's declared type but the call site below still
            # passes `lv_parent` raw), insert the same cast that
            # compile_int_class_fallback_expr already inserts at
            # property-access sites. Without this, gcc errors
            # `incompatible integer to pointer conversion`.
            if is_obj_type(ptypes[k]) == 1
              arg_at = infer_type(positional_ids[k])
              if arg_at == "int"
                bt_arg = base_type(ptypes[k])
                arg_cname = bt_arg[4, bt_arg.length - 4]
                result = result + "(sp_" + arg_cname + " *)" + compile_expr(positional_ids[k])
                k = k + 1
                next
              end
            end
          end
          result = result + compile_expr(positional_ids[k])
        else
          # Use default value
          if k < defaults.length
            def_id = defaults[k].to_i
            if def_id >= 0
              result = result + compile_expr(def_id)
            else
              result = result + "0"
            end
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_constructor_args(ci, nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      # No call-site args. If init has parameters with defaults, fill them
      # in here (issue #49: `Counter.new` for `initialize(start = 0)`).
      init_ci = find_init_class(ci)
      if init_ci >= 0
        init_idx = cls_find_method_direct(init_ci, "initialize")
        if init_idx >= 0
          return compile_typed_call_args(nid, init_ci, init_idx, 0, 1)
        end
      end
      return ""
    end
    arg_ids = get_args(args_id)
    # Check if any arg is a KeywordHashNode
    has_kw = 0
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        has_kw = 1
      end
      ak = ak + 1
    end
    if has_kw == 0
      # Positional args: compile against the inferred initializer
      # signature so defaults are filled and poly params are boxed.
      init_ci_p = find_init_class(ci)
      if init_ci_p >= 0
        init_idx_p = cls_find_method_direct(init_ci_p, "initialize")
        if init_idx_p >= 0
          return compile_typed_call_args(nid, init_ci_p, init_idx_p, 0, 1)
        end
      end
      return compile_call_args(nid)
    end
    # Extract keyword pairs — remember the expression nid too so we can
    # box it (sp_box_int etc.) when the matching ctor param is poly.
    kw_names = "".split(",")
    kw_exprs = []
    ak = 0
    while ak < arg_ids.length
      if @nd_type[arg_ids[ak]] == "KeywordHashNode"
        elems = parse_id_list(@nd_elements[arg_ids[ak]])
        ek = 0
        while ek < elems.length
          if @nd_type[elems[ek]] == "AssocNode"
            key_id = @nd_key[elems[ek]]
            if key_id >= 0
              kname = ""
              if @nd_type[key_id] == "SymbolNode"
                kname = @nd_content[key_id]
              end
              kw_names.push(kname)
              kw_exprs.push(@nd_expression[elems[ek]])
            end
          end
          ek = ek + 1
        end
      end
      ak = ak + 1
    end
    # Get init param names/types from class
    init_ci = find_init_class(ci)
    if init_ci < 0
      return compile_call_args(nid)
    end
    init_idx = cls_find_method_direct(init_ci, "initialize")
    if init_idx < 0
      return compile_call_args(nid)
    end
    pnames = cls_meth_pnames_get(init_ci, init_idx)
    ptypes = cls_meth_ptypes_get(init_ci, init_idx)
    # Build args in param order using keyword values
    result = ""
    pk = 0
    while pk < pnames.length
      if pk > 0
        result = result + ", "
      end
      pt = "int"
      if pk < ptypes.length
        pt = ptypes[pk]
      end
      found = 0
      ki = 0
      while ki < kw_names.length
        if kw_names[ki] == pnames[pk]
          expr_id = kw_exprs[ki]
          if pt == "poly"
            result = result + box_expr_to_poly(expr_id)
          else
            result = result + compile_expr(expr_id)
          end
          found = 1
        end
        ki = ki + 1
      end
      if found == 0
        if pt == "poly"
          result = result + "sp_box_nil()"
        else
          result = result + "0"
        end
      end
      pk = pk + 1
    end
    result
  end

  def compile_call_args(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return ""
    end
    arg_ids = get_args(args_id)
    # Check if multiple args may trigger GC
    gc_count = 0
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        gc_count = gc_count + 1
      end
      k = k + 1
    end
    if gc_count >= 2
      return compile_gc_safe_args(arg_ids)
    end
    result = ""
    k = 0
    while k < arg_ids.length
      if k > 0
        result = result + ", "
      end
      result = result + compile_expr(arg_ids[k])
      k = k + 1
    end
    result
  end

  def compile_gc_safe_args(arg_ids)
    temps = "".split(",")
    k = 0
    while k < arg_ids.length
      if expr_may_gc(arg_ids[k]) == 1
        tmp = new_temp
        at = infer_type(arg_ids[k])
        ct = c_type(at)
        emit("  " + ct + " " + tmp + " = " + compile_expr(arg_ids[k]) + ";")
        if type_is_pointer(at) == 1
          emit("  SP_GC_ROOT(" + tmp + ");")
        end
        temps.push(tmp)
      else
        temps.push(compile_expr(arg_ids[k]))
      end
      k = k + 1
    end
    result = ""
    k = 0
    while k < temps.length
      if k > 0
        result = result + ", "
      end
      result = result + temps[k]
      k = k + 1
    end
    result
  end

  def constructor_arg_needs_root(arg_type)
    bt = base_type(arg_type)
    if is_obj_type(bt) == 1
      return 1
    end
    if is_array_type(bt) == 1 || is_ptr_array_type(bt) == 1 || is_tuple_type(bt) == 1
      return 1
    end
    if bt == "fiber" || bt == "bigint" || bt == "lambda" || bt == "poly_array"
      return 1
    end
    0
  end

  def root_constructor_arg_if_needed(expr_id, expr, arg_type, later_arg_may_gc)
    if constructor_arg_needs_root(arg_type) == 0
      return expr
    end
    may_gc = 0
    if expr_id >= 0
      may_gc = expr_may_gc(expr_id)
    end
    if may_gc == 0 && later_arg_may_gc == 0
      return expr
    end
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(arg_type) + " " + tmp + " = " + expr + ";")
    emit("  SP_GC_ROOT(" + tmp + ");")
    tmp
  end

  def compile_typed_call_args(nid, target_ci, target_midx, omit_trailing, root_constructor_args = 0)
    # Like compile_call_args but casts arguments to match target method param
    # types AND fills in defaults from @cls_meth_defaults for trailing
    # parameters the caller omitted (issue #49). Returns "" only when the
    # method takes no parameters at all.
    #
    # `omit_trailing` is the number of trailing param slots to leave out
    # entirely — block-forwarding call sites pass 1 so the &block slot
    # isn't default-padded with "0" (the actual proc is appended by the
    # caller after this returns).
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    all_defaults = @cls_meth_defaults[target_ci].split("|")
    ptypes = cls_meth_ptypes_get(target_ci, target_midx)
    defaults = "".split(",")
    if target_midx < all_defaults.length
      defaults = all_defaults[target_midx].split(",")
    end
    # Drop the trailing slots the caller will fill explicitly (the
    # &block slot when block-forwarding) — otherwise a surplus
    # positional arg would mis-cast against the omitted slot's type
    # and the loop's default-padding would emit "0" for the slot the
    # caller is about to fill itself.
    if omit_trailing > 0
      kept = []
      pk = 0
      limit = ptypes.length - omit_trailing
      if limit < 0
        limit = 0
      end
      while pk < limit
        kept.push(ptypes[pk])
        pk = pk + 1
      end
      ptypes = kept
    end
    total = ptypes.length
    if arg_ids.length > total
      total = arg_ids.length
    end
    if total == 0
      return ""
    end
    later_arg_may_gc = []
    if root_constructor_args == 1
      gc_expr_ids = []
      gk = 0
      while gk < total
        gc_expr_id = -1
        if gk < arg_ids.length
          gc_expr_id = arg_ids[gk]
        else
          if gk < defaults.length
            gc_expr_id = defaults[gk].to_i
          end
        end
        gc_expr_ids.push(gc_expr_id)
        gk = gk + 1
      end
      seen_gc = 0
      gk = total - 1
      while gk >= 0
        later_arg_may_gc[gk] = seen_gc
        gc_expr_id = gc_expr_ids[gk]
        if gc_expr_id >= 0 && expr_may_gc(gc_expr_id) == 1
          seen_gc = 1
        end
        gk = gk - 1
      end
    end
    result = ""
    pcname = ""
    k = 0
    while k < total
      if k > 0
        result = result + ", "
      end
      if k < arg_ids.length
        at = infer_type(arg_ids[k])
        if k < ptypes.length
          pt = ptypes[k]
          pt_base = base_type(pt)
          if pt_base == "poly" || pt_base == "string" || is_array_type(pt_base) == 1 || (at == "poly" && is_obj_type(pt_base) == 1)
            aexpr = compile_expr_for_expected_type(arg_ids[k], pt)
            if root_constructor_args == 1
              aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
            end
            result = result + aexpr
            k = k + 1
            next
          end
          aexpr = compile_expr(arg_ids[k])
          if at == "int"
            if is_obj_type(pt) == 1
              # Cast int to object pointer. Strip the nullable `?`
              # marker before deriving the C class name — a param
              # type like `obj_BoundMethod?` would otherwise produce
              # `(sp_BoundMethod? *)0` and gcc chokes on the stray `?`.
              pt_base = pt
              if is_nullable_type(pt) == 1
                pt_base = base_type(pt)
              end
              pcname = pt_base[4, pt_base.length - 4]
              aexpr = "(sp_" + pcname + " *)" + aexpr
            end
          end
          if is_obj_type(at) == 1
            if pt == "int"
              # Cast object pointer to int
              aexpr = "(mrb_int)" + aexpr
            end
          end
        else
          aexpr = compile_expr(arg_ids[k])
          pt = at
        end
        if root_constructor_args == 1
          aexpr = root_constructor_arg_if_needed(arg_ids[k], aexpr, pt, later_arg_may_gc[k])
        end
        result = result + aexpr
      else
        # Caller omitted this trailing arg — emit the method's
        # default expression. The default was authored in the
        # callee's class scope, so any `self` / `@ivar` references
        # need to resolve against the call's receiver, not the
        # caller's self. Switch @current_class_idx and override
        # `self_arrow` for the duration of the inline expansion.
        if k < defaults.length
          def_id = defaults[k].to_i
          if def_id >= 0
            recv_for_default = @nd_receiver[nid]
            saved_ci = @current_class_idx
            saved_override = @self_override
            if recv_for_default >= 0
              # Materialize the recv into a C expression. Wrap in
              # parens so any cast/operator chain stays self-
              # contained when consumed as `(<recv>)->iv_X` (via
              # `self_arrow`) or as the first arg of a same-class
              # method call (via `self_expr`).
              recv_c = compile_expr_gc_rooted(recv_for_default)
              # Cast the recv expression to the target class's
              # pointer type when the static type of the recv is not
              # already that pointer (e.g. an inherited @apu ivar
              # whose slot was inferred as mrb_int but the runtime
              # value is sp_Optcarrot_APU *). Without the cast, an
              # `@cpu` reference inside the default expression
              # lowers to `(<recv>)->iv_cpu` which gcc rejects when
              # `<recv>` is mrb_int.
              recv_t = infer_type(recv_for_default)
              target_obj_t = "obj_" + @cls_names[target_ci]
              if base_type(recv_t) != target_obj_t && @cls_is_value_type[target_ci] != 1
                recv_c = "(sp_" + @cls_names[target_ci] + " *)" + recv_c
              end
              @self_override = "(" + recv_c + ")"
              @current_class_idx = target_ci
            end
            if k < ptypes.length
              aexpr = compile_expr_for_expected_type(def_id, ptypes[k])
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, ptypes[k], later_arg_may_gc[k])
              end
              result = result + aexpr
            else
              aexpr = compile_expr(def_id)
              if root_constructor_args == 1
                aexpr = root_constructor_arg_if_needed(def_id, aexpr, infer_type(def_id), later_arg_may_gc[k])
              end
              result = result + aexpr
            end
            @current_class_idx = saved_ci
            @self_override = saved_override
          else
            if k < ptypes.length && ptypes[k] == "poly"
              result = result + "sp_box_nil()"
            else
              result = result + "0"
            end
          end
        else
          if k < ptypes.length && ptypes[k] == "poly"
            result = result + "sp_box_nil()"
          else
            result = result + "0"
          end
        end
      end
      k = k + 1
    end
    result
  end

  def find_method_owner(ci, mname)
    if ci < 0
      return ""
    end
    mnames = @cls_meth_names[ci].split(";")
    j = 0
    while j < mnames.length
      if mnames[j] == mname
        return @cls_names[ci]
      end
      j = j + 1
    end
    if @cls_parents[ci] != ""
      pi = find_class_idx(@cls_parents[ci])
      if pi >= 0
        return find_method_owner(pi, mname)
      end
    end
    ""
  end

  # `recv OP rhs` lowering for an obj-typed receiver. When the
  # receiver's class (or an ancestor) defines `op` as a user method,
  # returns the C expression `sp_<owner>_<op>(<recv_c>, <rhs_c>)`.
  # Returns "" when no dispatch applies (caller falls back to its
  # inline path, or to `warn_unresolved_call`).
  def obj_op_dispatch_expr(recv_t, recv_c, op, rhs_c)
    if is_obj_type(recv_t) == 0
      return ""
    end
    cname = recv_t[4, recv_t.length - 4]
    ci = find_class_idx(cname)
    if ci < 0
      return ""
    end
    owner = find_method_owner(ci, op)
    if owner == ""
      warn_unresolved_call(op, "obj_" + cname)
      return ""
    end
    cast = ""
    if owner != cname
      cast = "(sp_" + owner + " *)"
    end
    "sp_" + owner + "_" + sanitize_name(op) + "(" + cast + recv_c + ", " + rhs_c + ")"
  end

  def compile_if_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    unified_t = infer_type(nid)
    then_val = "0"
    then_t = "nil"
    body = @nd_body[nid]
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        then_t = infer_type(stmts.last)
        then_val = compile_expr(stmts.last)
      end
    end
    else_val = "0"
    else_t = "nil"
    sub = @nd_subsequent[nid]
    if sub >= 0
      if @nd_type[sub] == "ElseNode"
        eb = @nd_body[sub]
        if eb >= 0
          es = get_stmts(eb)
          if es.length > 0
            else_t = infer_type(es.last)
            else_val = compile_expr(es.last)
          end
        end
      else
        else_t = infer_type(sub)
        else_val = compile_if_expr(sub)
      end
    end
    # When the if-expression's unified type is `poly` but the
    # branches have concrete types, the raw C ternary
    # `(cond ? sp_IntArray * : sp_PtrArray *)` mixes pointer types
    # and the C compiler rejects the assignment to sp_RbVal.
    # Box each branch into sp_RbVal so the ternary's two arms
    # share a type. Keeps the static infer_type(IfNode) → poly
    # contract that downstream dispatch (e.g. .each on poly recv)
    # relies on.
    if unified_t == "poly"
      if then_t != "poly"
        then_val = box_value_to_poly(then_t, then_val)
      end
      if else_t != "poly"
        else_val = box_value_to_poly(else_t, else_val)
      end
    end
    "(" + cond + " ? " + then_val + " : " + else_val + ")"
  end

  def compile_unless_expr(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    then_val = "0"
    body = @nd_body[nid]
    if body >= 0
      stmts = get_stmts(body)
      if stmts.length > 0
        then_val = compile_expr(stmts.last)
      end
    end
    "(!" + cond + " ? " + then_val + " : 0)"
  end

  # Compile an `ArrayNode` literal as `sp_PolyArray *`, regardless
  # of the inferred elem type. Used by the nested-array path in
  # the poly_array branch so 3D-and-deeper arrays preserve cls_id
  # tags through every level (e.g. an inner `[1,2,3]` ends up
  # boxed via `sp_box_int_array` so the dispatch can still
  # `sp_IntArray_get` on it).
  def compile_array_literal_as_poly(nid)
    @needs_gc = 1
    @needs_rb_value = 1
    elems = parse_id_list(@nd_elements[nid])
    tmp = new_temp
    emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
      et = infer_type(eid)
      if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
        inner = compile_array_literal_as_poly(eid)
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + inner + "));")
      elsif is_ptr_array_type(et) == 1
        # Non-ArrayNode whose static type is a typed `<X>_ptr_array`
        # (e.g. `Array.new(N) { ... }` returning int_array_ptr_array).
        # Convert at runtime so each inner element keeps its real
        # cls_id (sp_box_int_array etc.) — `arr[i][j][k]` chains
        # correctly through the next-level dispatch.
        val = compile_expr(eid)
        inner_t = ptr_array_elem_type(et)
        conv = new_temp
        ii = new_temp
        emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
        emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
        inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
        emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
        emit("  }")
        emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
      else
        val = compile_expr(eid)
        emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
      end
      k = k + 1
    end
    tmp
  end

  def compile_array_literal(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_int_array = 1
      return "sp_IntArray_new()"
    end
    compile_array_literal_from_ids(elems, infer_array_elem_type(nid))
  end

  # Body of compile_array_literal, parameterised on the list of value
  # node ids and the resolved array element type. Lets a HashNode
  # whose keys are 0..N-1 (lowered to Array) reuse the same emission
  # paths by feeding in the AssocNode rhs ids without needing an
  # ArrayNode wrapper.
  def compile_array_literal_from_ids(elems, arr_type)
    @needs_gc = 1
    if is_tuple_type(arr_type) == 1
      name = tuple_c_name(arr_type)
      tmp = new_temp
      parts = tuple_elem_types_str(arr_type).split(",")
      emit("  " + name + " *" + tmp + " = (" + name + " *)sp_gc_alloc(sizeof(" + name + "), NULL, " + tuple_scan_name(arr_type) + ");")
      k = 0
      while k < elems.length && k < parts.length
        emit("  " + tmp + "->_" + k.to_s + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "str_array"
      @needs_str_array = 1
      tmp = new_temp
      emit("  sp_StrArray *" + tmp + " = sp_StrArray_new();")
      k = 0
      while k < elems.length
        emit("  sp_StrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if arr_type == "poly_array"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_PolyArray *" + tmp + " = sp_PolyArray_new();")
      k = 0
      while k < elems.length
        et = infer_type(elems[k])
        # 3D+ shape: when the element is itself a typed
        # `<X>_ptr_array` that came from a nested ArrayNode, the
        # default `compile_array_literal` for that element would
        # emit a typed sp_PtrArray and `sp_box_ptr_array` would
        # erase the elem type (cls_id PTR_ARRAY). Recompile the
        # nested literal as poly_array so the next-level dispatch
        # sees `cls_id == POLY_ARRAY` and recurses with each
        # innermost typed array still tagged correctly.
        if @nd_type[elems[k]] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
          val = compile_array_literal_as_poly(elems[k])
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + val + "));")
        elsif is_ptr_array_type(et) == 1
          # Same 3D+ erasure but the element is a non-ArrayNode
          # expression (e.g. `Array.new(N) { ... }` returning a
          # typed `<X>_ptr_array`). compile_array_literal_as_poly
          # only walks ArrayNodes — emit a runtime conversion that
          # iterates the typed PtrArray and tags each inner with
          # its real cls_id (sp_box_int_array etc.).
          val = compile_expr(elems[k])
          inner_t = ptr_array_elem_type(et)
          conv = new_temp
          ii = new_temp
          emit("  sp_PolyArray *" + conv + " = sp_PolyArray_new();")
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_PtrArray_length(" + val + "); " + ii + "++) {")
          inner_get = "(" + c_type(inner_t) + ")sp_PtrArray_get(" + val + ", " + ii + ")"
          emit("    sp_PolyArray_push(" + conv + ", " + box_value_to_poly(inner_t, inner_get) + ");")
          emit("  }")
          emit("  sp_PolyArray_push(" + tmp + ", sp_box_poly_array(" + conv + "));")
        else
          val = compile_expr(elems[k])
          emit("  sp_PolyArray_push(" + tmp + ", " + box_value_to_poly(et, val) + ");")
        end
        k = k + 1
      end
      return tmp
    end
    if arr_type == "float_array"
      @needs_float_array = 1
      tmp = new_temp
      emit("  sp_FloatArray *" + tmp + " = sp_FloatArray_new();")
      k = 0
      while k < elems.length
        emit("  sp_FloatArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    if is_ptr_array_type(arr_type) == 1
      tmp = new_temp
      emit("  sp_PtrArray *" + tmp + " = sp_PtrArray_new();")
      # Root the freshly-allocated PtrArray before compiling element
      # expressions. Each element is typically Klass.new(...), and that
      # call allocates → may trigger GC. Without this, GC sees `tmp` as
      # unreachable and frees it, leaving a dangling pointer that the
      # subsequent push (and the eventual ivar assignment) writes through.
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < elems.length
        emit("  sp_PtrArray_push(" + tmp + ", " + compile_expr(elems[k]) + ");")
        k = k + 1
      end
      return tmp
    end
    @needs_int_array = 1
    tmp = new_temp
    emit("  sp_IntArray *" + tmp + " = sp_IntArray_new();")
    k = 0
    while k < elems.length
      eid = elems[k]
      # SplatNode in an Array literal — `[*range]` or `[*arr]` —
      # expands the inner expression's elements into the array.
      # Without this branch, compile_expr lowered the splat to a
      # default value (e.g., the lower bound of a Range), so
      # `[*0..4096]` ended up as just `[0]`.
      if @nd_type[eid] == "SplatNode"
        inner = @nd_expression[eid]
        it = infer_type(inner)
        # Root tmp so a sp_IntArray_push grow inside the splat loop
        # can't sweep the half-built array. Hoist range / source
        # expressions to a temp so side effects (method calls in the
        # bound, chained recv) fire exactly once.
        emit("  SP_GC_ROOT(" + tmp + ");")
        if @nd_type[inner] == "RangeNode"
          lo = compile_expr(@nd_left[inner])
          hi_expr = compile_expr(@nd_right[inner])
          hi = new_temp
          emit("  mrb_int " + hi + " = " + hi_expr + ";")
          cmp = range_excl_end(inner) == 1 ? "<" : "<="
          ii = new_temp
          emit("  for (mrb_int " + ii + " = " + lo + "; " + ii + " " + cmp + " " + hi + "; " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", " + ii + ");")
          emit("  }")
        elsif it == "int_array" || it == "sym_array"
          src_expr = compile_expr(inner)
          src = new_temp
          emit("  sp_IntArray *" + src + " = " + src_expr + ";")
          emit("  SP_GC_ROOT(" + src + ");")
          ii = new_temp
          emit("  for (mrb_int " + ii + " = 0; " + ii + " < sp_IntArray_length(" + src + "); " + ii + "++) {")
          emit("    sp_IntArray_push(" + tmp + ", sp_IntArray_get(" + src + ", " + ii + "));")
          emit("  }")
        end
        k = k + 1
        next
      end
      ev = compile_expr(eid)
      et = infer_type(eid)
      # Unbox poly values when pushing into a (concrete) IntArray.
      # An ArrayNode literal whose elements are poly (e.g.
      # `[addr]` where addr's recorded type is sp_RbVal) needs the
      # int payload extracted via `.v.i`. Without this, the C
      # compiler rejects the push with "incompatible type".
      if et == "poly"
        ev = "(" + ev + ").v.i"
      end
      emit("  sp_IntArray_push(" + tmp + ", " + ev + ");")
      k = k + 1
    end
    tmp
  end

  # HashNode literal whose keys are 0..N-1 lowered to an Array
  # literal. Reuses compile_array_literal_from_ids by mapping each
  # AssocNode to its rhs value id.
  def compile_int_keyed_hash_as_array(nid)
    @needs_gc = 1
    elems = parse_id_list(@nd_elements[nid])
    vids = []
    k = 0
    while k < elems.length
      vids.push(@nd_expression[elems[k]])
      k = k + 1
    end
    compile_array_literal_from_ids(vids, infer_array_elem_type_from_ids(vids))
  end

  def compile_hash_literal(nid)
    @needs_gc = 1
    if is_int_array_lowered_hash(nid) == 1
      return compile_int_keyed_hash_as_array(nid)
    end
    elems = parse_id_list(@nd_elements[nid])
    if elems.length == 0
      @needs_str_int_hash = 1
      return "sp_StrIntHash_new()"
    end
    ht = infer_hash_val_type(nid)
    if ht == "int_str_hash"
      @needs_int_str_hash = 1
      tmp = new_temp
      emit("  sp_IntStrHash *" + tmp + " = sp_IntStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_IntStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_str_hash"
      @needs_str_str_hash = 1
      tmp = new_temp
      emit("  sp_StrStrHash *" + tmp + " = sp_StrStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          vt = infer_type(@nd_expression[el])
          val = compile_expr(@nd_expression[el])
          if vt == "int"
            val = "sp_int_to_s(" + val + ")"
          else
            if vt == "float"
              val = "sp_float_to_s(" + val + ")"
            else
              if vt == "bool"
                val = "(" + val + " ? \"true\" : \"false\")"
              end
            end
          end
          emit("  sp_StrStrHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + val + ");")
        end
      }
      return tmp
    end
    if ht == "sym_int_hash"
      @needs_sym_int_hash = 1
      tmp = new_temp
      emit("  sp_SymIntHash *" + tmp + " = sp_SymIntHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymIntHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "sym_str_hash"
      @needs_sym_str_hash = 1
      tmp = new_temp
      emit("  sp_SymStrHash *" + tmp + " = sp_SymStrHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymStrHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "sym_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_SymPolyHash *" + tmp + " = sp_SymPolyHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_SymPolyHash_set(" + tmp + ", " + compile_expr(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    if ht == "str_poly_hash"
      @needs_rb_value = 1
      tmp = new_temp
      emit("  sp_StrPolyHash *" + tmp + " = sp_StrPolyHash_new();")
      elems.each { |el|
        if @nd_type[el] == "AssocNode"
          emit("  sp_StrPolyHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + box_expr_to_poly(@nd_expression[el]) + ");")
        end
      }
      return tmp
    end
    @needs_str_int_hash = 1
    tmp = new_temp
    emit("  sp_StrIntHash *" + tmp + " = sp_StrIntHash_new();")
    elems.each { |el|
      if @nd_type[el] == "AssocNode"
        emit("  sp_StrIntHash_set(" + tmp + ", " + compile_expr_as_string(@nd_key[el]) + ", " + compile_expr(@nd_expression[el]) + ");")
      end
    }
    tmp
  end

  # ---- Statement compiler ----
  def compile_stmt(nid)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "UnsupportedNode"
      # Same loud-error path as compile_expr's UnsupportedNode arm.
      $stderr.puts "Spinel: cannot compile " + @nd_content[nid] + " at line " + @nd_value[nid].to_s + " (unsupported Ruby syntax)"
      exit(1)
    end
    if t == "MultiWriteNode"
      compile_multi_write(nid)
      return
    end
    if t == "GlobalVariableWriteNode"
      gname = @nd_name[nid]
      if gname != "$stderr" && gname != "$stdout" && gname != "$?"
        cname = sanitize_gvar(gname)
        val = compile_expr(@nd_expression[nid])
        emit("  " + cname + " = " + val + ";")
        return
      end
    end
    if t == "GlobalVariableOperatorWriteNode"
      # `$x += val`, `$x -= val`, etc. Mirrors LocalVariableOperatorWriteNode
      # for the storage path (sanitize_gvar instead of fiber_var_ref).
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      cname = sanitize_gvar(@nd_name[nid])
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      end
      if op == "-"
        emit("  " + cname + " -= " + val + ";")
      end
      if op == "*"
        emit("  " + cname + " *= " + val + ";")
      end
      if op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      end
      if op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      end
      if op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      end
      if op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      end
      if op == "&"
        emit("  " + cname + " &= " + val + ";")
      end
      if op == "|"
        emit("  " + cname + " |= " + val + ";")
      end
      if op == "^"
        emit("  " + cname + " ^= " + val + ";")
      end
      return
    end
    if t == "GlobalVariableOrWriteNode"
      # `$x ||= val`. Short-circuit: only evaluate RHS when LHS is
      # falsy. compile_expr can emit prerequisite statements; running
      # it inside the C `if` block ensures those side effects only
      # fire on the assign branch. Note: in Ruby, an undefined $-var
      # reads as nil, which is falsy in C terms, so the `if (!cname)`
      # guard fires both for never-assigned and assigned-to-falsy.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "GlobalVariableAndWriteNode"
      # `$x &&= val`. Short-circuit: only evaluate RHS when LHS is
      # truthy. compile_expr can emit prerequisite statements; running
      # it inside the C `if` block keeps those side effects on the
      # assign branch only. Mirror of OrWrite, condition inverted.
      cname = sanitize_gvar(@nd_name[nid])
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableWriteNode"
      # `@@x = val` inside class body or method. Storage is the
      # per-(class,name) C global cvar_<ClassName>_<var> registered
      # by collect_cvars during the pre-pass. If the cvar wasn't seen
      # there (e.g. inside a class-method that pre-pass missed) we
      # register defensively.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      emit("  cvar_" + qname + " = " + val + ";")
      return
    end
    if t == "ClassVariableOperatorWriteNode"
      # `@@x op= val` -- desugar to `@@x = @@x op val`. Mirrors
      # GlobalVariableOperatorWriteNode and the instance-var
      # variant. Same storage path as ClassVariableWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      op = @nd_binop[nid]
      if op == "+"
        emit("  " + cname + " += " + val + ";")
      elsif op == "-"
        emit("  " + cname + " -= " + val + ";")
      elsif op == "*"
        emit("  " + cname + " *= " + val + ";")
      elsif op == "/"
        emit("  " + cname + " = sp_idiv(" + cname + ", " + val + ");")
      elsif op == "%"
        emit("  " + cname + " = sp_imod(" + cname + ", " + val + ");")
      elsif op == "<<"
        emit("  " + cname + " <<= " + val + ";")
      elsif op == ">>"
        emit("  " + cname + " >>= " + val + ";")
      elsif op == "&"
        emit("  " + cname + " &= " + val + ";")
      elsif op == "|"
        emit("  " + cname + " |= " + val + ";")
      elsif op == "^"
        emit("  " + cname + " ^= " + val + ";")
      else
        emit("  " + cname + " = " + cname + " " + op + " " + val + ";")
      end
      return
    end
    if t == "ClassVariableOrWriteNode"
      # `@@x ||= val` -- evaluate rhs only when @@x is falsy.
      # Mirror of GlobalVariableOrWriteNode.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (!(" + cname + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "ClassVariableAndWriteNode"
      # `@@x &&= val` -- evaluate rhs only when @@x is truthy.
      qname = cvar_qname(@current_class_idx, @nd_name[nid])
      val_t = infer_type(@nd_expression[nid])
      register_cvar(qname, val_t)
      cname = "cvar_" + qname
      emit("  if (" + cname + ") {")
      val = compile_expr(@nd_expression[nid])
      emit("    " + cname + " = " + val + ";")
      emit("  }")
      return
    end
    if t == "RedoNode"
      # `redo` -- jump to the top of the current iteration without
      # advancing the iterator or re-evaluating the loop guard. The
      # loop emitter installs a label via push_redo_label /
      # emit_redo_label; we goto the innermost.
      if @redo_label_stack.length == 0
        $stderr.puts "Spinel: `redo` outside of a loop"
        exit(1)
      end
      lbl = @redo_label_stack.last
      emit("  goto " + lbl + ";")
      return
    end
    if t == "AliasGlobalVariableNode"
      # `alias $copy $orig` -- compile-time only. collect_all
      # already populated @galias_*; references through
      # sanitize_gvar / scan_features / infer_type pick up the
      # rewrite. Nothing to emit at runtime.
      return
    end
    if t == "AliasMethodNode"
      # `alias new old` -- compile-time only. The class-collect pass
      # already registered a duplicate method-table entry under the
      # new name pointing to the same body_id; subsequent dispatch
      # finds it like any other method.
      return
    end
    if t == "UndefNode"
      # `undef foo` -- compile-time only. The class-collect pass
      # already recorded the removal in @undef_*; nothing to emit.
      return
    end
    if t == "PreExecutionNode"
      # `BEGIN { ... }`. collect_all already pushed the body onto
      # @pre_execution_blocks; emit_main hoists it to the top of
      # main(). The toplevel statement itself is a no-op at its
      # source location.
      return
    end
    if t == "PostExecutionNode"
      # `END { ... }`. collect_all pushed the body onto
      # @post_execution_blocks; emit_post_execution_funcs emits the
      # static sp_end_block_<n> function and emit_main inserts an
      # atexit() call at startup.
      return
    end
    if t == "LocalVariableWriteNode"
      lname = @nd_name[nid]
      # `var = method(:name)` (no receiver, top-level) is the legacy
      # static-alias path: the call_expr handler returns a `0`
      # placeholder, we record (lname, mref) here, and a later
      # `m.call(x)` is rewritten in compile_dot_call_expr to a
      # direct `sp_<name>(x)` call. Inside a class body OR with a
      # receiver (`var = recv.method(:_)`), the call expr already
      # produced a real obj_Method instance — fall through to the
      # normal compile path so the typed local picks it up. Ref #215.
      expr_id = @nd_expression[nid]
      if expr_id >= 0
        if @nd_type[expr_id] == "CallNode"
          if @nd_name[expr_id] == "method" && @nd_receiver[expr_id] < 0 && @current_class_idx < 0
            args_id = @nd_arguments[expr_id]
            if args_id >= 0
              arg_ids = get_args(args_id)
              if arg_ids.length >= 1
                mref = @nd_content[arg_ids[0]]
                if mref == ""
                  mref = @nd_name[arg_ids[0]]
                end
                @method_ref_vars.push(lname)
                @method_ref_names.push(mref)
                emit("  /* " + lname + " = method(:" + mref + ") */")
                return
              end
            end
          end
        end
      end
      vref = fiber_var_ref(lname)
      vt = find_var_type(lname)
      # Empty array literal: create the correct array type. Returning
      # early here also preserves the scope's already-promoted type
      # (issue #58, #85) — the fall-through path below would clobber
      # vt with infer_type([])'s "int_array" via set_var_type.
      if vt == "str_array" || vt == "float_array" || vt == "sym_array" || vt == "poly_array" || is_ptr_array_type(vt) == 1
        expr_id = @nd_expression[nid]
        if expr_id >= 0 && @nd_type[expr_id] == "ArrayNode"
          elems = parse_id_list(@nd_elements[expr_id])
          if elems.length == 0
            if vt == "str_array"
              @needs_str_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_StrArray_new();")
            elsif vt == "float_array"
              @needs_float_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_FloatArray_new();")
            elsif vt == "sym_array"
              # sym_array shares sp_IntArray storage.
              @needs_int_array = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_IntArray_new();")
            elsif vt == "poly_array"
              @needs_rb_value = 1
              @needs_gc = 1
              emit("  " + vref + " = sp_PolyArray_new();")
            else
              @needs_gc = 1
              emit("  " + vref + " = sp_PtrArray_new();")
            end
            return
          end
        end
      end
      # Empty hash literal: create the correct hash type. The local's
      # type was promoted by scan_locals' empty-hash promotion (str_int_hash
      # default refined based on first []= site's key/value types).
      # Without these arms the literal `{}` would always emit
      # sp_StrIntHash_new() and the assignment would mismatch the
      # promoted local's struct type.
      if vt == "str_str_hash" || vt == "int_str_hash" || vt == "sym_int_hash" || vt == "sym_str_hash" || vt == "str_poly_hash" || vt == "sym_poly_hash" || vt == "poly_poly_hash"
        expr_id2 = @nd_expression[nid]
        if expr_id2 >= 0 && @nd_type[expr_id2] == "HashNode"
          elems2 = parse_id_list(@nd_elements[expr_id2])
          if elems2.length == 0
            @needs_gc = 1
            if vt == "str_str_hash"
              @needs_str_str_hash = 1
              emit("  " + vref + " = sp_StrStrHash_new();")
            elsif vt == "int_str_hash"
              @needs_int_str_hash = 1
              emit("  " + vref + " = sp_IntStrHash_new();")
            elsif vt == "sym_int_hash"
              @needs_sym_int_hash = 1
              emit("  " + vref + " = sp_SymIntHash_new();")
            elsif vt == "sym_str_hash"
              @needs_sym_str_hash = 1
              emit("  " + vref + " = sp_SymStrHash_new();")
            elsif vt == "str_poly_hash"
              @needs_str_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_StrPolyHash_new();")
            elsif vt == "sym_poly_hash"
              @needs_sym_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_SymPolyHash_new();")
            elsif vt == "poly_poly_hash"
              @needs_poly_poly_hash = 1
              @needs_rb_value = 1
              emit("  " + vref + " = sp_PolyPolyHash_new();")
            end
            return
          end
        end
      end
      if vt == "bigint"
        rhs_t = infer_type(@nd_expression[nid])
        val = compile_expr(@nd_expression[nid])
        if rhs_t == "bigint"
          emit("  " + vref + " = " + val + ";")
        else
          emit("  " + vref + " = sp_bigint_new_int(" + val + ");")
        end
        # Trigger GC after bigint statement (safe point - all results stored in vars)
        emit("  if(sp_gc_bytes>sp_gc_threshold){size_t _b=sp_gc_bytes;sp_gc_collect();size_t _f=_b-sp_gc_bytes;if(_f<_b/4)sp_gc_threshold=_b*2;else if(sp_gc_bytes>0){sp_gc_threshold=sp_gc_bytes*4;if(sp_gc_threshold<sp_gc_threshold_init)sp_gc_threshold=sp_gc_threshold_init;}else sp_gc_threshold=sp_gc_threshold_init;}")
        return
      end
      if vt == "poly"
        # Box the value
        emit("  " + vref + " = " + box_expr_to_poly(@nd_expression[nid]) + ";")
        return
      end
      if vt == "mutable_str"
        rhs_type = infer_type(@nd_expression[nid])
        val = compile_expr(@nd_expression[nid])
        if rhs_type == "string" || rhs_type == "int"
          emit("  " + vref + " = sp_String_new(" + val + ");")
        else
          emit("  " + vref + " = " + val + ";")
        end
        return
      end
      # Optimize: x = str.split(sep) inside a loop → reuse StrArray
      if @in_loop == 1 && vt == "str_array"
        expr_id = @nd_expression[nid]
        if expr_id >= 0 && @nd_type[expr_id] == "CallNode" && @nd_name[expr_id] == "split"
          r = @nd_receiver[expr_id]
          if r >= 0 && infer_type(r) == "string"
            src = compile_expr(r)
            sep = compile_arg0(expr_id)
            emit("  if (" + vref + " == NULL) " + vref + " = sp_str_split(" + src + ", " + sep + ");")
            emit("  else sp_str_split_into(" + vref + ", " + src + ", " + sep + ");")
            return
          end
        end
      end
      rhs_t = infer_type(@nd_expression[nid])
      if rhs_t == "nil" && is_nullable_type(vt) == 1
        emit("  " + vref + " = NULL;")
      else
        val = compile_expr(@nd_expression[nid])
        # Box scalar RHS into poly when the local slot is poly. Without
        # this, `lv = sp_IntArray_get(...)` (int RHS) into a sp_RbVal
        # slot fails C compile. Mirrors the InstanceVariableWriteNode
        # path's box-when-slot-is-poly logic.
        if vt == "poly" && rhs_t != "" && rhs_t != "poly"
          val = box_value_to_poly(rhs_t, val)
        end
        # Auto-unbox poly RHS into a primitive local slot. Common
        # case: `pixel0 = arr[i]` where arr is heterogeneous (poly
        # element type) and the dispatch arms all return int —
        # spinel types `arr[i]` as poly, but the local is concretely
        # int from a prior int-typed write. Reading .v.i preserves
        # the runtime int payload; non-int payloads fall to 0
        # (matches `to_i` semantics for poly).
        if rhs_t == "poly" && (vt == "int" || vt == "bool")
          val = "(" + val + ").v.i"
          rhs_t = vt
        end
        if rhs_t == "poly" && vt == "float"
          val = "(" + val + ").v.f"
          rhs_t = vt
        end
        # Auto-unbox poly RHS into a typed pointer slot. The
        # poly_poly_hash IndexOrWriteNode lowering returns sp_RbVal
        # so a `param = @cache[k] ||= param` assignment against a
        # typed param (e.g. `sp_Method *` for the optcarrot @pokes
        # cache where all callers happen to pass Method) needs the
        # `.v.p` extraction here. Strip the nullable `?` marker so
        # nullable obj slots (`obj_Method?`) cast to the same C type.
        kept_typed_unbox = 0
        if rhs_t == "poly" && is_obj_type(base_type(vt)) == 1
          cname_unbox = base_type(vt)[4, base_type(vt).length - 4]
          val = "(sp_" + cname_unbox + " *)(" + val + ").v.p"
          kept_typed_unbox = 1
        end
        emit("  " + vref + " = " + val + ";")
      end
      if rhs_t != "nil" || is_nullable_type(vt) == 0
        # Skip the type-widening update when we just unboxed the
        # poly RHS into a typed pointer slot — the C variable's
        # declared type is unchanged, so future reads must keep
        # treating the slot as the original obj_X.
        if !(rhs_t == "poly" && is_obj_type(base_type(vt)) == 1)
          set_var_type(lname, rhs_t)
        end
      end
      # Track `lv = @ivar` as a one-step alias so the `<poly>[k]`
      # narrowing can resolve through the local back to the ivar's
      # element-observation list. Any non-ivar RHS (or a subsequent
      # write of a non-ivar) clears the alias.
      ivar_alias = ""
      ex_id = @nd_expression[nid]
      if ex_id >= 0 && @nd_type[ex_id] == "InstanceVariableReadNode"
        ivar_alias = @nd_name[ex_id]
      end
      set_var_ivar_alias(lname, ivar_alias)
      return
    end
    if t == "LocalVariableOperatorWriteNode"
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      vref = fiber_var_ref(@nd_name[nid])
      vt = find_var_type(@nd_name[nid])
      # Same desugaring as the ivar form: `local OP= rhs` is
      # `local = local OP rhs`. Dispatch through the user-defined
      # operator when the local is obj-typed.
      disp = obj_op_dispatch_expr(vt, vref, op, val)
      if disp != ""
        emit("  " + vref + " = " + disp + ";")
        return
      end
      if vt == "bigint"
        at = infer_type(@nd_expression[nid])
        # Cast away volatile from bigint locals (see compile_bigint_arg).
        barg = at == "bigint" ? "(sp_Bigint *)" + val : "sp_bigint_new_int(" + val + ")"
        vref_b = "(sp_Bigint *)" + vref
        if op == "+"
          emit("  " + vref + " = sp_bigint_add(" + vref_b + ", " + barg + ");")
        end
        if op == "-"
          emit("  " + vref + " = sp_bigint_sub(" + vref_b + ", " + barg + ");")
        end
        if op == "*"
          emit("  " + vref + " = sp_bigint_mul(" + vref_b + ", " + barg + ");")
        end
        if op == "/"
          emit("  " + vref + " = sp_bigint_div(" + vref_b + ", " + barg + ");")
        end
        emit("  if(sp_gc_bytes>sp_gc_threshold){size_t _b=sp_gc_bytes;sp_gc_collect();size_t _f=_b-sp_gc_bytes;if(_f<_b/4)sp_gc_threshold=_b*2;else if(sp_gc_bytes>0){sp_gc_threshold=sp_gc_bytes*4;if(sp_gc_threshold<sp_gc_threshold_init)sp_gc_threshold=sp_gc_threshold_init;}else sp_gc_threshold=sp_gc_threshold_init;}")
        return
      end
      if op == "+"
        if vt == "string" && infer_type(@nd_expression[nid]) == "string"
          emit("  " + vref + " = sp_str_concat(" + vref + ", " + val + ");")
        elsif vt == "complex" && infer_type(@nd_expression[nid]) == "complex"
          # `+=` on a struct doesn't compile in C; desugar to
          # `vref = sp_complex_add(vref, val)`.
          emit("  " + vref + " = sp_complex_add(" + vref + ", " + val + ");")
        else
          emit("  " + vref + " += " + val + ";")
        end
      end
      if op == "-"
        emit("  " + vref + " -= " + val + ";")
      end
      if op == "*"
        if vt == "complex" && infer_type(@nd_expression[nid]) == "complex"
          emit("  " + vref + " = sp_complex_mul(" + vref + ", " + val + ");")
        else
          emit("  " + vref + " *= " + val + ";")
        end
      end
      if op == "/"
        emit("  " + vref + " = sp_idiv(" + vref + ", " + val + ");")
      end
      if op == "%"
        emit("  " + vref + " = sp_imod(" + vref + ", " + val + ");")
      end
      if op == "<<"
        emit("  " + vref + " <<= " + val + ";")
      end
      if op == ">>"
        emit("  " + vref + " >>= " + val + ";")
      end
      if op == "&"
        emit("  " + vref + " &= " + val + ";")
      end
      if op == "|"
        emit("  " + vref + " |= " + val + ";")
      end
      if op == "^"
        emit("  " + vref + " ^= " + val + ";")
      end
      return
    end
    if t == "LocalVariableOrWriteNode"
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      emit("  if (!(" + vref + ")) " + vref + " = " + val + ";")
      return
    end
    if t == "LocalVariableAndWriteNode"
      vref = fiber_var_ref(@nd_name[nid])
      val = compile_expr(@nd_expression[nid])
      emit("  if (" + vref + ") " + vref + " = " + val + ";")
      return
    end
    if t == "InstanceVariableWriteNode"
      iname = @nd_name[nid]
      expr_id = @nd_expression[nid]
      # Chained `@a = @b = ... = expr`. The naive emit lowers this as
      # `iv_a = (iv_b = (... = expr))` — one `expr` evaluation, but the
      # outer slot tries to absorb the inner write's typed value, so
      # disagreeing slot types fail the C compile. Per-slot recursion
      # would re-evaluate `expr` once per ivar and double-fire side
      # effects on a CallNode rhs. Compute `expr` once into a typed
      # temp and assign each slot from the temp, boxing to poly only
      # for the slots that scan_writer_calls already widened.
      if @nd_type[expr_id] == "InstanceVariableWriteNode"
        compile_chained_ivar_writes(nid)
        return
      end
      # Empty `{}` / `[]` literal assigned to an ivar that scan_writer_calls
      # has promoted to a non-default container type. The literal emitters use
      # default empty container types, so without this special-case the ivar
      # slot's type and the initializer's type can disagree.
      ivt = ""
      if @current_class_idx >= 0
        ivt = cls_ivar_type(@current_class_idx, iname)
      end
      if is_empty_hash_literal(expr_id) == 1 && ivt != "" && ivt != "str_int_hash"
        ctor = ""
        if ivt == "str_str_hash"
          @needs_str_str_hash = 1
          ctor = "sp_StrStrHash_new()"
        elsif ivt == "int_str_hash"
          @needs_int_str_hash = 1
          ctor = "sp_IntStrHash_new()"
        elsif ivt == "sym_int_hash"
          @needs_sym_int_hash = 1
          ctor = "sp_SymIntHash_new()"
        elsif ivt == "sym_str_hash"
          @needs_sym_str_hash = 1
          ctor = "sp_SymStrHash_new()"
        elsif ivt == "str_poly_hash"
          ctor = "sp_StrPolyHash_new()"
        elsif ivt == "sym_poly_hash"
          ctor = "sp_SymPolyHash_new()"
        elsif ivt == "poly_poly_hash"
          @needs_poly_poly_hash = 1
          @needs_rb_value = 1
          ctor = "sp_PolyPolyHash_new()"
        end
        if ctor != ""
          @needs_gc = 1
          emit("  " + self_arrow + sanitize_ivar(iname) + " = " + ctor + ";")
          return
        end
      end
      if is_empty_array_literal(expr_id) == 1 && ivt != ""
        ctor = empty_array_new_for_type(ivt)
        if ctor != ""
          @needs_gc = 1
          emit("  " + self_arrow + sanitize_ivar(iname) + " = " + ctor + ";")
          return
        end
      end
      # `@arr = [nil] * N` where @arr is a poly_array (or ptr_array)
      # slot. The default `*` codegen produces an sp_IntArray, which
      # mismatches the slot type and corrupts later
      # `sp_PolyArray_set(@arr, ...)` calls. Emit a sized PolyArray
      # of sp_box_nil() (or PtrArray of NULLs) inline so the slot
      # holds the matching storage.
      if (ivt == "poly_array" || is_ptr_array_type(ivt) == 1) && is_sized_empty_array_default(expr_id) == 1
        @needs_gc = 1
        cnt_e = compile_arg0(expr_id)
        tmp_arr = new_temp
        if ivt == "poly_array"
          @needs_rb_value = 1
          emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
          emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_arr + ", sp_box_nil()); }")
        else
          emit("  sp_PtrArray *" + tmp_arr + " = sp_PtrArray_new();")
          emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PtrArray_push(" + tmp_arr + ", NULL); }")
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + tmp_arr + ";")
        return
      end
      # `@arr = [nil] * N` where @arr is a poly slot (sp_RbVal). The
      # cyclic inference can leave a slot at poly when its definition
      # site `[nil] * N` would naturally infer as int_array but a
      # subsequent heterogeneous write demands more. Emit as a sized
      # PolyArray boxed to poly so the runtime storage supports
      # heterogeneous writes via the poly-recv `[]=` dispatch.
      if ivt == "poly" && is_sized_empty_array_default(expr_id) == 1
        @needs_gc = 1
        @needs_rb_value = 1
        cnt_e = compile_arg0(expr_id)
        tmp_arr = new_temp
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        emit("  { mrb_int _n = " + cnt_e + "; for (mrb_int _i = 0; _i < _n; _i++) sp_PolyArray_push(" + tmp_arr + ", sp_box_nil()); }")
        emit("  " + self_arrow + sanitize_ivar(iname) + " = sp_box_poly_array(" + tmp_arr + ");")
        return
      end
      # Non-empty array literal `[a, b, ...]` going into a poly_array
      # slot. compile_array_literal infers a typed array (ptr_array of
      # one class for homogeneous obj literals, etc.) and emits the
      # corresponding storage — but the slot was widened to poly_array,
      # so a typed-array-pointer assignment would fail the C compile.
      # Emit a fresh PolyArray with each element boxed to sp_RbVal.
      if ivt == "poly_array" && @nd_type[expr_id] == "ArrayNode"
        @needs_gc = 1
        @needs_rb_value = 1
        tmp_arr = new_temp
        emit("  sp_PolyArray *" + tmp_arr + " = sp_PolyArray_new();")
        elems_pa = parse_id_list(@nd_elements[expr_id])
        ek = 0
        while ek < elems_pa.length
          eid = elems_pa[ek]
          et = infer_type(eid)
          # 3D+ shape: nested ArrayNode with ptr_array element
          # type — recompile as poly_array so cls_id chain stays
          # tagged through every level.
          if @nd_type[eid] == "ArrayNode" && (is_ptr_array_type(et) == 1 || et == "poly_array")
            inner = compile_array_literal_as_poly(eid)
            emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_poly_array(" + inner + "));")
          elsif is_ptr_array_type(et) == 1
            # Same 3D+ erasure but the element is a non-ArrayNode
            # expression (e.g. `Array.new(N) { ... }` returning a
            # typed `<X>_ptr_array`). Convert at runtime so each
            # inner element keeps its real cls_id —
            # `arr[b][i][j]` chains correctly.
            ev = compile_expr(eid)
            inner_t_pa = ptr_array_elem_type(et)
            conv_pa = new_temp
            ii_pa = new_temp
            emit("  sp_PolyArray *" + conv_pa + " = sp_PolyArray_new();")
            emit("  for (mrb_int " + ii_pa + " = 0; " + ii_pa + " < sp_PtrArray_length(" + ev + "); " + ii_pa + "++) {")
            inner_get_pa = "(" + c_type(inner_t_pa) + ")sp_PtrArray_get(" + ev + ", " + ii_pa + ")"
            emit("    sp_PolyArray_push(" + conv_pa + ", " + box_value_to_poly(inner_t_pa, inner_get_pa) + ");")
            emit("  }")
            emit("  sp_PolyArray_push(" + tmp_arr + ", sp_box_poly_array(" + conv_pa + "));")
          else
            ev = compile_expr(eid)
            ebox = et == "poly" ? ev : box_value_to_poly(et, ev)
            emit("  sp_PolyArray_push(" + tmp_arr + ", " + ebox + ");")
          end
          ek = ek + 1
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + tmp_arr + ";")
        return
      end
      # Poly slot — every concrete-typed RHS must be boxed to
      # sp_RbVal. Without the box, the C compiler sees
      # `sp_RbVal = mrb_int` (or const char *, etc.) and either
      # rejects the assignment or silently coerces. Read sites
      # already dispatch through poly-aware emitters
      # (sp_poly_puts, etc.) that unbox.
      if ivt == "poly"
        val = box_expr_to_poly(expr_id)
      else
        val = compile_expr(expr_id)
      end
      # Check if we're in a module class method
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname[1, iname.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + val + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        emit("  " + ivar_lhs(iname) + " = " + val + ";")
      end
      return
    end
    # `@x ||= expr`: `@x = expr` only when @x is currently nil/false.
    # Lower to `if (!@x) { @x = expr; }`. For pointer-typed slots
    # (sp_Foo *, const char *, ...) the C `!ptr` check is exact; for
    # an int slot we treat 0 as falsy (Spinel's int slot has no
    # separate nil/false state). The `&&= expr` form is the dual.
    # Compile the rhs INSIDE the conditional block so any auxiliary
    # emits land in the conditional body — matches Ruby's
    # short-circuit semantics where the rhs (and its side effects)
    # only run when the lhs is falsy.
    if t == "InstanceVariableOrWriteNode" || t == "InstanceVariableAndWriteNode"
      ivor_iname = @nd_name[nid]
      ivor_lhs = ivar_lhs(ivor_iname)
      ivor_expr_id = @nd_expression[nid]
      ivor_ivar_t = ""
      if @current_class_idx >= 0
        ivor_ivar_t = cls_ivar_type(@current_class_idx, ivor_iname)
      end
      ivor_cond = ""
      if base_type(ivor_ivar_t) == "poly"
        ivor_cond = "(" + ivor_lhs + ").tag == SP_TAG_NIL || ((" + ivor_lhs + ").tag == SP_TAG_BOOL && (" + ivor_lhs + ").v.i == 0)"
      else
        ivor_cond = "!(" + ivor_lhs + ")"
      end
      if t == "InstanceVariableAndWriteNode"
        ivor_cond = "!(" + ivor_cond + ")"
      end
      emit("  if (" + ivor_cond + ") {")
      ivor_val = compile_expr(ivor_expr_id)
      ivor_val_t = infer_type(ivor_expr_id)
      if base_type(ivor_ivar_t) == "poly" && ivor_val_t != "" && ivor_val_t != "poly"
        ivor_val = box_value_to_poly(ivor_val_t, ivor_val)
      end
      emit("    " + ivor_lhs + " = " + ivor_val + ";")
      emit("  }")
      return
    end
    if t == "InstanceVariableOperatorWriteNode"
      op = @nd_binop[nid]
      val = compile_expr(@nd_expression[nid])
      lhs = ivar_lhs(@nd_name[nid])
      ivar_t = ""
      if @current_class_idx >= 0
        ivar_t = cls_ivar_type(@current_class_idx, @nd_name[nid])
      end
      # `@x OP= v` desugars to `@x = @x OP v`. When @x is obj-typed
      # and the class defines OP, dispatch to the user method
      # instead of emitting a raw C `+=` (which on a pointer is
      # silently miscompiled as pointer arithmetic).
      disp = obj_op_dispatch_expr(ivar_t, lhs, op, val)
      if disp != ""
        emit("  " + lhs + " = " + disp + ";")
        return
      end
      # Bitwise / shift / arithmetic op-assigns map directly onto C
      # `OP=`. Without these arms `@a &= v`, `@a |= v`, etc. were
      # silently dropped — the function emit fell through with no
      # `iv_<name>` write, so every read after kept the pre-call
      # value. Mirror the LocalVariableOperatorWriteNode arm.
      if op == "+"
        if ivar_t == "string" && infer_type(@nd_expression[nid]) == "string"
          emit("  " + lhs + " = sp_str_concat(" + lhs + ", " + val + ");")
        else
          emit("  " + lhs + " += " + val + ";")
        end
        return
      end
      if op == "-"
        emit("  " + lhs + " -= " + val + ";")
        return
      end
      if op == "*"
        emit("  " + lhs + " *= " + val + ";")
        return
      end
      if op == "/"
        emit("  " + lhs + " = sp_idiv(" + lhs + ", " + val + ");")
        return
      end
      if op == "%"
        emit("  " + lhs + " = sp_imod(" + lhs + ", " + val + ");")
        return
      end
      if op == "<<" || op == ">>" || op == "&" || op == "|" || op == "^"
        emit("  " + lhs + " " + op + "= " + val + ";")
        return
      end
      return
    end
    # `recv[idx] OP= value`. Without this case, the IndexOperatorWriteNode
    # the parser emits would fall through and the increment would be
    # silently dropped — symptoms include matmul / += accumulators
    # producing zero-valued output even though forward passes look fine.
    if t == "IndexOperatorWriteNode"
      compile_index_op_assign(nid)
      return
    end
    if t == "IndexAndWriteNode"
      compile_index_and_assign(nid)
      return
    end
    if t == "IndexOrWriteNode"
      compile_index_or_assign(nid)
      return
    end
    if t == "CallOperatorWriteNode"
      compile_call_assign_typed(nid, "Operator")
      return
    end
    if t == "CallAndWriteNode"
      compile_call_assign_typed(nid, "And")
      return
    end
    if t == "CallOrWriteNode"
      compile_call_assign_typed(nid, "Or")
      return
    end
    if t == "IfNode"
      compile_if_stmt(nid)
      return
    end
    if t == "UnlessNode"
      compile_unless_stmt(nid)
      return
    end
    if t == "WhileNode"
      compile_while_stmt(nid)
      return
    end
    if t == "UntilNode"
      compile_until_stmt(nid)
      return
    end
    if t == "ForNode"
      compile_for_stmt(nid)
      return
    end
    if t == "CaseNode"
      compile_case_stmt(nid)
      return
    end
    if t == "CaseMatchNode"
      compile_case_match_stmt(nid)
      return
    end
    if t == "ReturnNode"
      compile_return_stmt(nid)
      return
    end
    if t == "BreakNode"
      emit("  break;")
      return
    end
    if t == "NextNode"
      emit("  continue;")
      return
    end
    if t == "RetryNode"
      emit("  continue;")
      return
    end
    if t == "YieldNode"
      compile_yield_stmt(nid)
      return
    end
    if t == "BeginNode"
      compile_begin_stmt(nid)
      return
    end
    if t == "CallNode"
      compile_call_stmt(nid)
      return
    end
    if t == "StatementsNode"
      stmts = parse_id_list(@nd_stmts[nid])
      k = 0
      while k < stmts.length
        compile_stmt(stmts[k])
        k = k + 1
      end
      return
    end
    if t == "ParenthesesNode"
      body = @nd_body[nid]
      if body >= 0
        pstmts = get_stmts(body)
        pk = 0
        while pk < pstmts.length
          compile_stmt(pstmts[pk])
          pk = pk + 1
        end
      end
      return
    end
    expr = compile_expr(nid)
    if expr != "0"
      emit("  " + expr + ";")
    end
    return
  end

  # Emit assignment of `value_expr` to a single MultiWrite target node
  # (LocalVariableTargetNode or InstanceVariableTargetNode). Centralized
  # so the splat path doesn't have to duplicate the InstanceVariable
  # special-cases (module-method-promoted ivar handling).
  # Assign `value_expr` (whose static C type is `value_type`) into the
  # multi-write target node. When the local target's slot is `poly` and
  # the source value isn't already boxed, the value is boxed first so a
  # heterogeneous RHS like `a, b, c = [1, "b", 2.0]` lands in the right
  # tagged-union slots.
  def emit_multi_write_target(tid, value_expr, value_type)
    if @nd_type[tid] == "LocalVariableTargetNode"
      lname = @nd_name[tid]
      vt = find_var_type(lname)
      v = value_expr
      if vt == "poly" && value_type != "" && value_type != "poly"
        v = box_value_to_poly(value_type, value_expr)
      end
      # Reverse direction: poly RHS into a concrete-typed local
      # slot. Happens when destructuring a poly_array element
      # (each slot was sp_PolyArray_get, returning sp_RbVal).
      if value_type == "poly" && vt != "" && vt != "poly"
        v = unbox_poly_to(vt, value_expr)
      end
      emit("  " + fiber_var_ref(lname) + " = " + v + ";")
      return
    end
    if @nd_type[tid] == "InstanceVariableTargetNode"
      iname = @nd_name[tid]
      mod_ivar = 0
      mi3 = 0
      while mi3 < @module_names.length
        mmod = @module_names[mi3]
        if mmod != ""
          if @current_method_name.start_with?(mmod + "_cls_")
            cname3 = mmod + "_" + iname[1, iname.length - 1]
            ci3 = find_const_idx(cname3)
            if ci3 >= 0
              emit("  cst_" + cname3 + " = " + value_expr + ";")
              mod_ivar = 1
            end
          end
        end
        mi3 = mi3 + 1
      end
      if mod_ivar == 0
        v = value_expr
        if @current_class_idx >= 0
          it = cls_ivar_type(@current_class_idx, iname)
          if it == "poly" && value_type != "" && value_type != "poly"
            v = box_value_to_poly(value_type, value_expr)
          end
          if value_type == "poly" && it != "" && it != "poly"
            v = unbox_poly_to(it, value_expr)
          end
        end
        emit("  " + self_arrow + sanitize_ivar(iname) + " = " + v + ";")
      end
      return
    end
    if @nd_type[tid] == "CallTargetNode"
      # `obj.attr = val` style — used as one slot in a multi-write
      # destructure. Lower as either a direct ivar write (when the
      # receiver class has an attr_writer for the name) or as a call
      # to `sp_<C>_<attr>_eq`.
      recv_id = @nd_receiver[tid]
      mname = @nd_name[tid]
      if mname.end_with?("=")
        mname = mname[0, mname.length - 1]
      end
      recv_t = infer_type(recv_id)
      recv_c = compile_expr(recv_id)
      if recv_t.start_with?("obj_")
        cls_n = recv_t[4, recv_t.length - 4]
        ci_w = find_class_idx(cls_n)
        if cls_has_attr_writer(ci_w, mname) == 1
          emit("  " + recv_c + "->iv_" + mname + " = " + value_expr + ";")
        else
          emit("  sp_" + cls_n + "_" + mname + "_eq(" + recv_c + ", " + value_expr + ");")
        end
      end
    end
    if @nd_type[tid] == "IndexTargetNode"
      # Multi-assign LHS: `a[0], b[1] = 1, 2`. Each LHS is an
      # IndexTargetNode with a receiver and an arguments slot.
      # Routes through the same per-receiver-type sp_<TYPE>_set
      # dispatch as compile_index_op_assign, but without the
      # read-then-modify dance -- the value is supplied by the
      # caller. The temp-receiver pattern keeps `a` and the index
      # evaluated exactly once.
      tgt_recv = @nd_receiver[tid]
      tgt_args_id = @nd_arguments[tid]
      tgt_arg_ids = tgt_args_id >= 0 ? get_args(tgt_args_id) : []
      if tgt_arg_ids.length >= 1
        rt = infer_type(tgt_recv)
        rc = compile_expr_gc_rooted(tgt_recv)
        idx = compile_expr(tgt_arg_ids[0])
        if rt == "float_array" || rt == "int_array"
          pfx = array_c_prefix(rt)
          tt = new_temp
          ti = new_temp
          emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
               "; sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "str_int_hash"
          tt = new_temp
          ti = new_temp
          idx_s = compile_expr_as_string(tgt_arg_ids[0])
          emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s +
               "; sp_StrIntHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "sym_int_hash"
          tt = new_temp
          ti = new_temp
          emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
               "; sp_SymIntHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
        if rt == "int_str_hash"
          tt = new_temp
          ti = new_temp
          emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
               "; sp_IntStrHash_set(" + tt + ", " + ti + ", (" + value_expr + ")); }")
        end
      end
    end
    if @nd_type[tid] == "GlobalVariableTargetNode"
      # Multi-assign LHS: `$a, $b = 1, 2`. Same storage path as
      # GlobalVariableWriteNode but without an embedded expression --
      # the value is supplied by the caller.
      emit("  " + sanitize_gvar(@nd_name[tid]) + " = " + value_expr + ";")
    end
    if @nd_type[tid] == "MultiTargetNode"
      # Nested LHS: `a, (b, c), d = 1, [2, 3], 4`. The slot of the
      # outer multi-write that this node occupies is an array-typed
      # value; recursively unpack it into the inner targets via
      # per-element index reads.
      compile_nested_multi_target(tid, value_expr, value_type)
    end
  end

  # Handle `a, *b = rhs` / `*a, b = rhs` / `a, *b, c = rhs`.
  # `lefts` are pre-splat targets, `rest_id` is the SplatNode (its
  # expression is the splat target), `rights` are post-splat targets.
  def compile_multi_write_splat(lefts, rest_id, rights, val_id)
    splat_target = @nd_expression[rest_id]
    nleft = lefts.length
    nright = rights.length

    # ArrayNode literal RHS — split statically.
    if @nd_type[val_id] == "ArrayNode"
      elems = parse_id_list(@nd_elements[val_id])
      n = elems.length
      # Evaluate all RHS into temps first (swap-safe).
      tmps = "".split(",")
      ttypes = "".split(",")
      k = 0
      while k < n
        tmp = new_temp
        tmps.push(tmp)
        et = infer_type(elems[k])
        ttypes.push(et)
        emit("  " + c_type(et) + " " + tmp + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
      # Pre-splat targets get the first `nleft` temps.
      k = 0
      while k < nleft
        if k < n
          emit_multi_write_target(lefts[k], tmps[k], ttypes[k])
        end
        k = k + 1
      end
      # Splat target receives a fresh array of the matching element type.
      mid_count = n - nleft - nright
      if mid_count < 0
        mid_count = 0
      end
      st_type = splat_rest_type(val_id)
      st_tmp = new_temp
      @needs_gc = 1
      if st_type == "str_array"
        @needs_str_array = 1
        emit("  sp_StrArray *" + st_tmp + " = sp_StrArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_StrArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif st_type == "float_array"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + st_tmp + " = sp_FloatArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_FloatArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif is_ptr_array_type(st_type) == 1
        emit("  sp_PtrArray *" + st_tmp + " = sp_PtrArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_PtrArray_push(" + st_tmp + ", " + tmps[nleft + k] + ");")
          k = k + 1
        end
      elsif st_type == "poly_array"
        emit("  sp_PolyArray *" + st_tmp + " = sp_PolyArray_new();")
        k = 0
        while k < mid_count
          boxed = box_value_to_poly(ttypes[nleft + k], tmps[nleft + k])
          emit("  sp_PolyArray_push(" + st_tmp + ", " + boxed + ");")
          k = k + 1
        end
      else
        # int_array / sym_array share IntArray storage via mrb_int
        # reinterpretation at compile time.
        @needs_int_array = 1
        emit("  sp_IntArray *" + st_tmp + " = sp_IntArray_new();")
        k = 0
        while k < mid_count
          emit("  sp_IntArray_push(" + st_tmp + ", (mrb_int)" + tmps[nleft + k] + ");")
          k = k + 1
        end
      end
      emit_multi_write_target(splat_target, st_tmp, st_type)
      # Post-splat targets get the trailing temps.
      k = 0
      while k < nright
        idx = n - nright + k
        if idx >= 0 && idx < n
          emit_multi_write_target(rights[k], tmps[idx], ttypes[idx])
        end
        k = k + 1
      end
      return
    end

    # Generic typed-array RHS — slice at runtime.
    rt = infer_type(val_id)
    @needs_gc = 1
    tmp = new_temp
    emit("  " + c_type(rt) + " " + tmp + " = " + compile_expr(val_id) + ";")
    emit("  SP_GC_ROOT(" + tmp + ");")
    len_tmp = new_temp
    emit("  mrb_int " + len_tmp + " = " + length_c_expr(rt, tmp) + ";")
    # Pre-splat targets. int_array / sym_array share IntArray storage,
    # so they share the default. Other typed arrays need their matching
    # `_get` / `_slice` so the C calls are well-typed.
    get_fn = "sp_IntArray_get"
    slice_fn = "sp_IntArray_slice"
    if rt == "str_array"
      get_fn = "sp_StrArray_get"
      slice_fn = "sp_StrArray_slice"
    end
    if rt == "float_array"
      get_fn = "sp_FloatArray_get"
      slice_fn = "sp_FloatArray_slice"
    end
    if rt == "poly_array"
      get_fn = "sp_PolyArray_get"
      slice_fn = "sp_PolyArray_slice"
    end
    if is_ptr_array_type(rt) == 1
      get_fn = "sp_PtrArray_get"
      slice_fn = "sp_PtrArray_slice"
    end
    elem_t = elem_type_of_array(rt)
    k = 0
    while k < nleft
      emit_multi_write_target(lefts[k], get_fn + "(" + tmp + ", " + k.to_s + ")", elem_t)
      k = k + 1
    end
    # Splat target gets a runtime slice.
    mid_len = len_tmp + " - " + (nleft + nright).to_s
    emit_multi_write_target(splat_target, slice_fn + "(" + tmp + ", " + nleft.to_s + ", " + mid_len + ")", rt)
    # Post-splat targets.
    k = 0
    while k < nright
      offset_expr = len_tmp + " - " + (nright - k).to_s
      emit_multi_write_target(rights[k], get_fn + "(" + tmp + ", " + offset_expr + ")", elem_t)
      k = k + 1
    end
  end

  # The element type of an array-typed MultiTarget slot. For
  # `a, (b, c) = 1, [2, 3]` the slot value_type is "int_array" and
  # this returns "int" so b/c are declared as mrb_int. Mirrors the
  # array-prefix dispatch in compile_nested_multi_target.
  def nested_target_elem_type(slot_type)
    if slot_type == "int_array"
      return "int"
    end
    if slot_type == "float_array"
      return "float"
    end
    if slot_type == "str_array"
      return "string"
    end
    if slot_type == "sym_array"
      return "sym"
    end
    "int"
  end

  # Recursively unpack a `MultiTargetNode` slot in a multi-assign.
  # `value_expr` holds the value of this slot (always an array-typed
  # expression, since the source is `a, (b, c), d = ..., [2, 3], ...`).
  # We dispatch on the array's element type and emit per-target
  # index reads.
  def compile_nested_multi_target(tid, value_expr, value_type)
    lefts = parse_id_list(@nd_targets[tid])
    prefix = ""
    elem_t = "int"
    if value_type == "int_array"
      prefix = "IntArray"
      elem_t = "int"
    end
    if value_type == "float_array"
      prefix = "FloatArray"
      elem_t = "float"
    end
    if value_type == "str_array"
      prefix = "StrArray"
      elem_t = "string"
    end
    if value_type == "sym_array"
      prefix = "IntArray"
      elem_t = "sym"
    end
    if prefix == ""
      $stderr.puts "Spinel: MultiTargetNode requires a typed-array RHS slot; got value_type \"" + value_type + "\""
      exit(1)
    end
    @needs_gc = 1
    tmp_arr = new_temp
    emit("  sp_" + prefix + " *" + tmp_arr + " = " + value_expr + ";")
    k = 0
    while k < lefts.length
      inner_val = "sp_" + prefix + "_get(" + tmp_arr + ", " + k.to_s + ")"
      emit_multi_write_target(lefts[k], inner_val, elem_t)
      k = k + 1
    end
  end

  def compile_multi_write(nid)
    targets = parse_id_list(@nd_targets[nid])
    val_id = @nd_expression[nid]
    if val_id < 0
      return
    end
    rest_id = @nd_rest[nid]
    if is_splat_with_target(rest_id) == 1
      rights = parse_id_list(@nd_rights[nid])
      compile_multi_write_splat(targets, rest_id, rights, val_id)
      return
    end
    if @nd_type[val_id] == "ArrayNode"
      # Direct array literal: a, b, c = [1, 2, 3] or a, b = b, a
      elems = parse_id_list(@nd_elements[val_id])
      # For swap safety, evaluate all RHS first into temps
      tmps = "".split(",")
      ttypes_lit = "".split(",")
      k = 0
      while k < elems.length
        tmp = new_temp
        tmps.push(tmp)
        et = infer_type(elems[k])
        ttypes_lit.push(et)
        emit("  " + c_type(et) + " " + tmp + " = " + compile_expr(elems[k]) + ";")
        k = k + 1
      end
      # Now assign — emit_multi_write_target boxes when target slot is poly.
      k = 0
      while k < targets.length
        if k < tmps.length
          emit_multi_write_target(targets[k], tmps[k], ttypes_lit[k])
        end
        k = k + 1
      end
    elsif is_tuple_type(infer_type(val_id)) == 1
      # RHS is a tuple-returning call — destructure via field access.
      # Route every slot through emit_multi_write_target so ivar /
      # constant / attr-writer / index targets (not just local vars)
      # all get the per-component assignment.
      val_t = infer_type(val_id)
      @needs_gc = 1
      tmp = new_temp
      emit("  " + c_type(val_t) + " " + tmp + " = " + compile_expr(val_id) + ";")
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < targets.length
        tid = targets[k]
        slot_expr = tmp + "->_" + k.to_s
        slot_type = tuple_elem_type_at(val_t, k)
        emit_multi_write_target(tid, slot_expr, slot_type)
        k = k + 1
      end
    else
      # RHS is a function call returning a typed array. Dispatch by
      # the RHS's static type — IntArray default, PolyArray when the
      # inner is heterogeneous (optcarrots `@io_addr,
      # @bg_pattern_lut_fetched, _ = @attr_lut[i]` where attr_lut
      # elements are 3-tuples of mixed types), and the matching typed-
      # array variants otherwise. Without per-type dispatch a method
      # returning e.g. `[Mat.new, Mat.new]` (typed obj_Mat_ptr_array)
      # destructured via `a, b = self.two_mats` got compiled as
      # `sp_IntArray *_t = sp_N_two_mats(...); sp_IntArray_get(_t, i)`,
      # mismatching the actual sp_PtrArray * return.
      val_t_local = infer_type(val_id)
      @needs_gc = 1
      tmp = new_temp
      if val_t_local == "poly_array"
        @needs_rb_value = 1
        emit("  sp_PolyArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "poly"
        # RHS is a poly value (e.g. `@attr_lut[i]` where @attr_lut
        # is a poly_array of inner arrays — each element is a
        # boxed sp_PolyArray with cls_id POLY_ARRAY). Unbox to
        # sp_PolyArray * and destructure via sp_PolyArray_get.
        # Same shape as the static poly_array branch above.
        @needs_rb_value = 1
        rb_tmp_mw = new_temp
        emit("  sp_RbVal " + rb_tmp_mw + " = " + compile_expr(val_id) + ";")
        emit("  sp_PolyArray *" + tmp + " = (" + rb_tmp_mw + ".cls_id == SP_BUILTIN_POLY_ARRAY) ? (sp_PolyArray *)" + rb_tmp_mw + ".v.p : NULL;")
      elsif val_t_local == "str_array"
        @needs_str_array = 1
        emit("  sp_StrArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "float_array"
        @needs_float_array = 1
        emit("  sp_FloatArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif val_t_local == "sym_array"
        emit("  sp_IntArray *" + tmp + " = " + compile_expr(val_id) + ";")
      elsif is_ptr_array_type(val_t_local) == 1
        emit("  sp_PtrArray *" + tmp + " = " + compile_expr(val_id) + ";")
      else
        @needs_int_array = 1
        emit("  sp_IntArray *" + tmp + " = " + compile_expr(val_id) + ";")
      end
      emit("  SP_GC_ROOT(" + tmp + ");")
      k = 0
      while k < targets.length
        tid = targets[k]
        if val_t_local == "poly_array" || val_t_local == "poly"
          rhs = "sp_PolyArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "poly"
        elsif val_t_local == "str_array"
          rhs = "sp_StrArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "string"
        elsif val_t_local == "float_array"
          rhs = "sp_FloatArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "float"
        elsif val_t_local == "sym_array"
          rhs = "((sp_sym)sp_IntArray_get(" + tmp + ", " + k.to_s + "))"
          val_t_for_target = "symbol"
        elsif is_ptr_array_type(val_t_local) == 1
          elem_t = ptr_array_elem_type(val_t_local)
          rhs = "((" + c_type(elem_t) + ")sp_PtrArray_get(" + tmp + ", " + k.to_s + "))"
          val_t_for_target = elem_t
        else
          rhs = "sp_IntArray_get(" + tmp + ", " + k.to_s + ")"
          val_t_for_target = "int"
        end
        # Route ivar / local writes through emit_multi_write_target so
        # the box-when-slot-is-poly logic fires. Without boxing, an int
        # RHS into a sp_RbVal slot fails C compile (`@x, @y = arr` where
        # @y is poly because other writers store other types).
        if @nd_type[tid] == "LocalVariableTargetNode"
          emit_multi_write_target(tid, rhs, val_t_for_target)
        end
        if @nd_type[tid] == "InstanceVariableTargetNode"
          emit_multi_write_target(tid, rhs, val_t_for_target)
        end
        if @nd_type[tid] == "ConstantTargetNode"
          if find_const_idx(@nd_name[tid]) >= 0
            emit("  cst_" + @nd_name[tid] + " = " + rhs + ";")
          end
        end
        if @nd_type[tid] == "CallTargetNode"
          # `obj.attr = <slot>` in a multi-write context.
          # Inline as a direct ivar write when the recv class has an
          # attr_writer; otherwise fall back to the generated setter.
          recv_id = @nd_receiver[tid]
          mname = @nd_name[tid]
          if mname.end_with?("=")
            mname = mname[0, mname.length - 1]
          end
          recv_t = infer_type(recv_id)
          recv_c = compile_expr(recv_id)
          slot_expr = "sp_IntArray_get(" + tmp + ", " + k.to_s + ")"
          if recv_t.start_with?("obj_")
            cls_n = recv_t[4, recv_t.length - 4]
            ci_w = find_class_idx(cls_n)
            if cls_has_attr_writer(ci_w, mname) == 1
              emit("  " + recv_c + "->iv_" + mname + " = " + slot_expr + ";")
            else
              emit("  sp_" + cls_n + "_" + mname + "_eq(" + recv_c + ", " + slot_expr + ");")
            end
          end
        end
        k = k + 1
      end
    end
  end

  def compile_if_stmt(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    # Static-false fold: a predicate whose static type is `nil`
    # (e.g. an attr_reader for an ivar only ever assigned `nil`)
    # collapses to `if (FALSE) { … }`. The body is unreachable, but
    # its statements still pass through the C compiler — and they
    # often type-error against ivars/methods whose shapes only make
    # sense when the predicate is true. Drop the body entirely; emit
    # the else branch (if any) at the surrounding scope.
    if cond == "FALSE"
      sub_sf = @nd_subsequent[nid]
      if sub_sf >= 0
        if @nd_type[sub_sf] == "ElseNode"
          compile_stmts_body(@nd_body[sub_sf])
        else
          compile_if_stmt(sub_sf)
        end
      end
      return
    end
    if cond == "TRUE"
      compile_stmts_body(@nd_body[nid])
      return
    end
    emit("  if (" + cond + ") {")
    @indent = @indent + 1
    compile_stmts_body(@nd_body[nid])
    @indent = @indent - 1
    sub = @nd_subsequent[nid]
    if sub >= 0
      if @nd_type[sub] == "ElseNode"
        emit("  } else {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[sub])
        @indent = @indent - 1
      else
        # Wrap elsif in braces. compile_cond_expr for the nested
        # predicate may emit prologue C (temp decls, tag checks)
        # before returning the cond expression — e.g.
        # `value.is_a?(B)` on a poly receiver expands to
        # `sp_RbVal _t = ...; if (_t.tag == SP_TAG_OBJ) {...}; if
        # (_flag) ...`. Without the wrap, the `} else <prologue>
        # if (...)` shape is invalid C: the bare-else's body
        # would be the first statement only (the prologue decl),
        # leaving the inner if in the outer scope with the decl
        # out of reach.
        emit("  } else {")
        @indent = @indent + 1
        compile_if_stmt(sub)
        @indent = @indent - 1
        emit("  }")
        return
      end
    end
    emit("  }")
  end

  def compile_unless_stmt(nid)
    cond = compile_cond_expr(@nd_predicate[nid])
    # Symmetric to compile_if_stmt's static-fold: an `unless` whose
    # predicate is statically TRUE drops its body, FALSE drops the
    # else branch.
    if cond == "TRUE"
      ec_sf = @nd_else_clause[nid]
      if ec_sf >= 0
        compile_stmts_body(@nd_body[ec_sf])
      end
      return
    end
    if cond == "FALSE"
      compile_stmts_body(@nd_body[nid])
      return
    end
    emit("  if (!(" + cond + ")) {")
    @indent = @indent + 1
    compile_stmts_body(@nd_body[nid])
    @indent = @indent - 1
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

  # C expression for computing length of a value of the given type.
  # Returns "" if the type doesn't have a hoist-friendly length op.
  def length_c_expr(rt, rc)
    if rt == "string"
      return "sp_str_length(" + rc + ")"
    end
    if rt == "int_array" || rt == "sym_array"
      return "sp_IntArray_length(" + rc + ")"
    end
    if rt == "str_array"
      return "sp_StrArray_length(" + rc + ")"
    end
    if rt == "float_array"
      return "sp_FloatArray_length(" + rc + ")"
    end
    if is_ptr_array_type(rt) == 1
      return "sp_PtrArray_length(" + rc + ")"
    end
    if rt == "poly_array"
      return "sp_PolyArray_length(" + rc + ")"
    end
    if rt == "str_int_hash"
      return "sp_StrIntHash_length(" + rc + ")"
    end
    if rt == "str_str_hash"
      return "sp_StrStrHash_length(" + rc + ")"
    end
    if rt == "int_str_hash"
      return "sp_IntStrHash_length(" + rc + ")"
    end
    if rt == "sym_int_hash"
      return "sp_SymIntHash_length((sp_SymIntHash *)(" + rc + "))"
    end
    if rt == "sym_str_hash"
      return "sp_SymStrHash_length((sp_SymStrHash *)(" + rc + "))"
    end
    ""
  end

  # Scan a while-body for any mutation of a local variable (by name).
  # Returns 1 if any mutating method call is found on the receiver
  # (push/pop/shift/unshift/<< / []= / delete / clear / insert /
  # replace / concat).  Used to block unsafe hoisting.
  def body_mutates_var?(body_nid, vname)
    if body_nid < 0
      return 0
    end
    t = @nd_type[body_nid]
    if t == "CallNode"
      mn = @nd_name[body_nid]
      recv = @nd_receiver[body_nid]
      if recv >= 0 && @nd_type[recv] == "LocalVariableReadNode" && @nd_name[recv] == vname
        if mn == "push" || mn == "pop" || mn == "shift" || mn == "unshift" ||
           mn == "<<" || mn == "[]=" || mn == "delete" || mn == "clear" ||
           mn == "insert" || mn == "replace" || mn == "concat" ||
           mn == "sort!" || mn == "reverse!" || mn == "compact!" || mn == "uniq!" ||
           mn == "merge!" || mn == "store" || mn == "update" || mn == "fill"
          return 1
        end
      end
    end
    if t == "LocalVariableWriteNode" && @nd_name[body_nid] == vname
      return 1
    end
    # Recurse into children
    if @nd_body[body_nid] >= 0
      if body_mutates_var?(@nd_body[body_nid], vname) == 1
        return 1
      end
    end
    stmts = parse_id_list(@nd_stmts[body_nid])
    k = 0
    while k < stmts.length
      if body_mutates_var?(stmts[k], vname) == 1
        return 1
      end
      k = k + 1
    end
    if @nd_subsequent[body_nid] >= 0
      if body_mutates_var?(@nd_subsequent[body_nid], vname) == 1
        return 1
      end
    end
    if @nd_receiver[body_nid] >= 0
      if body_mutates_var?(@nd_receiver[body_nid], vname) == 1
        return 1
      end
    end
    args_id = @nd_arguments[body_nid]
    if args_id >= 0
      arr = get_args(args_id)
      k = 0
      while k < arr.length
        if body_mutates_var?(arr[k], vname) == 1
          return 1
        end
        k = k + 1
      end
    end
    0
  end

  # Return the local variable name on which .length/.size is called
  # inside a comparison predicate (for mutation scanning).  Empty if
  # the predicate doesn't match the hoist pattern.
  def hoist_receiver_var(pred_nid)
    if @nd_type[pred_nid] != "CallNode"
      return ""
    end
    op = @nd_name[pred_nid]
    if op != "<" && op != "<=" && op != ">" && op != ">="
      return ""
    end
    len_nid = -1
    args_id = @nd_arguments[pred_nid]
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        len_nid = a[0]
      end
    end
    if op == ">" || op == ">="
      len_nid = @nd_receiver[pred_nid]
    end
    if len_nid < 0 || @nd_type[len_nid] != "CallNode"
      return ""
    end
    mn = @nd_name[len_nid]
    if mn != "length" && mn != "size"
      return ""
    end
    recv = @nd_receiver[len_nid]
    if recv < 0 || @nd_type[recv] != "LocalVariableReadNode"
      return ""
    end
    @nd_name[recv]
  end

  # Check if while condition uses .length/.size and hoist if safe.
  # Supports string, arrays, and hashes.
  def try_hoist_strlen(pred_nid)
    if @nd_type[pred_nid] != "CallNode"
      return ""
    end
    op = @nd_name[pred_nid]
    if op != "<" && op != "<=" && op != ">"  && op != ">="
      return ""
    end
    # Find the .length/.size call
    len_nid = -1
    args_id = @nd_arguments[pred_nid]
    if args_id >= 0
      a = get_args(args_id)
      if a.length > 0
        len_nid = a[0]
      end
    end
    # For > or >=, the length call may be on the receiver side
    if op == ">" || op == ">="
      len_nid = @nd_receiver[pred_nid]
    end
    if len_nid < 0
      return ""
    end
    if @nd_type[len_nid] != "CallNode"
      return ""
    end
    mn = @nd_name[len_nid]
    if mn != "length" && mn != "size"
      return ""
    end
    recv = @nd_receiver[len_nid]
    if recv < 0
      return ""
    end
    rt = infer_type(recv)
    # Must be a local variable so we can check for mutations in the body
    if @nd_type[recv] != "LocalVariableReadNode"
      # string literal or ivar: be conservative, only hoist string (already safe)
      if rt != "string"
        return ""
      end
      tmp = new_temp
      rc = compile_expr_gc_rooted(recv)
      emit("  mrb_int " + tmp + " = sp_str_length(" + rc + ");")
      @hoisted_strlen_recv = rc
      return tmp
    end
    len_c = length_c_expr(rt, "")
    if len_c == ""
      return ""
    end
    # Check that the loop body doesn't mutate this variable
    vname = @nd_name[recv]
    # (The pred_nid is the while predicate; body scan happens below via caller
    #  passing @while_body_nid.  Here we only check if type is hoistable.)
    tmp = new_temp
    rc = compile_expr_gc_rooted(recv)
    emit("  mrb_int " + tmp + " = " + length_c_expr(rt, rc) + ";")
    @hoisted_strlen_recv = rc
    tmp
  end

  def compile_while_stmt(nid)
    old = @in_loop
    @in_loop = 1
    # Save outer hoist state to restore on exit (support nested loops)
    saved_var = @hoisted_strlen_var
    saved_recv = @hoisted_strlen_recv
    # Try to hoist length from condition (string/array/hash).  Skip if the
    # loop body mutates the receiver variable (push/pop/<< etc.).
    len_tmp = ""
    can_hoist = 1
    hoist_target = hoist_receiver_var(@nd_predicate[nid])
    if hoist_target != ""
      if body_mutates_var?(@nd_body[nid], hoist_target) == 1
        can_hoist = 0
      end
    end
    if can_hoist == 1
      len_tmp = try_hoist_strlen(@nd_predicate[nid])
      if len_tmp != ""
        @hoisted_strlen_var = len_tmp
      end
    end
    # Prism PM_LOOP_FLAGS_BEGIN_MODIFIER (bit 0): `begin..end while cond`
    # is a post-test (do-while) loop — body runs at least once. Without
    # this, optcarrots `poke_4014` slow-path DMA never runs because
    # `data <<= 8` makes `data & 0xff == 0` initially, so the pre-test
    # while condition is false and the body is skipped.
    if (@nd_flags[nid] & 4) != 0
      emit("  do {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  } while (" + cond + ");")
    else
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  while (" + cond + ") {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      emit("  }")
    end
    @hoisted_strlen_var = saved_var
    @hoisted_strlen_recv = saved_recv
    @in_loop = old
  end

  def compile_until_stmt(nid)
    old = @in_loop
    @in_loop = 1
    if (@nd_flags[nid] & 4) != 0
      emit("  do {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  } while (!(" + cond + "));")
    else
      cond = compile_cond_expr(@nd_predicate[nid])
      emit("  while (!(" + cond + ")) {")
      @indent = @indent + 1
      redo_label = push_redo_label
      emit_redo_label(redo_label)
      compile_stmts_body(@nd_body[nid])
      pop_redo_label
      @indent = @indent - 1
      emit("  }")
    end
    @in_loop = old
  end

  def compile_for_stmt(nid)
    old = @in_loop
    @in_loop = 1
    coll = @nd_collection[nid]
    if coll >= 0
      vname = "i"
      tgt = @nd_target[nid]
      if tgt >= 0
        if @nd_type[tgt] == "LocalVariableTargetNode"
          vname = @nd_name[tgt]
        end
      end
      if @nd_type[coll] == "RangeNode"
        left = compile_expr(@nd_left[coll])
        right = compile_expr(@nd_right[coll])
        cmp = range_excl_end(coll) == 1 ? "<" : "<="
        emit("  for (lv_" + vname + " = " + left + "; lv_" + vname + " " + cmp + " " + right + "; lv_" + vname + "++) {")
        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      else
        # for x in array
        ct = infer_type(coll)
        rc = compile_expr(coll)
        tmp = new_temp
        pfx = array_c_prefix(ct)
        emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + rc + "); " + tmp + "++) {")
        # Loop-var assignment stays OUTSIDE the redo label so `redo` re-runs
        # the body with the same value (matches MRI: `redo` does not advance).
        emit("    lv_" + vname + " = sp_" + pfx + "_get(" + rc + ", " + tmp + ");")

        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[nid])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
      end
    end
    @in_loop = old
  end

  def compile_case_stmt(nid)
    pred = @nd_predicate[nid]
    if pred < 0
      compile_case_no_pred(nid)
      return
    end
    pred_type = infer_type(pred)
    pred_val = compile_expr(pred)
    tmp = new_temp
    if pred_type == "string"
      emit("  const char *" + tmp + " = " + pred_val + ";")
    elsif is_obj_type(pred_type) == 1
      # `case obj when ClassName` — keep the temp as the right pointer
      # type so the when arms can read its NULLability and the static
      # class match in compile_when_conds picks the matching cls_id
      # path. Issue #67.
      bt = base_type(pred_type)
      obj_cname = bt[4, bt.length - 4]
      emit("  sp_" + obj_cname + " *" + tmp + " = " + pred_val + ";")
    elsif pred_type == "poly"
      # `case <poly_value> when ...` — keep the receiver tagged so
      # each when-arm can do tag-check + value-compare. Issue #387.
      emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
    else
      emit("  mrb_int " + tmp + " = " + pred_val + ";")
    end
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      wid = conds[k]
      if @nd_type[wid] == "WhenNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        cond_str = compile_when_conds(wid, tmp, pred_type)
        emit("  " + kw + " (" + cond_str + ") {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[wid])
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

  def compile_case_no_pred(nid)
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      wid = conds[k]
      if @nd_type[wid] == "WhenNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        wconds = parse_id_list(@nd_conditions[wid])
        cexpr = "0"
        if wconds.length > 0
          cexpr = compile_expr(wconds.first)
        end
        emit("  " + kw + " (" + cexpr + ") {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[wid])
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    emit("  }")
  end

  def compile_when_conds(wid, tmp, pred_type)
    wconds = parse_id_list(@nd_conditions[wid])
    result = ""
    k = 0
    while k < wconds.length
      if k > 0
        result = result + " || "
      end
      cid = wconds[k]
      if @nd_type[cid] == "RangeNode"
        left = compile_expr(@nd_left[cid])
        right = compile_expr(@nd_right[cid])
        cmp = range_excl_end(cid) == 1 ? "<" : "<="
        result = result + "(" + tmp + " >= " + left + " && " + tmp + " " + cmp + " " + right + ")"
      elsif is_obj_type(pred_type) == 1 && @nd_type[cid] == "ConstantReadNode"
        # `case obj when ClassName` — resolve statically against the
        # predicate's known class. Predicate type `obj_X`:
        #   when X (or any ancestor of X)  → match (with a NULL guard
        #                                    when the predicate is
        #                                    nullable, since `nil` is
        #                                    not a class instance)
        #   when anything else             → no match
        # Subclass matching across an `obj_<Parent>` predicate that
        # actually carries an `obj_<Child>` instance needs a runtime
        # cls_id check; that's a separate enhancement (issue #67 only
        # covers the static-class form of the bug).
        cname = @nd_name[cid]
        if find_class_idx(cname) >= 0
          bt = base_type(pred_type)
          pred_cname = bt[4, bt.length - 4]
          if is_class_or_ancestor(pred_cname, cname) == 1
            if is_nullable_type(pred_type) == 1
              result = result + tmp + " != NULL"
            else
              result = result + "1"
            end
          else
            result = result + "0"
          end
        else
          result = result + "0"
        end
      else
        if pred_type == "poly"
          # `case <poly> when <lit>` — Issue #387. The pred_tmp is
          # an sp_RbVal; emit a tag-check + value-compare matched
          # to the literal's type. Class consts (`when Foo`) are
          # left for the future Class-object work; here we only
          # cover the value-literal arms (sym/str/int/float/nil).
          ct = @nd_type[cid]
          if ct == "SymbolNode"
            result = result + "(" + tmp + ".tag == SP_TAG_SYM && " + tmp + ".v.i == " + compile_expr(cid) + ")"
          elsif ct == "StringNode"
            result = result + "(" + tmp + ".tag == SP_TAG_STR && strcmp(" + tmp + ".v.s, " + compile_expr(cid) + ") == 0)"
          elsif ct == "IntegerNode"
            result = result + "(" + tmp + ".tag == SP_TAG_INT && " + tmp + ".v.i == " + compile_expr(cid) + ")"
          elsif ct == "FloatNode"
            result = result + "(" + tmp + ".tag == SP_TAG_FLT && " + tmp + ".v.f == " + compile_expr(cid) + ")"
          elsif ct == "NilNode"
            result = result + "(" + tmp + ".tag == SP_TAG_NIL)"
          elsif ct == "TrueNode"
            result = result + "(" + tmp + ".tag == SP_TAG_BOOL && " + tmp + ".v.b)"
          elsif ct == "FalseNode"
            result = result + "(" + tmp + ".tag == SP_TAG_BOOL && !" + tmp + ".v.b)"
          else
            # Fallback: unbox via sp_poly_eq (does the right thing for
            # numeric / string / sym pairs) and box the rhs.
            @needs_rb_value = 1
            result = result + "sp_poly_eq(" + tmp + ", " + box_expr_to_poly(cid) + ")"
          end
        elsif pred_type == "string"
          # `case <string> when :sym_literal` — CRuby's
          # `:sym === "str"` is always false (Symbol#=== returns
          # false for non-Symbol receivers), so emit a literal
          # 0 for this arm. Without the special-case
          # compile_expr(cid) returns `SPS_<sym>` (an sp_sym aka
          # long long) and strcmp would reject it.
          if @nd_type[cid] == "SymbolNode"
            result = result + "0"
          else
            result = result + "strcmp(" + tmp + ", " + compile_expr(cid) + ") == 0"
          end
        else
          # Symmetric case: `case <sym> when "literal_str"` is
          # also always false in CRuby (String#=== returns false
          # for a Symbol). Emit 0 to avoid a `mrb_int == const
          # char *` type mismatch in the generated C.
          if pred_type == "symbol" && @nd_type[cid] == "StringNode"
            result = result + "0"
          else
            result = result + tmp + " == " + compile_expr(cid)
          end
        end
      end
      k = k + 1
    end
    result
  end

  def compile_case_match_stmt(nid)
    pred = @nd_predicate[nid]
    pred_type = infer_type(pred)
    pred_val = compile_expr(pred)
    tmp = new_temp
    if pred_type == "poly"
      emit("  sp_RbVal " + tmp + " = " + pred_val + ";")
    else
      if pred_type == "string"
        emit("  const char *" + tmp + " = " + pred_val + ";")
      else
        if pred_type == "float"
          emit("  mrb_float " + tmp + " = " + pred_val + ";")
        else
          emit("  mrb_int " + tmp + " = " + pred_val + ";")
        end
      end
    end
    conds = parse_id_list(@nd_conditions[nid])
    k = 0
    while k < conds.length
      inid = conds[k]
      if @nd_type[inid] == "InNode"
        kw = "if"
        if k > 0
          kw = "} else if"
        end
        pat = @nd_pattern[inid]
        cond_str = compile_in_pattern(pat, tmp, pred_type)
        emit("  " + kw + " (" + cond_str + ") {")
        @indent = @indent + 1
        compile_stmts_body(@nd_body[inid])
        @indent = @indent - 1
      end
      k = k + 1
    end
    ec = @nd_else_clause[nid]
    if ec >= 0
      emit("  } else {")
      @indent = @indent + 1
      compile_stmts_body(@nd_body[ec])
      @indent = @indent - 1
    end
    if conds.length > 0
      emit("  }")
    end
  end

  def compile_in_pattern(pat_id, tmp, pred_type)
    if pat_id < 0
      return "1"
    end
    pt = @nd_type[pat_id]
    if pt == "ConstantReadNode"
      cname = @nd_name[pat_id]
      if pred_type == "poly"
        if cname == "Integer"
          return tmp + ".tag == SP_TAG_INT"
        end
        if cname == "String"
          return tmp + ".tag == SP_TAG_STR"
        end
        if cname == "Float"
          return tmp + ".tag == SP_TAG_FLT"
        end
        return "0"
      end
      if cname == "Integer"
        return "1"
      end
      if cname == "String"
        return "1"
      end
      if cname == "Float"
        return "1"
      end
      return "0"
    end
    if pt == "IntegerNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_INT && " + tmp + ".v.i == " + @nd_value[pat_id].to_s + ")"
      end
      return "#{tmp} == #{@nd_value[pat_id]}"
    end
    if pt == "StringNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_STR && strcmp(" + tmp + ".v.s, " + c_string_literal(@nd_content[pat_id]) + ") == 0)"
      end
      return "strcmp(" + tmp + ", " + c_string_literal(@nd_content[pat_id]) + ") == 0"
    end
    if pt == "NilNode"
      if pred_type == "poly"
        return tmp + ".tag == SP_TAG_NIL"
      end
      return tmp + " == 0"
    end
    if pt == "TrueNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_BOOL && " + tmp + ".v.b)"
      end
      return tmp + " != 0"
    end
    if pt == "FalseNode"
      if pred_type == "poly"
        return "(" + tmp + ".tag == SP_TAG_BOOL && !" + tmp + ".v.b)"
      end
      return tmp + " == 0"
    end
    if pt == "AlternationPatternNode"
      left = compile_in_pattern(@nd_left[pat_id], tmp, pred_type)
      right = compile_in_pattern(@nd_right[pat_id], tmp, pred_type)
      return "(" + left + " || " + right + ")"
    end
    "1"
  end

  def compile_return_stmt(nid)
    args_id = @nd_arguments[nid]
    if args_id >= 0
      arg_ids = get_args(args_id)
      if arg_ids.length > 1
        # `return a, b [, c]` — materialize as a fixed-arity tuple struct.
        @needs_gc = 1
        tt = tuple_type_from_elems(arg_ids)
        tname = tuple_c_name(tt)
        arr_tmp = new_temp
        emit("  " + tname + " *" + arr_tmp + " = (" + tname + " *)sp_gc_alloc(sizeof(" + tname + "), NULL, " + tuple_scan_name(tt) + ");")
        k = 0
        while k < arg_ids.length
          emit("  " + arr_tmp + "->_" + k.to_s + " = " + compile_expr(arg_ids[k]) + ";")
          k = k + 1
        end
        # Replay any in-scope `ensure` bodies before the return.
        # Ruby semantics: return value is already materialized, ensure
        # may mutate locals/ivars but does not affect the saved value.
        # `sp_exc_top -= N` undoes the setjmps we pushed; emit it once
        # before the replays so a nested `return` inside an ensure
        # body doesn't double-pop.
        emit_setjmp_depth_unwind
        emit_ensure_replays
        if @in_gc_scope == 1
          emit("  SP_GC_RESTORE();")
        end
        emit("  return " + arr_tmp + ";")
        return
      end
      if arg_ids.length > 0
        # `pre_return_unwind` = needs `sp_exc_top -= N;` and/or
        # ensure-body replays. When neither, we can leave the
        # original simple `return <expr>;` shape alone.
        pre_return_unwind = 0
        if @ensure_stack.length > 0
          pre_return_unwind = 1
        end
        if @setjmp_depth > 0
          pre_return_unwind = 1
        end
        if @current_method_return == "poly"
          ret_expr = box_expr_to_poly(arg_ids[0])
          if @in_gc_scope == 1
            tmp = new_temp
            emit("  sp_RbVal " + tmp + " = " + ret_expr + ";")
            emit_setjmp_depth_unwind
            emit_ensure_replays
            emit("  SP_GC_RESTORE();")
            emit("  return " + tmp + ";")
          else
            if pre_return_unwind == 1
              tmp = new_temp
              emit("  sp_RbVal " + tmp + " = " + ret_expr + ";")
              emit_setjmp_depth_unwind
              emit_ensure_replays
              emit("  return " + tmp + ";")
            else
              emit("  return " + ret_expr + ";")
            end
          end
          return
        end
        rt = infer_type(arg_ids[0])
        # return nil in a nullable pointer method → return NULL
        if rt == "nil" && is_nullable_pointer_type(@current_method_return) == 1
          emit_setjmp_depth_unwind
          emit_ensure_replays
          if @in_gc_scope == 1
            emit("  SP_GC_RESTORE();")
          end
          emit("  return NULL;")
          return
        end
        if @in_gc_scope == 1
          # Save return value, run ensure replays (which may mutate
          # ivars/locals), restore GC, then return the saved value.
          tmp = new_temp
          emit("  " + c_type(rt) + " " + tmp + " = " + compile_expr(arg_ids[0]) + ";")
          emit_setjmp_depth_unwind
          emit_ensure_replays
          emit("  SP_GC_RESTORE();")
          emit("  return " + tmp + ";")
        else
          if pre_return_unwind == 1
            tmp = new_temp
            emit("  " + c_type(rt) + " " + tmp + " = " + compile_expr(arg_ids[0]) + ";")
            emit_setjmp_depth_unwind
            emit_ensure_replays
            emit("  return " + tmp + ";")
          else
            emit("  return " + compile_expr(arg_ids[0]) + ";")
          end
        end
        return
      end
    end
    # bare return — emit shape depends on the enclosing function's
    # C return type:
    #   void              → return;
    #   poly              → return sp_box_nil();    (boxed nil)
    #   obj_<C>           → return self;            (constructor
    #                                                synthesis path
    #                                                with self in
    #                                                scope)
    #   nullable pointer  → return NULL;
    #   anything else     → return 0;
    # The shape per @current_method_return matters because a
    # `return if x.nil?` inside an `sp_RbVal`-returning method
    # would otherwise emit `return 0;` (int) into a poly slot,
    # and the same bare-return inside a `def initialize` reaches
    # the constructor-synthesis branch where `return 0;` would
    # silently NULL the instance.
    emit_setjmp_depth_unwind
    emit_ensure_replays
    if @in_gc_scope == 1
      emit("  SP_GC_RESTORE();")
    end
    if @current_method_return == "void"
      emit("  return;")
    elsif @current_method_return == "poly"
      @needs_rb_value = 1
      emit("  return sp_box_nil();")
    elsif is_obj_type(@current_method_return) == 1
      # `self` is in C scope only when the wrapping function has a
      # self binding — instance methods and constructor synthesis.
      # Class methods, module class methods, and top-level free
      # functions don't have self; their bare returns fall through
      # to `c_return_default` (value-type classes get
      # `(sp_<C>){0}`, pointer-typed obj returns get NULL).
      if @current_method_has_self == 1
        emit("  return self;")
      else
        emit("  return " + c_return_default(@current_method_return) + ";")
      end
    elsif is_nullable_pointer_type(@current_method_return) == 1
      emit("  return NULL;")
    else
      emit("  return 0;")
    end
  end


  def compile_call_stmt(nid)
    mname = @nd_name[nid]
    recv = @nd_receiver[nid]

    # define_method is handled at collection time, skip at runtime
    if mname == "define_method"
      return
    end

    # `Module.accessor = X` write.
    #   Stage 1 (1 candidate): no emit; reads fold to that constant.
    #   Stage 2 (2+ candidates): emit `slot = SP_MOD_<X>;` so the
    #   read site's sentinel switch picks the right branch.
    if mname.length > 1 && mname[mname.length - 1] == "=" && recv >= 0 && @nd_type[recv] == "ConstantReadNode"
      mod_name = @nd_name[recv]
      if module_name_exists(mod_name) == 1
        accessor = mname[0, mname.length - 1]
        rconsts = module_acc_resolved(mod_name, accessor)
        if rconsts != "" && rconsts != "?"
          cands = rconsts.split(";")
          if cands.length == 1
            return
          end
          # Stage 2: write the sentinel for the assigned module.
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            ai = get_args(args_id2)
            if ai.length > 0 && @nd_type[ai[0]] == "ConstantReadNode"
              rhs = @nd_name[ai[0]]
              slot = "sp_module_" + mod_name + "_" + sanitize_name(accessor)
              emit("  " + slot + " = " + module_sentinel(rhs).to_s + ";")
              return
            end
          end
        end
      end
    end

    # Hoisted instance_eval block (statement context): the lifted
    # function returns void, so emit it as a plain statement.
    if is_ieval_call_name(mname) == 1
      emit("  " + compile_ieval_call(nid) + ";")
      return
    end

    # IO: puts, print, printf
    if compile_io_call_stmt(nid, mname, recv) == 1
      return
    end

    # File.open with block
    if compile_file_open_call_stmt(nid, mname, recv) == 1
      return
    end

    # Mutating operations: []=, delete, <<, replace, clear, push, reverse!, sort!
    if compile_mutating_call_stmt(nid, mname, recv) == 1
      return
    end

    # Block iteration: each, times, upto, downto, loop, reduce, inject, reject
    if compile_block_iteration_stmt(nid, mname, recv) == 1
      return
    end

    # Control flow: raise, system, trap, catch, throw, File ops, exit
    if compile_control_call_stmt(nid, mname, recv) == 1
      return
    end

    # attr_writer, map, select, yield method calls
    if compile_writer_and_block_call_stmt(nid, mname, recv) == 1
      return
    end

    # General
    val = compile_expr(nid)
    if val != "0"
      emit("  " + val + ";")
    end
  end

  def compile_io_call_stmt(nid, mname, recv)
    if mname == "puts"
      if recv < 0
        compile_puts(nid)
        return 1
      end
      if recv >= 0
        if @nd_type[recv] == "GlobalVariableReadNode"
          if @nd_name[recv] == "$stderr"
            compile_stderr_puts(nid)
            return 1
          end
        end
      end
    end
    # $stdout.flush / $stderr.flush / STDOUT.flush / STDERR.flush.
    # Important on Windows where stdio is fully-buffered when stdout
    # is a pipe — without an explicit flush, output written via puts
    # before a `system(...)` call appears after the child process's
    # output. The expression-context system path already emits
    # fflush(stdout) implicitly; this lets user code do the same
    # explicitly.
    if mname == "flush" && recv >= 0
      stream = ""
      if @nd_type[recv] == "GlobalVariableReadNode"
        if @nd_name[recv] == "$stdout"
          stream = "stdout"
        elsif @nd_name[recv] == "$stderr"
          stream = "stderr"
        end
      elsif @nd_type[recv] == "ConstantReadNode"
        if @nd_name[recv] == "STDOUT"
          stream = "stdout"
        elsif @nd_name[recv] == "STDERR"
          stream = "stderr"
        end
      end
      if stream != ""
        emit("  fflush(" + stream + ");")
        return 1
      end
    end
    if mname == "print"
      if recv < 0
        compile_print(nid)
        return 1
      end
    end
    if mname == "printf"
      if recv < 0
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length >= 1
            # First arg is format string
            fmt_expr = compile_expr(arg_ids[0])
            rest_args = ""
            k = 1
            while k < arg_ids.length
              at = infer_type(arg_ids[k])
              if at == "int"
                rest_args = rest_args + ", (int)" + compile_expr(arg_ids[k])
              else
                rest_args = rest_args + ", " + compile_expr(arg_ids[k])
              end
              k = k + 1
            end
            emit("  printf(" + fmt_expr + rest_args + ");")
            return 1
          end
        end
      end
    end
    0
  end

  def compile_file_open_call_stmt(nid, mname, recv)
    # File.open with block
    if mname == "open"
      if recv >= 0
        if @nd_type[recv] == "ConstantReadNode"
          if @nd_name[recv] == "File"
            if @nd_block[nid] >= 0
              args_id = @nd_arguments[nid]
              path_expr = "\"\""
              mode_expr = "\"r\""
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  path_expr = compile_expr(arg_ids[0])
                end
                if arg_ids.length >= 2
                  mode_expr = compile_expr(arg_ids[1])
                end
              end
              blk = @nd_block[nid]
              bp = get_block_param(nid, 0)
              ftmp = new_temp
              emit("  { FILE *" + ftmp + " = fopen(" + path_expr + ", " + mode_expr + ");")
              emit("  if (" + ftmp + ") {")
              # Compile block body -- f.puts => fprintf, f.each_line => fgets loop
              bbody = @nd_body[blk]
              if bbody >= 0
                bstmts = get_stmts(bbody)
                bk = 0
                while bk < bstmts.length
                  compile_file_block_stmt(bstmts[bk], ftmp, bp)
                  bk = bk + 1
                end
              end
              emit("  fclose(" + ftmp + ");")
              emit("  } }")
              return 1
            end
          end
        end
      end
    end
    0
  end

  def compile_mutating_call_stmt(nid, mname, recv)
    # []=
    if mname == "[]="
      if recv >= 0
        compile_bracket_assign(nid)
        return 1
      end
    end

    # store (Hash): equivalent to []=
    if mname == "store"
      if recv >= 0
        rt = infer_type(recv)
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length >= 2
            rc = compile_expr_gc_rooted(recv)
            val = compile_expr(aargs[1])
            if rt == "sym_int_hash"
              emit("  sp_SymIntHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            if rt == "sym_str_hash"
              emit("  sp_SymStrHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            if rt == "int_str_hash"
              emit("  sp_IntStrHash_set(" + rc + ", " + compile_expr(aargs[0]) + ", " + val + ");")
              return 1
            end
            key = compile_expr_as_string(aargs[0])
            if rt == "str_int_hash"
              emit("  sp_StrIntHash_set(" + rc + ", " + key + ", " + val + ");")
              return 1
            end
            if rt == "str_str_hash"
              emit("  sp_StrStrHash_set(" + rc + ", " + key + ", " + val + ");")
              return 1
            end
          end
        end
      end
    end

    # delete
    if mname == "delete"
      if recv >= 0
        rt = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        if rt == "sym_int_hash"
          emit("  sp_SymIntHash_delete(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "sym_str_hash"
          emit("  sp_SymStrHash_delete(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_int_hash"
          emit("  sp_StrIntHash_delete(" + rc + ", " + compile_str_arg0(nid) + ");")
          return 1
        end
        if rt == "str_str_hash"
          emit("  sp_StrStrHash_delete(" + rc + ", " + compile_str_arg0(nid) + ");")
          return 1
        end
        if rt == "int_array"
          emit("  sp_IntArray_delete(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_array"
          emit("  sp_StrArray_delete(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

    # << on string (mutating append)
    if mname == "<<"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          arg_id = @nd_arguments[nid]
          if arg_id >= 0
            argl = parse_id_list(@nd_args[arg_id])
            if argl.length > 0
              at = infer_type(argl[0])
              val = compile_expr(argl[0])
              if at == "int"
                emit("  sp_String_append(" + rc + ", sp_int_to_s(" + val + "));")
              else
                if at == "mutable_str"
                  emit("  sp_String_append(" + rc + ", " + val + "->data);")
                else
                  if at == "poly"
                    # A poly-typed source (e.g. a module method
                    # returning sp_RbVal from a SymPolyHash read)
                    # needs runtime unbox to const char * before
                    # sp_String_append. sp_poly_to_s handles
                    # every tag.
                    emit("  sp_String_append(" + rc + ", sp_poly_to_s(" + val + "));")
                  else
                    emit("  sp_String_append(" + rc + ", " + val + ");")
                  end
                end
              end
            end
          end
          return 1
        end
        if rt == "string"
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
          # If receiver is a local variable, reassign
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = sp_str_concat(lv_" + @nd_name[recv] + ", " + val + ");")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = sp_str_concat(self->" + sanitize_ivar(@nd_name[recv]) + ", " + val + ");")
            return 1
          end
        end
      end
    end

    # << on array (same as push)
    if mname == "<<"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          av = compile_arg0(nid)
          a0id = -1
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            aargs2 = get_args(args_id2)
            if aargs2.length > 0
              a0id = aargs2[0]
            end
          end
          if a0id >= 0
            if infer_type(a0id) == "lambda"
              av = "(mrb_int)" + av
            end
          end
          emit("  sp_IntArray_push(" + rc + ", " + av + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_PtrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "poly_array"
          rc = compile_expr_gc_rooted(recv)
          args_id3 = @nd_arguments[nid]
          if args_id3 >= 0
            aa = get_args(args_id3)
            if aa.length > 0
              vt = infer_type(aa[0])
              vexpr = compile_expr(aa[0])
              if vt != "poly"
                vexpr = box_value_to_poly(vt, vexpr)
              end
              emit("  sp_PolyArray_push(" + rc + ", " + vexpr + ");")
              return 1
            end
          end
        end
      end
    end

    # update / merge! on hash (mutating merge)
    if mname == "update" || mname == "merge!"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "str_int_hash"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrIntHash_update(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_str_hash"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrStrHash_update(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

    # concat on array (mutating append)
    if mname == "concat"
      if recv >= 0
        rt = infer_type(recv)
        if is_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          arg = compile_arg0(nid)
          pfx = array_c_prefix(rt)
          tmp = new_temp
          emit("  for (mrb_int " + tmp + " = 0; " + tmp + " < sp_" + pfx + "_length(" + arg + "); " + tmp + "++)")
          emit("    sp_" + pfx + "_push(" + rc + ", sp_" + pfx + "_get(" + arg + ", " + tmp + "));")
          return 1
        end
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            ak = 0
            while ak < aargs.length
              emit("  sp_String_append(" + rc + ", " + compile_expr(aargs[ak]) + ");")
              ak = ak + 1
            end
          end
          return 1
        end
      end
    end

    # replace on string (mutating reassign)
    if mname == "replace"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
          emit("  " + rc + "->len = 0; " + rc + "->data[0] = 0; sp_String_append(" + rc + ", " + val + ");")
          return 1
        end
        if rt == "string"
          val = compile_arg0(nid)
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = " + val + ";")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = " + val + ";")
            return 1
          end
        end
        if rt == "int_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_replace(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

    # prepend on mutable_str (mutating prepend)
    if mname == "prepend"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          @needs_mutable_str = 1
          rc = compile_expr_gc_rooted(recv)
          val = compile_arg0(nid)
          emit("  sp_String_prepend(" + rc + ", " + val + ");")
          return 1
        end
      end
    end

    # clear on string (set to empty)
    if mname == "clear"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0; " + rc + "->data[0] = 0;")
          return 1
        end
        if rt == "string"
          if @nd_type[recv] == "LocalVariableReadNode"
            emit("  lv_" + @nd_name[recv] + " = \"\";")
            return 1
          end
          if @nd_type[recv] == "InstanceVariableReadNode"
            emit("  " + self_arrow + sanitize_ivar(@nd_name[recv]) + " = \"\";")
            return 1
          end
        end
        # Typed array Array#clear — zero the length (and start
        # for IntArray, which uses a sliding window). Capacity
        # and the backing buffer stay; subsequent pushes refill
        # the slots from index 0.
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0; " + rc + "->start = 0;")
          return 1
        end
        if rt == "float_array" || rt == "poly_array" || is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  " + rc + "->len = 0;")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          # StrArray has an inline-storage optimization: data may
          # point to inline_data (small) or a malloc'd buffer.
          # Either way, zeroing len is a clean reset — the next
          # push refills from index 0.
          emit("  " + rc + "->len = 0;")
          return 1
        end
      end
    end

    # push
    if mname == "push"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array" || rt == "sym_array"
          rc = compile_expr_gc_rooted(recv)
          av = compile_arg0(nid)
          # If pushing a lambda value, cast to mrb_int
          a0id = -1
          args_id2 = @nd_arguments[nid]
          if args_id2 >= 0
            aargs2 = get_args(args_id2)
            if aargs2.length > 0
              a0id = aargs2[0]
            end
          end
          if a0id >= 0
            if infer_type(a0id) == "lambda"
              av = "(mrb_int)" + av
            end
          end
          emit("  sp_IntArray_push(" + rc + ", " + av + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
        if is_ptr_array_type(rt) == 1
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_PtrArray_push(" + rc + ", " + compile_arg0(nid) + ");")
          return 1
        end
      end
    end

    # rotate!(n) — defaults to n=1 like Ruby.
    if mname == "rotate!"
      if recv >= 0
        rt = infer_type(recv)
        rot_pfx = ""
        if rt == "int_array" || rt == "sym_array"
          rot_pfx = "IntArray"
        end
        if rt == "float_array"
          rot_pfx = "FloatArray"
        end
        if rt == "str_array"
          rot_pfx = "StrArray"
        end
        if is_ptr_array_type(rt) == 1
          rot_pfx = "PtrArray"
        end
        if rt == "poly_array"
          rot_pfx = "PolyArray"
        end
        if rot_pfx != ""
          args_id = @nd_arguments[nid]
          n_expr = "1"
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              n_expr = compile_expr(aargs[0])
            end
          end
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_" + rot_pfx + "_rotate_bang(" + rc + ", " + n_expr + ");")
          return 1
        end
      end
    end

    # reverse! / sort!
    if mname == "reverse!"
      if recv >= 0
        rt = infer_type(recv)
        rev_pfx = ""
        if rt == "int_array" || rt == "sym_array"
          rev_pfx = "IntArray"
        end
        if rt == "str_array"
          rev_pfx = "StrArray"
        end
        if rt == "float_array"
          rev_pfx = "FloatArray"
        end
        if is_ptr_array_type(rt) == 1
          rev_pfx = "PtrArray"
        end
        if rev_pfx != ""
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_" + rev_pfx + "_reverse_bang(" + rc + ");")
          return 1
        end
      end
    end
    if mname == "sort!"
      if recv >= 0
        rt = infer_type(recv)
        if rt == "int_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_IntArray_sort_bang(" + rc + ");")
          return 1
        end
        if rt == "sym_array"
          # sym sort compares by symbol name, not numeric ID
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_sym_array_sort(" + rc + ");")
          return 1
        end
        if rt == "str_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_StrArray_sort_bang(" + rc + ");")
          return 1
        end
        if rt == "float_array"
          rc = compile_expr_gc_rooted(recv)
          emit("  sp_FloatArray_sort_bang(" + rc + ");")
          return 1
        end
      end
    end
    0
  end

  def compile_block_iteration_stmt(nid, mname, recv)
    # each with block
    if mname == "each" || (mname == "each_pair" && recv >= 0)
      if @nd_block[nid] >= 0
        # For object types with yield-using each, use yield method call
        if recv >= 0
          ert = infer_type(recv)
          if is_obj_type(ert) == 1 && is_ptr_array_type(ert) == 0
            # Fall through to yield method handler below
          else
            compile_each_block(nid)
            return 1
          end
        else
          compile_each_block(nid)
          return 1
        end
      end
    end

    if mname == "each_with_index"
      if @nd_block[nid] >= 0
        compile_each_with_index_block(nid)
        return 1
      end
    end

    # `hash.each_value { |v| ... }` for poly_poly_hash. Other hash
    # shapes can be added here once they surface; the underlying
    # representation is the same `vals[order[i]]` walk.
    if mname == "each_value" && recv >= 0 && @nd_block[nid] >= 0
      rt_ev = infer_type(recv)
      if rt_ev == "poly_poly_hash"
        rc_ev = compile_expr_gc_rooted(recv)
        bp_ev = get_block_param(nid, 0)
        has_bp_ev = 1
        if bp_ev == ""
          has_bp_ev = 0
          bp_ev = "_v"
        end
        tmp_ev = new_temp
        emit("  for (mrb_int " + tmp_ev + " = 0; " + tmp_ev + " < " + rc_ev + "->len; " + tmp_ev + "++) {")
        if has_bp_ev == 1
          emit("    sp_RbVal lv_" + bp_ev + " = " + rc_ev + "->vals[" + rc_ev + "->order[" + tmp_ev + "]];")
        end
        @indent = @indent + 1
        push_scope
        if has_bp_ev == 1
          declare_var(bp_ev, "poly")
        end
        redo_label_ev = push_redo_label
        emit_redo_label(redo_label_ev)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        return 1
      end
    end

    if mname == "each_slice"
      if @nd_block[nid] >= 0
        compile_each_slice_block(nid)
        return 1
      end
    end

    if mname == "each_char"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_c"
          end
          tmp = new_temp
          src = rc
          if rt == "mutable_str"
            src = rc + "->data"
          end
          src_tmp = new_temp
          cn_tmp = new_temp
          char_buf = new_temp
          emit("  const char *" + src_tmp + " = " + src + ";")
          emit("  for (mrb_int " + tmp + " = 0; " + src_tmp + "[" + tmp + "]; ) {")
          emit("    int " + cn_tmp + " = sp_utf8_advance(" + src_tmp + " + " + tmp + ");")
          emit("    char *" + char_buf + " = sp_str_alloc_raw(" + cn_tmp + " + 1);")
          emit("    memcpy(" + char_buf + ", " + src_tmp + " + " + tmp + ", " + cn_tmp + ");")
          emit("    " + char_buf + "[" + cn_tmp + "] = 0;")
          emit("    const char *lv_" + bp + " = " + char_buf + ";")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "string")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("    " + tmp + " += " + cn_tmp + ";")
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_byte"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_b"
          end
          tmp = new_temp
          src = rc
          if rt == "mutable_str"
            src = rc + "->data"
          end
          src_tmp = new_temp
          emit("  const char *" + src_tmp + " = " + src + ";")
          emit("  for (mrb_int " + tmp + " = 0; " + src_tmp + "[" + tmp + "]; " + tmp + "++) {")
          emit("    mrb_int lv_" + bp + " = (unsigned char)" + src_tmp + "[" + tmp + "];")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "int")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_line"
      if @nd_block[nid] >= 0 && recv >= 0
        rt = infer_type(recv)
        if rt == "string" || rt == "mutable_str"
          rc = compile_expr_gc_rooted(recv)
          bp = get_block_param(nid, 0)
          if bp == ""
            bp = "_l"
          end
          @needs_str_array = 1
          tmp_arr = new_temp
          tmp_i = new_temp
          src = rc
          if rt == "mutable_str"
            src = rc + "->data"
          end
          emit("  sp_StrArray *" + tmp_arr + " = sp_str_split(" + src + ", \"\\n\");")
          emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < " + tmp_arr + "->len; " + tmp_i + "++) {")
          emit("    const char *lv_" + bp + " = " + tmp_arr + "->data[" + tmp_i + "];")
          @indent = @indent + 1
          push_scope
          declare_var(bp, "string")
          compile_stmts_body(@nd_body[@nd_block[nid]])
          pop_scope
          @indent = @indent - 1
          emit("  }")
          return 1
        end
      end
    end

    if mname == "each_cons"
      if @nd_block[nid] >= 0
        compile_each_cons_block(nid)
        return 1
      end
    end

    if mname == "each_with_object"
      if @nd_block[nid] >= 0 && recv >= 0
        compile_each_with_object_block(nid)
        return 1
      end
    end

    if mname == "zip"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        rt = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        arg = compile_arg0(nid)
        bp1 = get_block_param(nid, 0)
        bp2 = get_block_param(nid, 1)
        if bp1 == ""
          bp1 = "_a"
        end
        if bp2 == ""
          bp2 = "_b"
        end
        pfx = array_c_prefix(rt)
        elem_t = elem_type_of_array(rt)
        et = c_type(elem_t)
        tmp_i = new_temp
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++) {")
        emit("    " + et + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + ");")
        emit("    " + et + " lv_" + bp2 + " = sp_" + pfx + "_get(" + arg + ", " + tmp_i + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp1, elem_t)
        declare_var(bp2, elem_t)
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end

    if mname == "step"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        rc = compile_expr_gc_rooted(recv)
        args_id = @nd_arguments[nid]
        limit_val = "0"
        step_val = "1"
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            limit_val = compile_expr(aargs[0])
          end
          if aargs.length > 1
            step_val = compile_expr(aargs[1])
          end
        end
        bp1 = get_block_param(nid, 0)
        synth = 0
        if bp1 == ""
          bp1 = "_i"
          synth = 1
        end
        # When the block omits its parameter, the synthesized `_i` isn't
        # declared anywhere — wrap the loop in a block scope and declare
        # it locally. This also avoids redefinition errors when multiple
        # paramless `step` blocks appear in the same function.
        if synth == 1
          emit("  {")
          emit("  mrb_int lv_" + bp1 + " = 0;")
        end
        emit("  for (lv_" + bp1 + " = " + rc + "; lv_" + bp1 + " <= " + limit_val + "; lv_" + bp1 + " += " + step_val + ") {")
        @indent = @indent + 1
        push_scope
        declare_var(bp1, "int")
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        if synth == 1
          emit("  }")
        end
        @in_loop = old
        return 1
      end
    end

    if mname == "cycle"
      if @nd_block[nid] >= 0 && recv >= 0
        old = @in_loop
        @in_loop = 1
        rt = infer_type(recv)
        rc = compile_expr_gc_rooted(recv)
        n = compile_arg0(nid)
        bp1 = get_block_param(nid, 0)
        if bp1 == ""
          bp1 = "_x"
        end
        pfx = array_c_prefix(rt)
        et = elem_type_of_array(rt)
        tmp_c = new_temp
        tmp_i = new_temp
        emit("  for (mrb_int " + tmp_c + " = 0; " + tmp_c + " < " + n + "; " + tmp_c + "++)")
        emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < sp_" + pfx + "_length(" + rc + "); " + tmp_i + "++) {")
        emit("    " + c_type(et) + " lv_" + bp1 + " = sp_" + pfx + "_get(" + rc + ", " + tmp_i + ");")
        @indent = @indent + 1
        push_scope
        declare_var(bp1, et)
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        pop_scope
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end

    # scan with block: str.scan(/re/) { |m| ... }
    if mname == "scan"
      if @nd_block[nid] >= 0
        recv = @nd_receiver[nid]
        if recv >= 0
          args_id = @nd_arguments[nid]
          if args_id >= 0
            argl = get_args(args_id)
            if argl.length > 0
              ridx = find_regexp_index(argl[0])
              if ridx >= 0
                @needs_str_array = 1
                rc = compile_expr_gc_rooted(recv)
                bp = get_block_param(nid, 0)
                if bp == ""
                  bp = "_m"
                end
                tmp_arr = new_temp
                tmp_i = new_temp
                emit("  sp_StrArray *" + tmp_arr + " = sp_re_scan(sp_re_pat_" + ridx.to_s + ", " + rc + ");")
                emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < " + tmp_arr + "->len; " + tmp_i + "++) {")
                emit("    const char *lv_" + bp + " = " + tmp_arr + "->data[" + tmp_i + "];")
                push_scope
                declare_var(bp, "string")
                blk = @nd_block[nid]
                if @nd_body[blk] >= 0
                  compile_stmts_body(@nd_body[blk])
                end
                pop_scope
                emit("  }")
                return 1
              end
            end
          end
        end
      end
    end

    # times/upto/downto with block
    if mname == "times"
      if @nd_block[nid] >= 0
        compile_times_block(nid)
        return 1
      end
    end
    if mname == "upto"
      if @nd_block[nid] >= 0
        compile_upto_block(nid)
        return 1
      end
    end
    if mname == "downto"
      if @nd_block[nid] >= 0
        compile_downto_block(nid)
        return 1
      end
    end

    # reduce/inject
    if mname == "reduce"
      if @nd_block[nid] >= 0
        compile_reduce_block(nid)
        return 1
      end
    end
    if mname == "inject"
      if @nd_block[nid] >= 0
        compile_reduce_block(nid)
        return 1
      end
    end

    # reject
    if mname == "reject"
      if @nd_block[nid] >= 0
        compile_reject_block(nid)
        return 1
      end
    end

    # loop
    if mname == "loop"
      if @nd_block[nid] >= 0
        old = @in_loop
        @in_loop = 1
        emit("  while (1) {")
        @indent = @indent + 1
        redo_label = push_redo_label
        emit_redo_label(redo_label)
        compile_stmts_body(@nd_body[@nd_block[nid]])
        pop_redo_label
        @indent = @indent - 1
        emit("  }")
        @in_loop = old
        return 1
      end
    end
    0
  end

  def compile_control_call_stmt(nid, mname, recv)
    # raise
    if mname == "raise"
      if recv < 0
        @needs_setjmp = 1
        args_id = @nd_arguments[nid]
        if args_id >= 0
          arg_ids = get_args(args_id)
          if arg_ids.length >= 2
            # raise ClassName, "message" - use the message with class
            if @nd_type[arg_ids[0]] == "ConstantReadNode"
              emit("  sp_raise_cls(\"" + @nd_name[arg_ids[0]] + "\", " + compile_expr(arg_ids[1]) + ");")
            else
              emit("  sp_raise(" + compile_expr(arg_ids[1]) + ");")
            end
          else
            if arg_ids.length == 1
              # raise "message" or raise ClassName
              if @nd_type[arg_ids[0]] == "ConstantReadNode"
                emit("  sp_raise(\"" + @nd_name[arg_ids[0]] + "\");")
              else
                emit("  sp_raise(" + compile_expr(arg_ids[0]) + ");")
              end
            else
              emit_bare_raise
            end
          end
        else
          emit_bare_raise
        end
        return 1
      end
    end

    # system
    if mname == "system"
      if recv < 0
        emit("  fflush(stdout);")
        emit("  sp_last_status = system(" + compile_arg0(nid) + ");")
        return 1
      end
    end

    # trap (just ignore)
    if mname == "trap"
      if recv < 0
        return 1
      end
    end

    # catch/throw
    if mname == "catch"
      if recv < 0
        if @nd_block[nid] >= 0
          compile_catch_stmt(nid)
          return 1
        end
      end
    end
    if mname == "throw"
      if recv < 0
        compile_throw_stmt(nid)
        return 1
      end
    end

    # File operations
    if recv >= 0
      if @nd_type[recv] == "ConstantReadNode"
        rcname = @nd_name[recv]
        if rcname == "File"
          if mname == "write"
            args_id = @nd_arguments[nid]
            arg_ids = []
            if args_id >= 0
              arg_ids = get_args(args_id)
            end
            a0 = "0"
            a1 = "0"
            if arg_ids.length >= 1
              a0 = compile_expr(arg_ids[0])
            end
            if arg_ids.length >= 2
              a1 = compile_expr(arg_ids[1])
            end
            emit("  sp_file_write(" + a0 + ", " + a1 + ");")
            return 1
          end
          if mname == "delete"
            emit("  sp_file_delete(" + compile_arg0(nid) + ");")
            return 1
          end
        end
      end
    end

    # exit
    if mname == "exit"
      if recv < 0
        val = compile_arg0(nid)
        emit("  exit(" + val + ");")
        return 1
      end
    end

    # abort — print message to stderr and exit(1)
    if mname == "abort"
      if recv < 0
        args_id = @nd_arguments[nid]
        if args_id >= 0
          aargs = get_args(args_id)
          if aargs.length > 0
            msg = compile_expr(aargs[0])
            emit("  fputs(" + msg + ", stderr); fputc('\\n', stderr);")
          end
        end
        emit("  exit(1);")
        return 1
      end
    end
    0
  end

  def compile_writer_and_block_call_stmt(nid, mname, recv)
    # attr_writer: obj.x = val — only short-circuit to a direct field
    # write when `x=` is actually a registered attr_writer on the class
    # (or transitive parent). Otherwise fall through to method-call
    # dispatch so a real `def x=(v)` method gets called.
    if recv >= 0
      if mname.length > 1
        if mname[mname.length - 1] == "="
          bname = mname[0, mname.length - 1]
          rt = infer_type(recv)
          if is_obj_type(rt) == 1
            r_cname = rt[4, rt.length - 4]
            r_ci = find_class_idx(r_cname)
            is_writer = 0
            if r_ci >= 0
              is_writer = cls_has_attr_writer(r_ci, bname)
            end
            if is_writer == 1
              rc = compile_expr_gc_rooted(recv)
              arrow2 = "->"
              if is_value_type_obj(rt) == 1
                arrow2 = "."
              end
              # Box rhs when the slot is poly, same as the
              # expression-form attr_writer above.
              slot_t = cls_ivar_type(r_ci, "@" + bname)
              arg0_w = compile_arg0(nid)
              if slot_t == "poly"
                args_id_w = @nd_arguments[nid]
                arg_t = "int"
                if args_id_w >= 0
                  arg_ids_w = get_args(args_id_w)
                  if arg_ids_w.length > 0
                    arg_t = infer_type(arg_ids_w[0])
                  end
                end
                arg0_w = box_value_to_poly(arg_t, arg0_w)
              end
              emit("  " + rc + arrow2 + sanitize_ivar(bname) + " = " + arg0_w + ";")
              return 1
            end
          end
        end
      end
    end

    # map with block
    if mname == "map"
      if @nd_block[nid] >= 0
        compile_map_block(nid)
        return 1
      end
    end

    # select with block
    if mname == "select"
      if @nd_block[nid] >= 0
        compile_select_block(nid)
        return 1
      end
    end

    # User-defined yield function or instance_eval trampoline, called
    # with a literal block. (A `&proc_var` forward at the call site
    # doesn't trigger inlining — those flow through compile_call_expr's
    # regular block-forwarding path.)
    if has_literal_block(nid) == 1
      if recv < 0
        mi = find_method_idx(mname)
        if mi >= 0
          if @meth_has_yield[mi] == 1
            compile_yield_call_stmt(nid, mi)
            return 1
          end
        end
        # Bare `m { ... }` inside another method body of the same
        # class — `m` is a sibling instance method, lookup happens on
        # @current_class_idx (and its ancestors). compile_yield_method
        # _call_stmt synthesizes `self` for rc when recv < 0.
        if @current_class_idx >= 0
          ci_self = @current_class_idx
          if try_yield_or_trampoline_dispatch(nid, recv, ci_self, mname) == 1
            return 1
          end
          pwalk = ci_self
          while @cls_parents[pwalk] != ""
            pci = find_class_idx(@cls_parents[pwalk])
            if pci < 0
              break
            end
            if try_yield_or_trampoline_dispatch(nid, recv, pci, mname) == 1
              return 1
            end
            pwalk = pci
          end
        end
      end
      # Class method with yield, or an arity-0 instance_eval trampoline.
      # The direct-class and parent-class lookups share the same dispatch
      # shape (find midx, check yield, check trampoline); collapsed into
      # try_yield_or_trampoline_dispatch.
      if recv >= 0
        rtype = infer_type(recv)
        if is_obj_type(rtype) == 1
          cn = rtype[4, rtype.length - 4]
          cci = find_class_idx(cn)
          if cci >= 0
            if try_yield_or_trampoline_dispatch(nid, recv, cci, mname) == 1
              return 1
            end
            if @cls_parents[cci] != ""
              pci = find_class_idx(@cls_parents[cci])
              if pci >= 0
                if try_yield_or_trampoline_dispatch(nid, recv, pci, mname) == 1
                  return 1
                end
              end
            end
          end
        end
      end
    end
    0
  end


  def compile_file_block_stmt(nid, ftmp, bp)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "CallNode"
      mn = @nd_name[nid]
      r = @nd_receiver[nid]
      # f.puts "text"
      if mn == "puts"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fprintf(" + ftmp + ", \"%s" + bsl_n + "\", " + compile_expr(arg_ids[0]) + ");")
                  return
                end
              end
              emit("  fputc('" + bsl_n + "', " + ftmp + ");")
              return
            end
          end
        end
      end
      # f.print "text"
      if mn == "print"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fputs(" + compile_expr(arg_ids[0]) + ", " + ftmp + ");")
                  return
                end
              end
              return
            end
          end
        end
      end
      # f.write "text"
      if mn == "write"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              args_id = @nd_arguments[nid]
              if args_id >= 0
                arg_ids = get_args(args_id)
                if arg_ids.length >= 1
                  emit("  fputs(" + compile_expr(arg_ids[0]) + ", " + ftmp + ");")
                  return
                end
              end
              return
            end
          end
        end
      end
      # f.each_line { |line| ... }
      if mn == "each_line"
        if r >= 0
          if @nd_type[r] == "LocalVariableReadNode"
            if @nd_name[r] == bp
              if @nd_block[nid] >= 0
                lblk = @nd_block[nid]
                lbp = get_block_param(nid, 0)
                ltmp = new_temp
                emit("  { char " + ltmp + "[4096];")
                emit("  while (fgets(" + ltmp + ", sizeof(" + ltmp + "), " + ftmp + ")) {")
                emit("    const char *lv_" + lbp + " = " + ltmp + ";")
                push_scope
                declare_var(lbp, "string")
                # Compile block body
                lbbody = @nd_body[lblk]
                if lbbody >= 0
                  lbs = get_stmts(lbbody)
                  lbk = 0
                  while lbk < lbs.length
                    compile_stmt(lbs[lbk])
                    lbk = lbk + 1
                  end
                end
                pop_scope
                emit("  } }")
                return
              end
            end
          end
        end
      end
    end
    # Handle control flow: while/if/unless with file block context
    if t == "WhileNode"
      cond = @nd_predicate[nid]
      emit("  while (" + compile_expr(cond) + ") {")
      body = @nd_body[nid]
      if body >= 0
        bs = get_stmts(body)
        bk = 0
        while bk < bs.length
          compile_file_block_stmt(bs[bk], ftmp, bp)
          bk = bk + 1
        end
      end
      emit("  }")
      return
    end
    if t == "IfNode"
      cond = @nd_predicate[nid]
      emit("  if (" + compile_expr(cond) + ") {")
      body = @nd_body[nid]
      if body >= 0
        bs = get_stmts(body)
        bk = 0
        while bk < bs.length
          compile_file_block_stmt(bs[bk], ftmp, bp)
          bk = bk + 1
        end
      end
      if @nd_subsequent[nid] >= 0
        emit("  } else {")
        ebs = get_stmts(@nd_subsequent[nid])
        ebk = 0
        while ebk < ebs.length
          compile_file_block_stmt(ebs[ebk], ftmp, bp)
          ebk = ebk + 1
        end
      end
      emit("  }")
      return
    end
    # Fallback: compile as normal statement
    compile_stmt(nid)
  end

  def scan_lambda_free_vars(nid, params, locals, free_vars)
    # Scan AST node for free variable references
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "LocalVariableReadNode"
      vn = @nd_name[nid]
      if not_in(vn, params) == 1
        if not_in(vn, locals) == 1
          if not_in(vn, free_vars) == 1
            free_vars.push(vn)
          end
        end
      end
      return
    end
    if t == "LambdaNode"
      # For nested lambdas, find their free vars and add them to OUR free vars
      # (they need to be captured transitively)
      inner_pname = ""
      inner_params_id = @nd_parameters[nid]
      if inner_params_id >= 0
        reqs = parse_id_list(@nd_requireds[inner_params_id])
        if reqs.length > 0
          inner_pname = @nd_name[reqs[0]]
        end
      end
      inner_params = "".split(",")
      if inner_pname != ""
        inner_params.push(inner_pname)
      end
      inner_body = @nd_body[nid]
      if inner_body >= 0
        inner_locals = "".split(",")
        inner_free = "".split(",")
        scan_lambda_free_vars(inner_body, inner_params, inner_locals, inner_free)
        inner_free.each { |vn|
          if not_in(vn, params) == 1
            if not_in(vn, locals) == 1
              if not_in(vn, free_vars) == 1
                free_vars.push(vn)
              end
            end
          end
        }
      end
      return
    end
    # Collect local writes — scan expression first to detect reads before the write
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      # Scan the RHS expression first (may contain reads of the same var)
      if @nd_expression[nid] >= 0
        scan_lambda_free_vars(@nd_expression[nid], params, locals, free_vars)
      end
      if not_in(vn, locals) == 1
        if not_in(vn, params) == 1
          if not_in(vn, free_vars) == 1
            # Check if variable exists in outer scope — if so, it's a free var
            outer_t = find_var_type(vn)
            if outer_t != ""
              free_vars.push(vn)
            else
              locals.push(vn)
            end
          end
        end
      end
      return
    end
    # Recurse
    if @nd_body[nid] >= 0
      scan_lambda_free_vars(@nd_body[nid], params, locals, free_vars)
    end
    stmts = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < stmts.length
      scan_lambda_free_vars(stmts[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_expression[nid] >= 0
      scan_lambda_free_vars(@nd_expression[nid], params, locals, free_vars)
    end
    if @nd_left[nid] >= 0
      scan_lambda_free_vars(@nd_left[nid], params, locals, free_vars)
    end
    if @nd_right[nid] >= 0
      scan_lambda_free_vars(@nd_right[nid], params, locals, free_vars)
    end
    if @nd_receiver[nid] >= 0
      scan_lambda_free_vars(@nd_receiver[nid], params, locals, free_vars)
    end
    if @nd_arguments[nid] >= 0
      scan_lambda_free_vars(@nd_arguments[nid], params, locals, free_vars)
    end
    args = parse_id_list(@nd_args[nid])
    k = 0
    while k < args.length
      scan_lambda_free_vars(args[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_predicate[nid] >= 0
      scan_lambda_free_vars(@nd_predicate[nid], params, locals, free_vars)
    end
    if @nd_subsequent[nid] >= 0
      scan_lambda_free_vars(@nd_subsequent[nid], params, locals, free_vars)
    end
    if @nd_else_clause[nid] >= 0
      scan_lambda_free_vars(@nd_else_clause[nid], params, locals, free_vars)
    end
    if @nd_block[nid] >= 0
      scan_lambda_free_vars(@nd_block[nid], params, locals, free_vars)
    end
    elems = parse_id_list(@nd_elements[nid])
    k = 0
    while k < elems.length
      scan_lambda_free_vars(elems[k], params, locals, free_vars)
      k = k + 1
    end
    if @nd_collection[nid] >= 0
      scan_lambda_free_vars(@nd_collection[nid], params, locals, free_vars)
    end
  end

  def scan_lambda_ret_types(stmts)
    stmts.each { |sid|
      scan_lambda_ret_types_node(sid)
    }
    # Also check: h = method_call() where method returns lambda
    stmts.each { |sid|
      if @nd_type[sid] == "LocalVariableWriteNode"
        vn = @nd_name[sid]
        expr = @nd_expression[sid]
        if expr >= 0 && @nd_type[expr] == "CallNode"
          call_ret = infer_type(expr)
          if call_ret == "lambda"
            # Find the method and its lambda return
            mn = @nd_name[expr]
            mi = find_method_idx(mn)
            if mi >= 0
              bid = @meth_body_ids[mi]
              if bid >= 0
                mbs = get_stmts(bid)
                if mbs.length > 0
                  last = mbs.last
                  if @nd_type[last] == "LambdaNode"
                    lbody = @nd_body[last]
                    if lbody >= 0
                      lbs = get_stmts(lbody)
                      if lbs.length > 0
                        lrt = infer_type(lbs.last)
                        if not_in(vn, @lambda_var_ret_names) == 1
                          @lambda_var_ret_names.push(vn)
                          @lambda_var_ret_types.push(lrt)
                        end
                      end
                    end
                  end
                end
              end
            end
          end
        end
      end
    }
  end

  def scan_lambda_ret_types_node(nid)
    if nid < 0
      return
    end
    t = @nd_type[nid]
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      expr = @nd_expression[nid]
      if expr >= 0 && @nd_type[expr] == "LambdaNode"
        lbody = @nd_body[expr]
        if lbody >= 0
          lbs = get_stmts(lbody)
          if lbs.length > 0
            lrt = infer_type(lbs.last)
            if not_in(vn, @lambda_var_ret_names) == 1
              @lambda_var_ret_names.push(vn)
              @lambda_var_ret_types.push(lrt)
            end
          end
        end
      end
      scan_lambda_ret_types_node(expr)
    end
    # Scan into method bodies to find lambdas returned from methods
    if t == "DefNode"
      if @nd_body[nid] >= 0
        scan_lambda_ret_types_node(@nd_body[nid])
      end
      return
    end
    if @nd_body[nid] >= 0
      scan_lambda_ret_types_node(@nd_body[nid])
    end
    if @nd_expression[nid] >= 0
      scan_lambda_ret_types_node(@nd_expression[nid])
    end
    ss = parse_id_list(@nd_stmts[nid])
    k = 0
    while k < ss.length
      scan_lambda_ret_types_node(ss[k])
      k = k + 1
    end
  end

  def lambda_var_ret_type(vname)
    i = 0
    while i < @lambda_var_ret_names.length
      if @lambda_var_ret_names[i] == vname
        return @lambda_var_ret_types[i]
      end
      i = i + 1
    end
    ""
  end

  def lam_box(expr, vtype)
    bt = base_type(vtype)
    if bt == "string"
      return "sp_lam_int((mrb_int)" + expr + ")"
    end
    if bt == "float"
      return "sp_lam_int(*(mrb_int*)&(mrb_float){" + expr + "})"
    end
    if bt == "bool"
      return "sp_lam_bool(" + expr + ")"
    end
    if bt == "nil" || bt == "void"
      return "&sp_lam_nil_val"
    end
    "sp_lam_int(" + expr + ")"
  end

  def lam_unbox(expr, vtype)
    bt = base_type(vtype)
    if bt == "string"
      return "(const char*)sp_lam_to_int(" + expr + ")"
    end
    if bt == "float"
      return "*(mrb_float*)&(mrb_int){sp_lam_to_int(" + expr + ")}"
    end
    if bt == "bool"
      return "(" + expr + ")->u.bval"
    end
    if bt == "nil" || bt == "void"
      return "(sp_lam_to_int(" + expr + "), 0)"
    end
    "sp_lam_to_int(" + expr + ")"
  end

  def compile_lambda_body_expr(nid, params, captures)
    # Compile an expression inside a lambda body, replacing:
    # - param refs with lv_param (local)
    # - captured var refs with self->captures[i]
    if nid < 0
      return "&sp_lam_nil_val"
    end
    t = @nd_type[nid]
    if t == "LocalVariableReadNode"
      vn = @nd_name[nid]
      # Check param
      if not_in(vn, params) == 0
        return "lv_" + vn
      end
      # Check captures
      ci = 0
      while ci < captures.length
        if captures[ci] == vn
          ct = ""
          if ci < @lambda_capture_cell_types.length
            ct = @lambda_capture_cell_types[ci]
          end
          if ct != ""
            # Typed cell capture: dereference and box
            deref = "*(" + c_type(ct) + "*)self->captures[" + ci.to_s + "]"
            return lam_box(deref, ct)
          end
          return "self->captures[" + ci.to_s + "]"
        end
        ci = ci + 1
      end
      return "lv_" + vn
    end
    if t == "LocalVariableWriteNode"
      vn = @nd_name[nid]
      val = compile_lambda_body_expr(@nd_expression[nid], params, captures)
      # Check if capture
      ci = 0
      while ci < captures.length
        if captures[ci] == vn
          ct = ""
          if ci < @lambda_capture_cell_types.length
            ct = @lambda_capture_cell_types[ci]
          end
          if ct != ""
            # Typed cell capture: unbox and store
            cptr = "*(" + c_type(ct) + "*)self->captures[" + ci.to_s + "]"
            return "(" + cptr + " = " + lam_unbox(val, ct) + ", " + val + ")"
          end
          return "(self->captures[" + ci.to_s + "] = " + val + ")"
        end
        ci = ci + 1
      end
      emit("  sp_Val *lv_" + vn + " = " + val + ";")
      return "lv_" + vn
    end
    if t == "IntegerNode"
      return "sp_lam_int(" + @nd_value[nid].to_s + ")"
    end
    if t == "TrueNode"
      return "sp_lam_bool(TRUE)"
    end
    if t == "FalseNode"
      return "sp_lam_bool(FALSE)"
    end
    if t == "NilNode"
      return "&sp_lam_nil_val"
    end
    if t == "StringNode"
      return "sp_lam_int(0)"
    end
    if t == "ConstantReadNode"
      cname = @nd_name[nid]
      ci = find_const_idx(cname)
      if ci >= 0
        return "cst_" + cname
      end
      return "&sp_lam_nil_val"
    end
    if t == "LambdaNode"
      return compile_lambda_expr(nid)
    end
    if t == "CallNode"
      mname = @nd_name[nid]
      recv = @nd_receiver[nid]
      # f[arg] -> sp_lam_call(f, arg)
      if mname == "[]"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              ac = compile_lambda_body_expr(aargs.first, params, captures)
              return "sp_lam_call(" + rc + ", " + ac + ")"
            end
          end
          return "sp_lam_call(" + rc + ", &sp_lam_nil_val)"
        end
      end
      # f.call(arg) -> sp_lam_call(f, arg)
      if mname == "call"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            if aargs.length > 0
              ac = compile_lambda_body_expr(aargs.first, params, captures)
              return "sp_lam_call(" + rc + ", " + ac + ")"
            end
          end
          return "sp_lam_call(" + rc + ", &sp_lam_nil_val)"
        end
      end
      # No receiver: bare function call
      if recv < 0
        if mname == "+"
          return "sp_lam_int(0)"
        end
        mi = find_method_idx(mname)
        if mi >= 0
          ca = ""
          args_id = @nd_arguments[nid]
          if args_id >= 0
            aargs = get_args(args_id)
            k = 0
            while k < aargs.length
              if k > 0
                ca = ca + ", "
              end
              ca = ca + compile_lambda_body_expr(aargs[k], params, captures)
              k = k + 1
            end
          end
          return "sp_" + sanitize_name(mname) + "(" + ca + ")"
        end
      end
      # Arithmetic on sp_Val (+ operator)
      if mname == "+"
        if recv >= 0
          rc = compile_lambda_body_expr(recv, params, captures)
          ac = compile_lambda_body_expr(get_args(@nd_arguments[nid])[0], params, captures)
          return "sp_lam_int(sp_lam_to_int(" + rc + ") + sp_lam_to_int(" + ac + "))"
        end
      end
      return "&sp_lam_nil_val"
    end
    if t == "IfNode"
      pred = compile_lambda_body_expr(@nd_predicate[nid], params, captures)
      body = @nd_body[nid]
      bexpr = "&sp_lam_nil_val"
      if body >= 0
        bs = get_stmts(body)
        if bs.length > 0
          bexpr = compile_lambda_body_expr(bs.last, params, captures)
        end
      end
      ec = @nd_else_clause[nid]
      eexpr = "&sp_lam_nil_val"
      if ec >= 0
        ebs = get_stmts(@nd_body[ec])
        if ebs.length > 0
          eexpr = compile_lambda_body_expr(ebs[ebs.length - 1], params, captures)
        end
      end
      return "(" + pred + " ? " + bexpr + " : " + eexpr + ")"
    end
    "&sp_lam_nil_val"
  end

  def wrap_as_sp_val(nid)
    at = infer_type(nid)
    if at == "lambda"
      return compile_expr(nid)
    end
    if at == "int"
      return "sp_lam_int(" + compile_expr(nid) + ")"
    end
    if at == "bool"
      return "sp_lam_bool(" + compile_expr(nid) + ")"
    end
    if @nd_type[nid] == "NilNode"
      return "&sp_lam_nil_val"
    end
    # Default: try to compile as expression
    compile_expr(nid)
  end

  def compile_lambda_expr(nid)
    @needs_lambda = 1
    # Get the parameter name
    pname = ""
    params_id = @nd_parameters[nid]
    if params_id >= 0
      reqs = parse_id_list(@nd_requireds[params_id])
      if reqs.length > 0
        pname = @nd_name[reqs[0]]
      end
    end
    param_arr = "".split(",")
    if pname != ""
      param_arr.push(pname)
    end

    body = @nd_body[nid]
    # Find free variables (captures)
    free_vars = "".split(",")
    locals = "".split(",")
    if body >= 0
      scan_lambda_free_vars(body, param_arr, locals, free_vars)
    end

    # Generate lambda function
    lam_id = @lambda_counter
    @lambda_counter = @lambda_counter + 1
    fname = "_lam_" + lam_id.to_s

    # Compute capture cell types (before body compilation)
    cap_cell_types = "".split(",")
    k = 0
    while k < free_vars.length
      fv = free_vars[k]
      cell = heap_promoted_cell(fv)
      if cell == "" && @in_fiber_body == 1 && fiber_capture_index(fv) >= 0
        cell = "_cap->" + fv
      end
      # Regular locals will be heap-promoted (not lambda params/captures)
      if cell == "" && not_in(fv, @lambda_params) == 1
        is_enclosing_cap = 0
        ci = 0
        while ci < @lambda_captures.length
          if @lambda_captures[ci] == fv
            is_enclosing_cap = 1
          end
          ci = ci + 1
        end
        if is_enclosing_cap == 0
          vt = find_var_type(fv)
          if vt != "" && vt != "lambda"
            cell = "will_promote"
          end
        end
      end
      if cell != ""
        cap_cell_types.push(find_var_type(fv))
      else
        cap_cell_types.push("")
      end
      k = k + 1
    end

    # Check if we have typed cell captures (need regular compiler path)
    has_typed_caps = 0
    k = 0
    while k < cap_cell_types.length
      if cap_cell_types[k] != ""
        has_typed_caps = 1
      end
      k = k + 1
    end

    # Get body expression
    bexpr = "&sp_lam_nil_val"
    if body >= 0
      bs = get_stmts(body)
      if bs.length > 0 && has_typed_caps == 1
        # Typed captures: compile body using regular compiler
        save_out = @out_lines
        save_indent = @indent
        save_hp_names_len = @heap_promoted_names.length
        save_hp_cells_len = @heap_promoted_cells.length
        @out_lines = "".split(",")
        @indent = 1

        push_scope
        # Declare parameter with proper type
        if pname != ""
          ptype = infer_type(bs.last)
          if ptype == ""
            ptype = "int"
          end
          declare_var(pname, "int")
        end
        # Set up cell pointer locals for typed captures
        k = 0
        while k < free_vars.length
          if cap_cell_types[k] != ""
            ct = c_type(cap_cell_types[k])
            cell_local = "_lc_" + free_vars[k]
            emit("  " + ct + " *" + cell_local + " = (" + ct + "*)self->captures[" + k.to_s + "];")
            @heap_promoted_names.push(free_vars[k])
            @heap_promoted_cells.push(cell_local)
            declare_var(free_vars[k], cap_cell_types[k])
          end
          k = k + 1
        end
        # Declare body-local variables
        lnames = "".split(",")
        ltypes = "".split(",")
        excl = "".split(",")
        if pname != ""
          excl.push(pname)
        end
        k = 0
        while k < free_vars.length
          excl.push(free_vars[k])
          k = k + 1
        end
        scan_locals(body, lnames, ltypes, excl)
        lk = 0
        while lk < lnames.length
          declare_var(lnames[lk], ltypes[lk])
          emit("  " + c_type(ltypes[lk]) + " lv_" + lnames[lk] + " = " + c_default_val(ltypes[lk]) + ";")
          lk = lk + 1
        end
        # Compile body statements
        i = 0
        while i < bs.length - 1
          compile_stmt(bs[i])
          i = i + 1
        end
        last = bs.last
        last_type = infer_type(last)
        if @nd_type[last] == "LocalVariableWriteNode" || @nd_type[last] == "LocalVariableOperatorWriteNode"
          compile_stmt(last)
        end
        last_val = compile_expr(last)

        pop_scope
        body_stmts = @out_lines.join(10.chr) + 10.chr
        @out_lines = save_out
        @indent = save_indent
        # Restore heap promoted
        while @heap_promoted_names.length > save_hp_names_len
          @heap_promoted_names.pop
        end
        while @heap_promoted_cells.length > save_hp_cells_len
          @heap_promoted_cells.pop
        end

        # Build lambda function with typed body
        @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) {\n"
        if pname != ""
          @lambda_funcs << "  mrb_int lv_"
          @lambda_funcs << pname
          @lambda_funcs << " = sp_lam_to_int(arg);\n"
        end
        @lambda_funcs << body_stmts
        @lambda_funcs << 10.chr
        bexpr = lam_box(last_val, last_type)
        @lambda_funcs << "  return "
        @lambda_funcs << bexpr
        @lambda_funcs << ";\n}\n\n"
      elsif bs.length > 0
        # No typed captures: use sp_Val* lambda body compiler
        save_out = @out_lines
        save_params = @lambda_params
        save_captures = @lambda_captures
        save_cell_types = @lambda_capture_cell_types
        @out_lines = "".split(",")
        @lambda_params = param_arr
        @lambda_captures = free_vars
        @lambda_capture_cell_types = cap_cell_types
        si = 0
        while si < bs.length - 1
          side_expr = compile_lambda_body_expr(bs[si], param_arr, free_vars)
          emit("  " + side_expr + ";")
          si = si + 1
        end
        bexpr = compile_lambda_body_expr(bs.last, param_arr, free_vars)
        body_stmts = @out_lines.join(10.chr) + 10.chr
        @out_lines = save_out
        @lambda_params = save_params
        @lambda_captures = save_captures
        @lambda_capture_cell_types = save_cell_types

        if body_stmts != ""
          @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) {\n"
          if pname != ""
            @lambda_funcs <<"  sp_Val *lv_" + pname + " = arg;\n"
          end
          @lambda_funcs <<"  (void)self;\n"
          @lambda_funcs <<body_stmts + 10.chr
          @lambda_funcs <<"  return " + bexpr + ";\n"
          @lambda_funcs <<"}\n\n"
        else
          @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) {\n"
          if pname != ""
            @lambda_funcs <<"  sp_Val *lv_" + pname + " = arg;\n"
          end
          @lambda_funcs <<"  (void)self;\n"
          @lambda_funcs <<"  return " + bexpr + ";\n"
          @lambda_funcs <<"}\n\n"
        end
      else
        @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) { (void)self; (void)arg; return &sp_lam_nil_val; }\n\n"
      end
    else
      @lambda_funcs <<"static sp_Val *" + fname + "(sp_Val *self, sp_Val *arg) { (void)self; (void)arg; return &sp_lam_nil_val; }\n\n"
    end

    # Build the closure creation expression
    if free_vars.length > 0
      # Heap-promote regular locals that need cell captures
      k = 0
      while k < free_vars.length
        if cap_cell_types[k] != "" && heap_promoted_cell(free_vars[k]) == ""
          fv = free_vars[k]
          # Skip if it's a fiber capture (already has cell) or lambda context
          if @in_fiber_body == 0 || fiber_capture_index(fv) < 0
            if not_in(fv, @heap_promoted_names) == 1
              ct = c_type(cap_cell_types[k])
              cell = "_hcell_" + fv + "_l" + lam_id.to_s
              emit("  " + ct + " *" + cell + " = (" + ct + "*)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
              emit("  *" + cell + " = " + fiber_var_ref(fv) + ";")
              @heap_promoted_names.push(fv)
              @heap_promoted_cells.push(cell)
            end
          end
        end
        k = k + 1
      end
      tmp = new_temp
      emit("  sp_Val *" + tmp + " = sp_lam_proc(" + fname + ", " + free_vars.length.to_s + ");")
      k = 0
      while k < free_vars.length
        fv = free_vars[k]
        if cap_cell_types[k] != ""
          # Heap-promoted or fiber-captured: store cell pointer cast to sp_Val*
          cell = heap_promoted_cell(fv)
          if cell == "" && @in_fiber_body == 1 && fiber_capture_index(fv) >= 0
            cell = "_cap->" + fv
          end
          emit("  " + tmp + "->captures[" + k.to_s + "] = (sp_Val*)" + cell + ";")
        else
          # Check if it's a param or capture of enclosing lambda (sp_Val* world)
          is_lam_ctx = 0
          if not_in(fv, @lambda_params) == 0
            is_lam_ctx = 1
            emit("  " + tmp + "->captures[" + k.to_s + "] = lv_" + fv + ";")
          else
            ci = 0
            while ci < @lambda_captures.length
              if @lambda_captures[ci] == fv
                is_lam_ctx = 1
                emit("  " + tmp + "->captures[" + k.to_s + "] = self->captures[" + ci.to_s + "];")
              end
              ci = ci + 1
            end
          end
          if is_lam_ctx == 0
            # Regular local: should have been heap-promoted already
            cell = heap_promoted_cell(fv)
            if cell != ""
              emit("  " + tmp + "->captures[" + k.to_s + "] = (sp_Val*)" + cell + ";")
            else
              emit("  " + tmp + "->captures[" + k.to_s + "] = " + fiber_var_ref(fv) + ";")
            end
          end
        end
        k = k + 1
      end
      return tmp
    else
      return "sp_lam_proc(" + fname + ", 0)"
    end
  end

  # Build the proc-fn body prelude that unpacks the args array passed
  # to the uniform `(void *_cap, mrb_int *args)` signature into named
  # `lv_<bp>` locals — one `mrb_int lv_<bp> = args[<idx>];` line per
  # block param. Used at both proc-fn body emit sites (captures and
  # no-captures branches; identical shape).
  def proc_fn_args_unpack(bps)
    s = ""
    bk = 0
    while bk < bps.length
      s = s + "  mrb_int lv_" + bps[bk] + " = args[" + bk.to_s + "];\n"
      bk = bk + 1
    end
    s
  end

  def compile_proc_literal(nid)
    blk = @nd_block[nid]
    if blk < 0
      return "sp_proc_new(NULL, NULL, NULL)"
    end
    # Collect every block param name. Single-param blocks fall through
    # to the existing `_unused` fallback for parameterless bodies.
    bps = "".split(",")
    pi = 0
    pn = get_block_param(nid, pi)
    while pn != ""
      bps.push(pn)
      pi = pi + 1
      pn = get_block_param(nid, pi)
    end
    if bps.length == 0
      bps.push("_unused")
    end
    # Generate a static function for the proc body
    @proc_counter = @proc_counter + 1
    pid = @proc_counter
    fname = "_sp_proc_fn_" + pid.to_s
    cap_name = "_proc_cap_" + pid.to_s
    cap_scan_name = "_proc_cap_scan_" + pid.to_s
    bbody = @nd_body[blk]

    # Detect captures (free variables that resolve in outer scope).
    # Every block param is in scope inside the body; only locals from
    # the outer scope read inside the body count as free.
    free_vars = "".split(",")
    if bbody >= 0
      # scan_lambda_free_vars treats `params` as read-only, so bps can
      # be passed directly without an intermediate copy.
      proc_locals = "".split(",")
      scan_lambda_free_vars(bbody, bps, proc_locals, free_vars)
    end
    captures = "".split(",")
    capture_types = "".split(",")
    fk = 0
    while fk < free_vars.length
      fv = free_vars[fk]
      vt = find_var_type(fv)
      if vt != ""
        captures.push(fv)
        capture_types.push(vt)
      end
      fk = fk + 1
    end
    has_captures = 0
    if captures.length > 0
      has_captures = 1
    end

    # Compile the body. While captures > 0, set @in_proc_body so that
    # compile_expr's fiber_var_ref rewrites captured-var reads/writes to
    # (*_cap->VN). Heap promotion of those vars in the enclosing scope is
    # done after body compile (so cells exist before they're referenced
    # in the cap struct allocation).
    save_out = @out_lines
    @out_lines = "".split(",")
    saved_in_proc_body = @in_proc_body
    saved_proc_captures = @proc_captures
    saved_proc_capture_types = @proc_capture_types
    if has_captures == 1
      @in_proc_body = 1
      @proc_captures = captures
      @proc_capture_types = capture_types
    end
    push_scope
    di = 0
    while di < bps.length
      declare_var(bps[di], "int")
      di = di + 1
    end
    bexpr = "0"
    body_stmts = ""
    if bbody >= 0
      bs = get_stmts(bbody)
      if bs.length > 0
        k = 0
        while k < bs.length
          lt = infer_type(bs[k])
          if k == bs.length - 1
            last_t = @nd_type[bs[k]]
            if last_t == "LocalVariableWriteNode" || last_t == "LocalVariableOperatorWriteNode"
              compile_stmt(bs[k])
              body_stmts = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",")
              bexpr = fiber_var_ref(@nd_name[bs[k]])
            elsif lt != "void"
              body_stmts = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",")
              bexpr = compile_expr(bs[k])
              extra = @out_lines.join(10.chr) + 10.chr
              @out_lines = "".split(",")
              body_stmts = body_stmts + extra
            else
              compile_stmt(bs[k])
            end
          else
            compile_stmt(bs[k])
          end
          k = k + 1
        end
        if body_stmts == ""
          body_stmts = @out_lines.join(10.chr) + 10.chr
          @out_lines = "".split(",")
        end
      end
    end
    pop_scope
    @in_proc_body = saved_in_proc_body
    @proc_captures = saved_proc_captures
    @proc_capture_types = saved_proc_capture_types
    @out_lines = save_out

    if has_captures == 1
      # Emit per-proc capture struct + scan function + body fn that casts
      # the void* cap to the typed struct.
      @lambda_funcs << "typedef struct { "
      k = 0
      while k < captures.length
        @lambda_funcs << c_type(capture_types[k])
        @lambda_funcs << " *"
        @lambda_funcs << captures[k]
        @lambda_funcs << "; "
        k = k + 1
      end
      @lambda_funcs << "} "
      @lambda_funcs << cap_name
      @lambda_funcs << ";\n"
      @lambda_funcs << "static void "
      @lambda_funcs << cap_scan_name
      @lambda_funcs << "(void *p) {\n"
      @lambda_funcs << "  "
      @lambda_funcs << cap_name
      @lambda_funcs << " *_c = ("
      @lambda_funcs << cap_name
      @lambda_funcs << " *)p;\n"
      k = 0
      while k < captures.length
        @lambda_funcs << "  if (_c->"
        @lambda_funcs << captures[k]
        @lambda_funcs << ") sp_gc_mark((void *)_c->"
        @lambda_funcs << captures[k]
        @lambda_funcs << ");\n"
        k = k + 1
      end
      @lambda_funcs << "}\n"
      @lambda_funcs << "static mrb_int "
      @lambda_funcs << fname
      @lambda_funcs << "(void *_cap_raw, mrb_int *args) {\n"
      @lambda_funcs << proc_fn_args_unpack(bps)
      @lambda_funcs << "  "
      @lambda_funcs << cap_name
      @lambda_funcs << " *_cap = ("
      @lambda_funcs << cap_name
      @lambda_funcs << " *)_cap_raw;\n"
      if body_stmts != ""
        @lambda_funcs << body_stmts
      end
      @lambda_funcs << "  return "
      @lambda_funcs << bexpr
      @lambda_funcs << ";\n}\n"

      # In the enclosing scope: heap-promote each captured local (allocate
      # a cell, copy current value into it, register so subsequent
      # references in the enclosing scope go through the cell), then
      # allocate the cap struct and populate its pointers.
      k = 0
      while k < captures.length
        vn = captures[k]
        ct = c_type(capture_types[k])
        already_promoted = 0
        ci = 0
        while ci < @heap_promoted_names.length
          if @heap_promoted_names[ci] == vn
            already_promoted = 1
          end
          ci = ci + 1
        end
        if already_promoted == 0
          cell = "_hcell_" + vn + "_p" + pid.to_s
          emit("  " + ct + " *" + cell + " = (" + ct + " *)sp_gc_alloc(sizeof(" + ct + "), NULL, NULL);")
          emit("  *" + cell + " = " + fiber_var_ref(vn) + ";")
          @heap_promoted_names.push(vn)
          @heap_promoted_cells.push(cell)
        end
        k = k + 1
      end
      cap_ptr = "_cap_ptr_p" + pid.to_s
      emit("  " + cap_name + " *" + cap_ptr + " = (" + cap_name + " *)sp_gc_alloc(sizeof(" + cap_name + "), NULL, " + cap_scan_name + ");")
      k = 0
      while k < captures.length
        vn = captures[k]
        ci = 0
        cell = ""
        while ci < @heap_promoted_names.length
          if @heap_promoted_names[ci] == vn
            cell = @heap_promoted_cells[ci]
          end
          ci = ci + 1
        end
        emit("  " + cap_ptr + "->" + vn + " = " + cell + ";")
        k = k + 1
      end
      return "sp_proc_new(" + fname + ", " + cap_ptr + ", " + cap_scan_name + ")"
    end

    # No captures: file-scope function with unused cap arg, sp_proc_new
    # with NULL cap and NULL scan.
    @lambda_funcs << "static mrb_int "
    @lambda_funcs << fname
    @lambda_funcs << "(void *_cap, mrb_int *args) {\n"
    @lambda_funcs << "  (void)_cap;\n"
    @lambda_funcs << proc_fn_args_unpack(bps)
    if body_stmts != ""
      @lambda_funcs << body_stmts
    end
    @lambda_funcs << "  return "
    @lambda_funcs << bexpr
    @lambda_funcs << ";\n}\n"
    return "sp_proc_new(" + fname + ", NULL, NULL)"
  end

  def compile_bracket_assign(nid)
    recv = @nd_receiver[nid]
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    args_id = @nd_arguments[nid]
    arg_ids = []
    if args_id >= 0
      arg_ids = get_args(args_id)
    end
    # Slice assignment `arr[i, n] = src`: replace n elements
    # starting at index i with the elements of src. Same-length
    # only (n == src.length); resize semantics not yet supported.
    # Only fires when both sides are the same C kind — falls
    # through otherwise to avoid silent miscompiles on mistyped
    # inputs (e.g. an `int_array`-typed src that's actually an
    # array-of-IntArrays would copy the wrong shape).
    if arg_ids.length == 3 && (rt == "int_array" || rt == "float_array" || rt == "str_array" || rt == "sym_array" || is_ptr_array_type(rt) == 1 || rt == "poly_array")
      src_t_check = infer_type(arg_ids[2])
      if array_c_prefix(rt) == array_c_prefix(src_t_check) && (src_t_check == "int_array" || src_t_check == "float_array" || src_t_check == "str_array" || src_t_check == "sym_array" || is_ptr_array_type(src_t_check) == 1 || src_t_check == "poly_array")
        compile_slice_assign(nid, recv, rt, rc, arg_ids)
        return
      end
    end
    # Slice assignment with poly recv: `@bg_pixels[xfine, 8] =
    # pattern_lut[bg_pattern]` against an iv typed as poly (because
    # widening saw it as either an int_array or a poly_array at
    # different points). Without this, the fall-through `[]=` path
    # would treat arg_ids[1] (the slice length) as the value to
    # store and silently drop the actual rhs. Dispatch by runtime
    # cls_id and copy len elements from src to dest.
    if arg_ids.length == 3 && rt == "poly"
      compile_poly_slice_assign(nid, recv, rc, arg_ids)
      return
    end
    # Slice assignment with poly_array recv and poly src: the recv
    # is statically typed (sp_PolyArray *) but src is sp_RbVal —
    # fold into compile_poly_slice_assign by pre-boxing the recv to
    # sp_RbVal so the runtime cls_id dispatch can pick the right
    # copy loop. This is the shape `@bg_pixels[xfine, 8] =
    # @bg_pattern_lut[@bg_pattern]` ends up in once a 3-level array
    # constant (TILE_LUT) types its inner-of-inner reads as poly.
    if arg_ids.length == 3 && rt == "poly_array"
      src_t_check2 = infer_type(arg_ids[2])
      if src_t_check2 == "poly"
        @needs_rb_value = 1
        compile_poly_slice_assign(nid, recv, "sp_box_poly_array(" + rc + ")", arg_ids)
        return
      end
    end
    idx = "0"
    val = "0"
    if arg_ids.length >= 1
      if rt == "str_int_hash" || rt == "str_str_hash"
        idx = compile_expr_as_string(arg_ids[0])
      else
        idx = compile_expr(arg_ids[0])
        # Auto-unbox poly index for typed-array recv. The block-param
        # iteration over a poly recv (compile_each_block's poly arm)
        # delivers `lv_<bp>` as sp_RbVal, but a downstream
        # `@arr[bp] = v` against a typed array expects an mrb_int.
        idx_t = infer_type(arg_ids[0])
        if idx_t == "poly" && (rt == "int_array" || rt == "float_array" || rt == "str_array" || rt == "sym_array" || is_ptr_array_type(rt) == 1 || rt == "poly_array")
          idx = "(" + idx + ").v.i"
        end
      end
    end
    if arg_ids.length >= 2
      val = compile_expr(arg_ids[1])
    end
    if rt == "int_str_hash"
      emit("  sp_IntStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "sym_int_hash"
      emit("  sp_SymIntHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "sym_str_hash"
      emit("  sp_SymStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "sym_poly_hash"
      boxed = val
      if arg_ids.length >= 2
        boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_SymPolyHash_set(" + rc + ", " + idx + ", " + boxed + ");")
      return
    end
    if rt == "str_poly_hash"
      idx_s = compile_expr_as_string(arg_ids[0])
      boxed = val
      if arg_ids.length >= 2
        boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_StrPolyHash_set(" + rc + ", " + idx_s + ", " + boxed + ");")
      return
    end
    if rt == "poly_poly_hash"
      key_boxed = box_expr_to_poly(arg_ids[0])
      val_boxed = val
      if arg_ids.length >= 2
        val_boxed = box_expr_to_poly(arg_ids[1])
      end
      emit("  sp_PolyPolyHash_set(" + rc + ", " + key_boxed + ", " + val_boxed + ");")
      return
    end
    if rt == "int_array"
      # Check if value is an object pointer - needs cast
      vt = "int"
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
      end
      if is_obj_type(vt) == 1
        emit("  sp_IntArray_set(" + rc + ", " + idx + ", (mrb_int)" + val + ");")
      else
        emit("  sp_IntArray_set(" + rc + ", " + idx + ", " + val + ");")
      end
      return
    end
    if rt == "float_array"
      emit("  sp_FloatArray_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "str_array"
      emit("  sp_StrArray_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if is_ptr_array_type(rt) == 1
      emit("  sp_PtrArray_set(" + rc + ", " + idx + ", (void *)" + val + ");")
      return
    end
    if rt == "poly_array"
      vbox = val
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
        if vt != "poly"
          vbox = box_value_to_poly(vt, val)
        end
      end
      emit("  sp_PolyArray_set(" + rc + ", " + idx + ", " + vbox + ");")
      return
    end
    if rt == "poly"
      # Slot is sp_RbVal — runtime cls_id determines which storage
      # the underlying pointer points at. Optcarrot's `@fetch[a] =
      # method(:peek_X)` lands here when @fetch was widened to poly
      # (rather than poly_array) by the heterogeneous IntArray + Method
      # writes. Dispatch by cls_id at runtime.
      #
      # When the slot's runtime storage is IntArray but the value
      # being stored is non-int (a pointer / poly with cls_id != 0),
      # we'd lose the cls_id by storing as int. Widen the storage at
      # runtime: allocate a fresh PolyArray, copy the existing int
      # elements as boxed-int, then store the new value boxed. Update
      # the slot to hold the new PolyArray. Requires knowing where
      # the slot is — only fires when recv is an ivar / local / cvar
      # / gvar that we can reassign in C.
      vbox = val
      vt = "int"
      if arg_ids.length >= 2
        vt = infer_type(arg_ids[1])
        if vt != "poly"
          vbox = box_value_to_poly(vt, val)
        end
      end
      vbox_tmp = new_temp
      emit("  sp_RbVal " + vbox_tmp + " = " + vbox + ";")
      # Determine the slot expression — what we'd assign to in order
      # to replace the storage. Only ivar / local / cvar / gvar are
      # supported; anything else falls back to no-widen (still
      # correct for the homogeneous cases, just not heterogeneous).
      slot_lhs = ""
      if @nd_type[recv] == "InstanceVariableReadNode"
        slot_lhs = self_arrow + sanitize_ivar(@nd_name[recv])
      elsif @nd_type[recv] == "LocalVariableReadNode"
        slot_lhs = fiber_var_ref(@nd_name[recv])
      end
      if slot_lhs != ""
        @needs_gc = 1
        @needs_rb_value = 1
        cur = new_temp
        new_arr = new_temp
        old_int = new_temp
        ii = new_temp
        emit("  sp_RbVal " + cur + " = " + rc + ";")
        # Widen path: if storage is IntArray but value can't fit int
        # (i.e. value carries cls_id != 0 or tag != INT, meaning it's
        # a typed pointer/box that loses info if cast to int).
        emit("  if (" + cur + ".cls_id == SP_BUILTIN_INT_ARRAY && (" + vbox_tmp + ".tag != SP_TAG_INT || " + vbox_tmp + ".cls_id != 0)) {")
        emit("    sp_IntArray *" + old_int + " = (sp_IntArray *)" + cur + ".v.p;")
        emit("    sp_PolyArray *" + new_arr + " = sp_PolyArray_new();")
        emit("    for (mrb_int " + ii + " = 0; " + ii + " < sp_IntArray_length(" + old_int + "); " + ii + "++) sp_PolyArray_push(" + new_arr + ", sp_box_int(sp_IntArray_get(" + old_int + ", " + ii + ")));")
        emit("    sp_PolyArray_set(" + new_arr + ", " + idx + ", " + vbox_tmp + ");")
        emit("    " + slot_lhs + " = sp_box_poly_array(" + new_arr + ");")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
        emit("    sp_PolyArray_set((sp_PolyArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ");")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_PTR_ARRAY) {")
        emit("    sp_PtrArray_set((sp_PtrArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ".v.p);")
        emit("  } else if (" + cur + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
        emit("    sp_IntArray_set((sp_IntArray *)" + cur + ".v.p, " + idx + ", " + vbox_tmp + ".v.i);")
        emit("  }")
      else
        emit("  if (" + rc + ".cls_id == SP_BUILTIN_POLY_ARRAY) sp_PolyArray_set((sp_PolyArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ");")
        emit("  else if (" + rc + ".cls_id == SP_BUILTIN_PTR_ARRAY) sp_PtrArray_set((sp_PtrArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ".v.p);")
        emit("  else if (" + rc + ".cls_id == SP_BUILTIN_INT_ARRAY) sp_IntArray_set((sp_IntArray *)" + rc + ".v.p, " + idx + ", " + vbox_tmp + ".v.i);")
      end
      return
    end
    if rt == "str_int_hash"
      emit("  sp_StrIntHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
    if rt == "str_str_hash"
      emit("  sp_StrStrHash_set(" + rc + ", " + idx + ", " + val + ");")
      return
    end
  end

  # `arr[start, len] = src` where arr is a poly-typed slot (sp_RbVal).
  # Dispatches by runtime cls_id of arr and src and emits a per-index
  # copy. Same-length only — `src.length` must equal `len`. Falls
  # back silently when src isn't an array (no copy emitted).
  def compile_poly_slice_assign(nid, recv, rc, arg_ids)
    @needs_rb_value = 1
    start_id = arg_ids[0]
    len_id = arg_ids[1]
    src_id = arg_ids[2]
    start_e = compile_expr(start_id)
    len_e = compile_expr(len_id)
    src_e = compile_expr_gc_rooted(src_id)
    src_t = infer_type(src_id)
    # Box src to poly so we can switch on cls_id at runtime even when
    # spinel statically inferred a concrete array kind (e.g. when src
    # is `pattern_lut[bg_pattern]` returning a poly value boxed from
    # a typed array push).
    if src_t != "poly"
      src_e = box_value_to_poly(src_t, src_e)
    end
    rc_t = new_temp
    src_t_v = new_temp
    start_t = new_temp
    len_t = new_temp
    ii = new_temp
    emit("  {")
    emit("    sp_RbVal " + rc_t + " = " + rc + ";")
    emit("    sp_RbVal " + src_t_v + " = " + src_e + ";")
    emit("    mrb_int " + start_t + " = " + start_e + ";")
    emit("    mrb_int " + len_t + " = " + len_e + ";")
    emit("    if (" + rc_t + ".cls_id == SP_BUILTIN_INT_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_IntArray_set((sp_IntArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_IntArray_get((sp_IntArray *)" + src_t_v + ".v.p, " + ii + "));")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_POLY_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_PolyArray_set((sp_PolyArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_PolyArray_get((sp_PolyArray *)" + src_t_v + ".v.p, " + ii + "));")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_INT_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_POLY_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_IntArray_set((sp_IntArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_PolyArray_get((sp_PolyArray *)" + src_t_v + ".v.p, " + ii + ").v.i);")
    emit("    } else if (" + rc_t + ".cls_id == SP_BUILTIN_POLY_ARRAY && " + src_t_v + ".cls_id == SP_BUILTIN_INT_ARRAY) {")
    emit("      for (mrb_int " + ii + " = 0; " + ii + " < " + len_t + "; " + ii + "++) sp_PolyArray_set((sp_PolyArray *)" + rc_t + ".v.p, " + start_t + " + " + ii + ", sp_box_int(sp_IntArray_get((sp_IntArray *)" + src_t_v + ".v.p, " + ii + ")));")
    emit("    }")
    emit("  }")
  end

  # Compile `arr[start, len] = src` slice assignment. Replaces
  # `len` elements of `arr` starting at `start` with the elements
  # of `src`. Same-length only — `src.length` must equal `len` at
  # runtime; resize semantics not implemented. Each index `i in
  # 0...len` is emitted as `arr[start + i] = src[i]`.
  def compile_slice_assign(nid, recv, rt, rc, arg_ids)
    start_id = arg_ids[0]
    len_id = arg_ids[1]
    src_id = arg_ids[2]
    src_t = infer_type(src_id)
    start_e = compile_expr(start_id)
    len_e = compile_expr(len_id)
    src_e = compile_expr_gc_rooted(src_id)
    pfx = array_c_prefix(rt)
    src_pfx = array_c_prefix(src_t)
    if pfx == "" || src_pfx == ""
      return
    end
    rc_t = new_temp
    src_t_v = new_temp
    start_t = new_temp
    ii = new_temp
    emit("  {")
    emit("    sp_" + pfx + " *" + rc_t + " = " + rc + ";")
    emit("    sp_" + src_pfx + " *" + src_t_v + " = " + src_e + ";")
    emit("    mrb_int " + start_t + " = " + start_e + ";")
    emit("    mrb_int _n = " + len_e + ";")
    # Inner loop: copy n elements from src to dest. Casting between
    # array kinds isn't supported here (e.g. int_array ← float_array
    # would silently truncate); both must be the same C kind.
    if pfx == src_pfx
      emit("    for (mrb_int " + ii + " = 0; " + ii + " < _n; " + ii + "++) {")
      emit("      sp_" + pfx + "_set(" + rc_t + ", " + start_t + " + " + ii + ", sp_" + src_pfx + "_get(" + src_t_v + ", " + ii + "));")
      emit("    }")
    end
    emit("  }")
  end

  # Compile `recv[idx] OP= value` (IndexOperatorWriteNode).
  #
  # Emitted as a get-modify-set against the appropriate typed container,
  # in a block scope so that the receiver and index are each evaluated
  # exactly once. Falls through silently for receiver types we don't
  # handle yet — currently float_array, int_array, and the four numeric
  # hash variants. Compound-assign on string arrays / poly hashes / str
  # hashes is rarely useful and would need per-type semantics.
  def compile_index_op_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    op = @nd_binop[nid]
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    val = compile_expr(@nd_expression[nid])

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt  = new_temp
      ti  = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
           "; sp_" + pfx + "_set(" + tt + ", " + ti +
           ", sp_" + pfx + "_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s +
           "; sp_StrIntHash_set(" + tt + ", " + ti +
           ", sp_StrIntHash_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
    if rt == "int_str_hash"
      # Concatenating strings (`+= str`) is the only sensible op here.
      if op == "+"
        tt = new_temp
        ti = new_temp
        emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx +
             "; sp_IntStrHash_set(" + tt + ", " + ti +
             ", sp_str_concat(sp_IntStrHash_get(" + tt + ", " + ti + "), " + val + ")); }")
        return
      end
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx +
           "; sp_SymIntHash_set(" + tt + ", " + ti +
           ", sp_SymIntHash_get(" + tt + ", " + ti + ") " + op + " (" + val + ")); }")
      return
    end
  end

  # `obj.attr <op>= val` family helper -- builds the
  # temp-receiver-once C block for typed-instance receivers backed by
  # an attr_accessor (or struct field). For non-attr receivers, we
  # exit with a precise error rather than fall through to an
  # incorrect emission. The caller passes a fragment that takes the
  # temp variable name and returns the C body to execute.
  #
  # Spec note: even for the typed-attr-accessor case the receiver is
  # evaluated exactly ONCE -- the source `obj.bar += val` is
  # `tmp = obj; tmp.bar = tmp.bar + val`, NOT `obj.bar = obj.bar + val`.
  # The temp pattern matters when the receiver expression has side
  # effects (e.g. `next_holder().attr += 1`).
  def compile_call_assign_typed(nid, kind)
    recv = @nd_receiver[nid]
    rt = infer_type(recv)
    bname = @nd_name[nid]   # parser emits read_name as "name"
    if rt.length <= 4 || rt[0, 4] != "obj_"
      $stderr.puts "Spinel: Call" + kind + "WriteNode requires a typed instance receiver with attr_accessor; got receiver type \"" + rt + "\""
      exit(1)
    end
    cname = rt[4, rt.length - 4]
    ci = find_class_idx(cname)
    if ci < 0 || cls_has_attr_writer(ci, bname) == 0
      $stderr.puts "Spinel: Call" + kind + "WriteNode for `." + bname + "` requires attr_accessor (or struct field) on class " + cname
      exit(1)
    end
    rc = compile_expr_gc_rooted(recv)
    val = compile_expr(@nd_expression[nid])
    tt = new_temp
    field = "iv_" + bname
    if kind == "Operator"
      op = @nd_binop[nid]
      ivar_t = cls_ivar_type(ci, "@" + bname)
      if op == "+" && ivar_t == "string" && infer_type(@nd_expression[nid]) == "string"
        # String-valued attr with `+=` becomes sp_str_concat, mirroring
        # the LocalVariableOperatorWriteNode arm at line 21786.
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = sp_str_concat(" + tt + "->" + field + ", (" + val + ")); }")
        return
      end
      if op == "%"
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = sp_imod(" + tt + "->" + field + ", (" + val + ")); }")
      else
        emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
             tt + "->" + field + " = " + tt + "->" + field + " " + op + " (" + val + "); }")
      end
      return
    end
    if kind == "And"
      emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
           "if (" + tt + "->" + field + ") " + tt + "->" + field + " = (" + val + "); }")
      return
    end
    if kind == "Or"
      emit("  { sp_" + cname + " *" + tt + " = " + rc + "; " +
           "if (!" + tt + "->" + field + ") " + tt + "->" + field + " = (" + val + "); }")
      return
    end
  end

  # `a[i] &&= val` -- read once, conditionally write once. Mirrors
  # compile_index_op_assign's per-receiver-type dispatch but routes
  # the new value through a C `if (cur)` guard instead of an
  # arithmetic op. The temp pattern keeps `a` and `i` evaluated
  # exactly once, matching CRuby's `a[i] = a[i] && val` evaluation
  # order.
  def compile_index_and_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    # Note: defer compile_expr(@nd_expression[nid]) to inside each
    # if-branch so RHS side effects only fire when the get is truthy
    # (Ruby `&&=` short-circuit semantics).

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt = new_temp
      ti = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (sp_" + pfx + "_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s + ";")
      emit("    if (sp_StrIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_StrIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "int_str_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (sp_IntStrHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_IntStrHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx + ";")
      emit("    if (sp_SymIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_SymIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
  end

  # `a[i] ||= val` -- read once, write only if current is falsy.
  # Same C-truthy vs Ruby-truthy gap as the LocalVariable/Global/
  # Class compound forms (numeric 0 is C-falsy; documented in
  # test/global_var_or_write.rb). For string-valued slots (NULL
  # falsy, anything else truthy) the C and Ruby semantics agree.
  def compile_index_or_assign(nid)
    recv = @nd_receiver[nid]
    args_id = @nd_arguments[nid]
    arg_ids = args_id >= 0 ? get_args(args_id) : []
    return if arg_ids.length < 1
    rt = infer_type(recv)
    rc = compile_expr_gc_rooted(recv)
    idx = compile_expr(arg_ids[0])
    # Note: defer compile_expr(@nd_expression[nid]) to inside each
    # if-branch so RHS side effects only fire when the get is falsy
    # (Ruby `||=` short-circuit semantics).

    if rt == "float_array" || rt == "int_array"
      pfx = array_c_prefix(rt)
      tt = new_temp
      ti = new_temp
      emit("  { sp_" + pfx + " *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (!sp_" + pfx + "_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_" + pfx + "_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "str_int_hash"
      tt = new_temp
      ti = new_temp
      idx_s = compile_expr_as_string(arg_ids[0])
      emit("  { sp_StrIntHash *" + tt + " = " + rc + "; const char *" + ti + " = " + idx_s + ";")
      emit("    if (!sp_StrIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_StrIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "int_str_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_IntStrHash *" + tt + " = " + rc + "; mrb_int " + ti + " = " + idx + ";")
      emit("    if (!sp_IntStrHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_IntStrHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "sym_int_hash"
      tt = new_temp
      ti = new_temp
      emit("  { sp_SymIntHash *" + tt + " = " + rc + "; sp_sym " + ti + " = " + idx + ";")
      emit("    if (!sp_SymIntHash_get(" + tt + ", " + ti + ")) {")
      val = compile_expr(@nd_expression[nid])
      emit("      sp_SymIntHash_set(" + tt + ", " + ti + ", (" + val + "));")
      emit("    }")
      emit("  }")
      return
    end
    if rt == "poly_poly_hash"
      # Lower `h[k] ||= v` to a get-then-set pair on the boxed key.
      # The expression-form lifts the temp out of a block scope so
      # callers can read the result; here we ignore the value but reuse
      # the same emitter for symmetry.
      compile_poly_poly_index_or_assign_to_temp(nid, rc, arg_ids)
      return
    end
    if rt == "sym_poly_hash" || rt == "str_poly_hash"
      compile_typed_poly_hash_index_or_assign_to_temp(nid, rc, arg_ids, rt)
      return
    end
    if rt == "poly_array"
      compile_typed_array_index_or_assign_to_temp(nid, rc, arg_ids, rt)
      return
    end
    if rt == "poly"
      compile_poly_value_array_index_or_assign_to_temp(nid, rc)
      return
    end
  end

  # Emit the get-then-set body for `recv[k] ||= v` against a
  # poly_poly_hash receiver and return the C name of the sp_RbVal temp
  # holding the resulting value (existing on hit, freshly-stored rhs on
  # miss). Caller is responsible for using or discarding the temp.
  def compile_poly_poly_index_or_assign_to_temp(nid, rc, arg_ids)
    tt = new_temp
    tk = new_temp
    tg = new_temp
    key_boxed = box_expr_to_poly(arg_ids[0])
    emit("  sp_PolyPolyHash *" + tt + " = " + rc + ";")
    emit("  sp_RbVal " + tk + " = " + key_boxed + ";")
    emit("  sp_RbVal " + tg + " = sp_PolyPolyHash_get(" + tt + ", " + tk + ");")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    sp_PolyPolyHash_set(" + tt + ", " + tk + ", " + tg + ");")
    emit("  }")
    tg
  end

  # Same shape as `compile_poly_poly_index_or_assign_to_temp` for
  # sym_poly_hash / str_poly_hash receivers — the keys are bare
  # `sp_sym` / `const char *` (not boxed sp_RbVal) but the value
  # slot is poly so the get-then-set still pivots on the
  # `tag == SP_TAG_NIL` miss probe.
  def compile_typed_poly_hash_index_or_assign_to_temp(nid, rc, arg_ids, recv_type)
    tt = new_temp
    tk = new_temp
    tg = new_temp
    if recv_type == "sym_poly_hash"
      hash_c = "sp_SymPolyHash"
      key_t = "sp_sym"
      key_expr = compile_expr(arg_ids[0])
    else
      hash_c = "sp_StrPolyHash"
      key_t = "const char *"
      key_expr = compile_expr_as_string(arg_ids[0])
    end
    emit("  " + hash_c + " *" + tt + " = " + rc + ";")
    emit("  " + key_t + " " + tk + " = " + key_expr + ";")
    emit("  sp_RbVal " + tg + " = " + hash_c + "_get(" + tt + ", " + tk + ");")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    " + hash_c + "_set(" + tt + ", " + tk + ", " + tg + ");")
    emit("  }")
    tg
  end

  # Box the rhs of an `||=` whose lhs is a poly-element slot. For
  # ArrayNode literals — `[]`, `[nil, nil]`, … — promote to
  # poly_array (boxed) so the slot carries a uniformly poly shape;
  # subsequent chain levels can then inspect the value's cls_id
  # against `SP_BUILTIN_POLY_ARRAY` reliably. Without the promote,
  # `[]` would lower to `sp_box_int_array(sp_IntArray_new())`, the
  # next chain level's `cls_id == POLY_ARRAY` check would fail, and
  # the back-set would skip silently. Non-ArrayNode rhs falls back
  # to the existing `box_expr_to_poly` machinery.
  def chained_or_assign_rhs_box(rhs_id)
    if rhs_id >= 0 && @nd_type[rhs_id] == "ArrayNode"
      @needs_rb_value = 1
      @needs_gc = 1
      return "sp_box_poly_array(" + compile_array_literal_as_poly(rhs_id) + ")"
    end
    box_expr_to_poly(rhs_id)
  end

  # `recv[i] ||= v` against a typed-array receiver whose element
  # slot is a boxed sp_RbVal — i.e. poly_array. The miss probe is
  # the same `tag == SP_TAG_NIL` pivot used by the *_poly_hash
  # forms, but indexed access has two extra wrinkles:
  #
  #   - the key must be in-bounds before `_get` is safe to call
  #     (sp_PolyArray_get reads `data[i]` without a length check),
  #   - on miss the slot may be beyond `len`, so before `_set` we
  #     pad the array with nil entries up to `i` inclusive.
  #
  # Mirrors CRuby's `arr[i] = v` auto-grow semantics for the gap.
  # Scalar-element typed arrays (int_array, float_array, …) need a
  # different probe (out-of-bounds check, no SP_TAG_NIL) and are
  # not handled here; the caller falls back to the existing stmt
  # path for those.
  def compile_typed_array_index_or_assign_to_temp(nid, rc, arg_ids, recv_type)
    tt = new_temp
    ti = new_temp
    tg = new_temp
    arr_c = "sp_PolyArray"
    emit("  " + arr_c + " *" + tt + " = " + rc + ";")
    emit("  mrb_int " + ti + " = " + compile_expr(arg_ids[0]) + ";")
    emit("  sp_RbVal " + tg + " = sp_box_nil();")
    emit("  if (" + ti + " >= 0 && " + ti + " < sp_" + arr_c.sub("sp_", "") + "_length(" + tt + ")) {")
    emit("    " + tg + " = " + arr_c + "_get(" + tt + ", " + ti + ");")
    emit("  }")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    while (sp_" + arr_c.sub("sp_", "") + "_length(" + tt + ") <= " + ti + ") { " + arr_c + "_push(" + tt + ", sp_box_nil()); }")
    emit("    " + arr_c + "_set(" + tt + ", " + ti + ", " + tg + ");")
    emit("  }")
    tg
  end

  # `<poly>[i] ||= v` where the recv is an sp_RbVal carrying — at
  # runtime — a poly_array. Common in chains like
  # `(@h[k] ||= [])[i] ||= ...`: spinel types `(@h[k] ||= [])` as
  # poly because the hash leaf type is poly, and the inner `||=`
  # sees a poly recv even though the value is concretely a
  # poly_array.
  #
  # The miss probe needs an extra `tag == SP_TAG_OBJ &&
  # cls_id == SP_BUILTIN_POLY_ARRAY` guard so the runtime falls
  # through cleanly when the poly carries a non-array shape. The
  # body otherwise mirrors `compile_typed_array_index_or_assign_to_temp`.
  def compile_poly_value_array_index_or_assign_to_temp(nid, rc)
    tr = new_temp
    tp = new_temp
    ti = new_temp
    tg = new_temp
    args_id = @nd_arguments[nid]
    arg0 = args_id >= 0 ? get_args(args_id)[0] : -1
    emit("  sp_RbVal " + tr + " = " + rc + ";")
    emit("  sp_PolyArray *" + tp + " = (" + tr + ".tag == SP_TAG_OBJ && " + tr + ".cls_id == SP_BUILTIN_POLY_ARRAY) ? (sp_PolyArray *)" + tr + ".v.p : NULL;")
    emit("  mrb_int " + ti + " = " + compile_expr(arg0) + ";")
    emit("  sp_RbVal " + tg + " = sp_box_nil();")
    emit("  if (" + tp + " && " + ti + " >= 0 && " + ti + " < sp_PolyArray_length(" + tp + ")) {")
    emit("    " + tg + " = sp_PolyArray_get(" + tp + ", " + ti + ");")
    emit("  }")
    val_boxed = chained_or_assign_rhs_box(@nd_expression[nid])
    emit("  if (" + tg + ".tag == SP_TAG_NIL) {")
    emit("    " + tg + " = " + val_boxed + ";")
    emit("    if (" + tp + ") {")
    emit("      while (sp_PolyArray_length(" + tp + ") <= " + ti + ") { sp_PolyArray_push(" + tp + ", sp_box_nil()); }")
    emit("      sp_PolyArray_set(" + tp + ", " + ti + ", " + tg + ");")
    emit("    }")
    emit("  }")
    tg
  end

  # Return a C expression that evaluates to the inspected form of `val`
  # (a value of inferred Ruby type `at`), following Ruby's Object#inspect
  # contract. Returns "" when `at` has no inspect implementation yet, so
  # callers can fall back to their previous behaviour.
  def compile_inspect_for(at, val)
    if at == "int"
      return "sp_int_to_s(" + val + ")"
    end
    if at == "float"
      return "sp_float_inspect(" + val + ")"
    end
    if at == "string" || at == "string?"
      return "sp_str_inspect(" + val + ")"
    end
    if at == "mutable_str"
      return "sp_str_inspect(" + val + "->data)"
    end
    if at == "symbol"
      return "sp_str_concat(\":\", sp_sym_to_s(" + val + "))"
    end
    if at == "bool"
      return "(" + val + " ? \"true\" : \"false\")"
    end
    if at == "nil"
      return "\"nil\""
    end
    if at == "int_array"
      @needs_int_array = 1
      return "sp_IntArray_inspect(" + val + ")"
    end
    if at == "float_array"
      @needs_float_array = 1
      return "sp_FloatArray_inspect(" + val + ")"
    end
    if at == "str_array"
      @needs_str_array = 1
      return "sp_StrArray_inspect(" + val + ")"
    end
    if at == "sym_array"
      @needs_int_array = 1
      return "sp_SymArray_inspect(" + val + ")"
    end
    if at == "poly_array"
      @needs_rb_value = 1
      return "sp_PolyArray_inspect(" + val + ")"
    end
    if at == "poly"
      @needs_rb_value = 1
      return "sp_poly_inspect(" + val + ")"
    end
    # Nested arrays: only the four T_array element shapes that already
    # have primitive inspect helpers (issue #169). Other ptr_array
    # element types (obj_<C>, poly_array) fall through to the
    # puts-style default — they're separate scope.
    if at == "int_array_ptr_array"
      @needs_int_array = 1
      return "sp_IntArrayPtrArray_inspect(" + val + ")"
    end
    if at == "float_array_ptr_array"
      @needs_float_array = 1
      return "sp_FloatArrayPtrArray_inspect(" + val + ")"
    end
    if at == "str_array_ptr_array"
      @needs_str_array = 1
      return "sp_StrArrayPtrArray_inspect(" + val + ")"
    end
    if at == "sym_array_ptr_array"
      @needs_int_array = 1
      return "sp_SymArrayPtrArray_inspect(" + val + ")"
    end
    # Tuples produced by methods that return Ruby Arrays of fixed
    # arity (Integer#divmod, Array#minmax, etc.).  Without an inspect
    # path here, `p arr.minmax` would fall through to printf("%lld",...)
    # and emit the struct pointer.  Format as Ruby's "[a, b]" so the
    # output round-trips with CRuby.
    if at == "tuple:int,int"
      return "sp_sprintf(\"[%lld, %lld]\", (long long)" + val + "->_0, (long long)" + val + "->_1)"
    end
    if at == "tuple:int,float"
      return "sp_sprintf(\"[%lld, %s]\", (long long)" + val + "->_0, sp_float_inspect(" + val + "->_1))"
    end
    if at == "tuple:float,float"
      return "sp_sprintf(\"[%s, %s]\", sp_float_inspect(" + val + "->_0), sp_float_inspect(" + val + "->_1))"
    end
    if at == "sym_int_hash"
      @needs_sym_int_hash = 1
      return "sp_SymIntHash_inspect(" + val + ")"
    end
    ""
  end

  # Kernel#p: for each argument, prints `arg.inspect` followed by a
  # newline. Uses `compile_inspect_for` for types that implement inspect;
  # falls back to puts-style output for types that don't yet (e.g.
  # user-defined classes, ranges, hashes).
  def compile_p(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      return
    end
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
      at = infer_type(aid)
      val = compile_expr(aid)
      ins = compile_inspect_for(at, val)
      if ins == ""
        # No inspect implementation for this type — keep the historic
        # behaviour so nothing regresses.
        compile_puts_single(aid, at, val)
      else
        emit("  fputs(" + ins + ", stdout); putchar('" + bsl_n + "');")
      end
      k = k + 1
    end
  end

  # Emit the puts-equivalent for a single arg (extracted for reuse from p).
  def compile_puts_single(aid, at, val)
    if at == "poly"
      @needs_rb_value = 1
      emit("  sp_poly_puts(" + val + ");")
      return
    end
    if at == "mutable_str"
      emit("  { const char *_ps = (const char *)(" + val + "->data); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
      return
    end
    if at == "int"
      emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
      return
    end
    if at == "float"
      emit("  { const char *_fs = sp_float_to_s(" + val + "); fputs(_fs, stdout); putchar('" + bsl_n + "'); }")
      return
    end
    if at == "bool"
      emit("  puts(" + val + " ? \"true\" : \"false\");")
      return
    end
    if at == "string" || at == "string?"
      emit("  { const char *_ps = (const char *)(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
      return
    end
    emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
  end

  def compile_puts(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      emit("  putchar('" + bsl_n + "');")
      return
    end
    arg_ids = get_args(args_id)
    if arg_ids.length == 0
      emit("  putchar('" + bsl_n + "');")
      return
    end
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
      at = infer_type(aid)
      val = compile_expr(aid)
      if at == "poly"
        @needs_rb_value = 1
        emit("  sp_poly_puts(" + val + ");")
        k = k + 1
        next
      end
      if at == "mutable_str"
        emit("  { const char *_ps = (const char *)(" + val + "->data); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "bigint"
        emit("  { const char *_bs = sp_bigint_to_s(" + val + "); fputs(_bs, stdout); putchar('" + bsl_n + "'); }")
        k = k + 1
        next
      end
      if at == "symbol"
        emit("  puts(sp_sym_to_s(" + val + "));")
        k = k + 1
        next
      end
      if at == "int"
        emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
      else
        if at == "float"
          emit("  { const char *_fs = sp_float_to_s(" + val + "); fputs(_fs, stdout); putchar('" + bsl_n + "'); }")
        else
          if at == "string" || at == "string?"
            emit("  { const char *_ps = (const char *)(" + val + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
          else
            if at == "bool"
              emit("  puts(" + val + " ? \"true\" : \"false\");")
            else
              if is_obj_type(at) == 1
                cname = at[4, at.length - 4]
                owner = find_method_owner(find_class_idx(cname), "to_s")
                if owner != ""
                  sv = "sp_" + owner + "_to_s(" + (owner == cname ? val : "(sp_" + owner + " *)" + val) + ")"
                  emit("  { const char *_ps = (const char *)(" + sv + "); if (_ps) { fputs(_ps, stdout); if (!*_ps || _ps[strlen(_ps)-1] != '" + bsl_n + "') putchar('" + bsl_n + "'); } else putchar('" + bsl_n + "'); }")
                else
                  emit("  printf(\"%lld" + bsl_n + "\", (long long)(mrb_int)" + val + ");")
                end
              else
                if at == "str_array"
                  emit("  { sp_StrArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) puts(_pa->data[_pi]); }")
                elsif at == "sym_array"
                  emit("  { sp_IntArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) puts(sp_sym_to_s((sp_sym)_pa->data[_pa->start + _pi])); }")
                elsif at == "int_array"
                  emit("  { sp_IntArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) printf(\"%lld" + bsl_n + "\", (long long)_pa->data[_pa->start + _pi]); }")
                elsif at == "float_array"
                  emit("  { sp_FloatArray *_pa = " + val + "; for (mrb_int _pi = 0; _pi < _pa->len; _pi++) { const char *_fs = sp_float_to_s(_pa->data[_pi]); fputs(_fs, stdout); putchar('" + bsl_n + "'); } }")
                else
                  emit("  printf(\"%lld" + bsl_n + "\", (long long)" + val + ");")
                end
              end
            end
          end
        end
      end
      k = k + 1
    end
  end

  def compile_stderr_puts(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      emit("  fputc('" + bsl_n + "', stderr);")
      return
    end
    arg_ids = get_args(args_id)
    k = 0
    while k < arg_ids.length
      at = infer_type(arg_ids[k])
      val = compile_expr(arg_ids[k])
      if at == "string"
        emit("  fprintf(stderr, \"%s" + bsl_n + "\", " + val + ");")
      else
        emit("  fprintf(stderr, \"%lld" + bsl_n + "\", (long long)" + val + ");")
      end
      k = k + 1
    end
  end

  def compile_print(nid)
    args_id = @nd_arguments[nid]
    if args_id < 0
      return
    end
    arg_ids = get_args(args_id)
    k = 0
    while k < arg_ids.length
      aid = arg_ids[k]
      # Detect x.chr pattern and use putchar for binary-safe output
      if @nd_type[aid] == "CallNode"
        if @nd_name[aid] == "chr"
          if @nd_receiver[aid] >= 0
            rchr = compile_expr(@nd_receiver[aid])
            emit("  putchar((unsigned char)" + rchr + ");")
            k = k + 1
            next
          end
        end
      end
      at = infer_type(aid)
      val = compile_expr(aid)
      if at == "bigint"
        emit("  fputs(sp_bigint_to_s(" + val + "), stdout);")
        k = k + 1
        next
      end
      if at == "symbol"
        emit("  fputs(sp_sym_to_s(" + val + "), stdout);")
        k = k + 1
        next
      end
      if at == "int"
        emit("  printf(\"%lld\", (long long)" + val + ");")
      else
        if at == "mutable_str"
          emit("  fputs(" + val + "->data, stdout);")
        else
          if at == "string"
            emit("  fputs(" + val + ", stdout);")
          else
            emit("  printf(\"%lld\", (long long)" + val + ");")
          end
        end
      end
      k = k + 1
    end
  end

  def get_block_param(nid, idx)
    blk = @nd_block[nid]
    if blk < 0
      return ""
    end
    params = @nd_parameters[blk]
    if params < 0
      return ""
    end
    # NumberedParametersNode ({ _1 + _2 }): params is the node itself,
    # and @nd_value holds the maximum (1 for _1, 2 for _2, etc.).
    if @nd_type[params] == "NumberedParametersNode"
      if idx < @nd_value[params]
        return "_" + (idx + 1).to_s
      end
      return ""
    end
    inner = @nd_parameters[params]
    if inner < 0
      return ""
    end
    reqs = parse_id_list(@nd_requireds[inner])
    if idx < reqs.length
      return @nd_name[reqs[idx]]
    end
    ""
  end

  def compile_each_slice_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    n = compile_arg0(nid)
    bp1 = get_block_param(nid, 0)
    if bp1 == ""
      bp1 = "_slice"
    end
    tmp_i = new_temp
    tmp_j = new_temp
    tmp_len = new_temp
    pfx = array_c_prefix(rt)
    @needs_gc = 1
    emit("  mrb_int " + tmp_len + " = sp_" + pfx + "_length(" + rc + ");")
    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " < " + tmp_len + "; " + tmp_i + " += " + n + ") {")
    # When bp1 shadows an outer same-named local of a different C type, the
    # function-level lv_<bp1> has the outer type. Emit a block-scoped fresh
    # declaration with its own GC root so the slice survives allocations in
    # the user block body.
    outer_t = find_var_type(bp1)
    if outer_t != "" && outer_t != rt
      emit("    SP_GC_SAVE();")
      emit("    " + c_type(rt) + " lv_" + bp1 + " = sp_" + pfx + "_new();")
      emit("    SP_GC_ROOT(lv_" + bp1 + ");")
    else
      emit("    lv_" + bp1 + " = sp_" + pfx + "_new();")
    end
    emit("    for (mrb_int " + tmp_j + " = 0; " + tmp_j + " < " + n + " && " + tmp_i + " + " + tmp_j + " < " + tmp_len + "; " + tmp_j + "++)")
    emit("      sp_" + pfx + "_push(lv_" + bp1 + ", sp_" + pfx + "_get(" + rc + ", " + tmp_i + " + " + tmp_j + "));")
    @indent = @indent + 1
    push_scope
    declare_var(bp1, rt)
    redo_label = push_redo_label
    emit_redo_label(redo_label)
    compile_stmts_body(@nd_body[@nd_block[nid]])
    pop_redo_label
    pop_scope
    @indent = @indent - 1
    emit("  }")
    @in_loop = old
  end

  def compile_each_cons_block(nid)
    old = @in_loop
    @in_loop = 1
    rt = infer_type(@nd_receiver[nid])
    rc = compile_expr_gc_rooted(@nd_receiver[nid])
    n = compile_arg0(nid)
