    emit("  for (mrb_int " + tmp_i + " = 0; " + tmp_i + " + " + n + " <= " + tmp_len + "; " + tmp_i + "++) {")
    # See compile_each_slice_block: shadow case needs a fresh typed slot with
    # its own GC root.
